-- Poems batch 57
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1ec76dac-5ecd-4374-8f0e-d96ac31d1f2e','歸國謠 三','馮延巳','唐','唐诗','tang','','[]','江水碧，江上何人吹玉笛。',40,'全唐诗/poet.tang.49000.json','["江水碧，江上何人吹玉笛。", "扁舟遠送瀟湘客，蘆花千里霜月白。", "傷行色，來朝便是關山隔。"]'),
('a1853142-c700-4ba2-b056-433cbaae2a27','長相思','馮延巳','唐','唐诗','tang','','[]','紅滿枝，綠滿枝，宿雨厭厭睡起遲，閑庭花影移。',44,'全唐诗/poet.tang.49000.json','["紅滿枝，綠滿枝，宿雨厭厭睡起遲，閑庭花影移。", "憶歸期，數歸期，夢見雖多相見稀，相逢知幾時。"]'),
('c9b03cf8-e879-4b20-a370-310d10b25007','相見歡','馮延巳','唐','唐诗','tang','','[]','曉窗夢到昭華，向瓊家。',45,'全唐诗/poet.tang.49000.json','["曉窗夢到昭華，向瓊家。", "欹枕殘妝一朵，臥枝花。", "情極處，却無語，玉釵斜。", "翠閣銀屏回首，已天涯。"]'),
('ccdd7cca-fc16-412f-8313-7a29fb3c56cb','拋毬樂 一','馮延巳','唐','唐诗','tang','','[]','酒罷歌餘興未闌，小橋清水共盤桓。',46,'全唐诗/poet.tang.49000.json','["酒罷歌餘興未闌，小橋清水共盤桓。", "波搖梅蘂傷心白，風入羅衣貼體寒。", "且莫思歸去，須盡笙歌此夕歡。"]'),
('2a292dd3-c38a-4f6f-897c-80ac28fcfc0b','拋毬樂 二','馮延巳','唐','唐诗','tang','','["\u5199\u96e8", "\u5199\u666f", "\u6292\u60c5", "\u96e8"]','逐勝歸來雨未晴，樓前風重草煙輕。',46,'全唐诗/poet.tang.49000.json','["逐勝歸來雨未晴，樓前風重草煙輕。", "谷鶯語輭花邊過，水調聲長醉裏聽。", "欵舉金觥勸，誰是當筵最有情。"]'),
('0548f0bb-ca74-4fa6-93bf-c7e8e7b6fce5','拋毬樂 三','馮延巳','唐','唐诗','tang','','[]','梅落新春入後庭，眼前風物可無情。',46,'全唐诗/poet.tang.49000.json','["梅落新春入後庭，眼前風物可無情。", "曲池波晚冰還合，芳草迎船綠未成。", "且上高樓望，相共凭闌看月生。"]'),
('536eff4e-5af8-4f57-81b3-913346b8ca4a','拋毬樂 四','馮延巳','唐','唐诗','tang','','[]','霜積秋山萬樹紅，倚巖樓上掛朱櫳。',46,'全唐诗/poet.tang.49000.json','["霜積秋山萬樹紅，倚巖樓上掛朱櫳。", "白雲天遠重重恨，黃葉煙深淅淅風。", "髣髴梁州曲，吹在誰家玉笛中。"]'),
('4304599d-3411-479b-9afb-c16b0b92bd22','拋毬樂 五','馮延巳','唐','唐诗','tang','','[]','盡日登高興未殘，紅樓人散獨盤桓。',46,'全唐诗/poet.tang.49000.json','["盡日登高興未殘，紅樓人散獨盤桓。", "一鉤冷霧懸珠箔，滿面西風凭玉闌。", "歸去須沈醉，小院新池月乍寒。"]'),
('ebbb2ec5-3e4a-400d-9de4-d3dd3c34093c','拋毬樂 六','馮延巳','唐','唐诗','tang','','[]','坐對高樓千萬山，鴈飛秋色滿闌干。',46,'全唐诗/poet.tang.49000.json','["坐對高樓千萬山，鴈飛秋色滿闌干。", "燒殘紅燭暮雲合，飄盡碧梧金井寒。", "咫尺人千里，猶憶笙歌昨夜歡。"]'),
('2c037512-649d-4cbe-9b4c-f254f8c8bd5c','點絳唇','馮延巳','唐','唐诗','tang','','[]','蔭綠圍紅，夢瓊家在桃源住。',50,'全唐诗/poet.tang.49000.json','["蔭綠圍紅，夢瓊家在桃源住。", "畫橋當路，臨水開朱戶。", "柳徑春深，行到關情處。", "顰不語，意憑風絮，吹向郎邊去。"]'),
('6682ebd0-ca24-4b46-bfd7-2a81c9d2d22f','酒泉子 一','馮延巳','唐','唐诗','tang','','[]','庭下花飛，月照妝樓春事晚。',52,'全唐诗/poet.tang.49000.json','["庭下花飛，月照妝樓春事晚。", "珠簾風，蘭燭燼，怨空閨。", "迢迢何處寄相思，玉筯零零腸斷。", "屏幃深，更漏永，夢魂迷。"]'),
('ad47e380-bfb9-4551-9b53-71cfac036094','酒泉子 二','馮延巳','唐','唐诗','tang','','[]','芳草長川，柳映危橋橋下路。',52,'全唐诗/poet.tang.49000.json','["芳草長川，柳映危橋橋下路。", "歸鴻飛，行人去，碧山邊。", "風微煙淡雨蕭然，隔岸馬嘶何處？", "九回腸，雙臉淚，夕陽天。"]'),
('6096b9cd-c1a3-40d5-bffe-6e7d775a7492','酒泉子 三','馮延巳','唐','唐诗','tang','','[]','[春]色融融，飛燕乍來鶯未語。',54,'全唐诗/poet.tang.49000.json','["[春]色融融，飛燕乍來鶯未語。", "小桃寒，垂柳晚，玉樓空。", "天長煙遠恨重重，消息燕鴻歸去。", "枕前燈，窗外月，閉朱籠。"]'),
('4cd951f4-02f4-46a0-a2f1-e84d9ff95540','酒泉子 四','馮延巳','唐','唐诗','tang','','[]','深院空幃，廊下風簾驚宿燕。',52,'全唐诗/poet.tang.49000.json','["深院空幃，廊下風簾驚宿燕。", "香印灰，蘭燭灺，覺來時。", "月明人自擣寒衣，剛愛無端惆悵。", "階前行，闌外立，欲雞啼。"]'),
('63cd382a-840e-4029-9fb0-7ef393f6b16e','采桑子 一','馮延巳','唐','唐诗','tang','','[]','小庭雨過春將盡，片片花飛，獨折殘枝，無語凭闌秪自知。',52,'全唐诗/poet.tang.49000.json','["小庭雨過春將盡，片片花飛，獨折殘枝，無語凭闌秪自知。", "玉堂香煖珠簾卷，雙燕來歸，君約佳期，肯信韶華得幾時。"]'),
('43f585b9-c50d-4157-8e1a-e30bbe7af989','采桑子 二','馮延巳','唐','唐诗','tang','','[]','馬嘶人語春風岸，芳草綿綿，楊柳橋邊，落日高樓酒斾懸。',52,'全唐诗/poet.tang.49000.json','["馬嘶人語春風岸，芳草綿綿，楊柳橋邊，落日高樓酒斾懸。", "舊愁新恨知多少，目斷遙天，獨立花前，更聽笙歌滿畫船。"]'),
('ae003587-92bd-470a-b2bf-de30b68c70ee','采桑子 三','馮延巳','唐','唐诗','tang','','[]','西風半夜簾櫳冷，遠夢初歸，夢過金扉，花謝窗前夜合枝。',52,'全唐诗/poet.tang.49000.json','["西風半夜簾櫳冷，遠夢初歸，夢過金扉，花謝窗前夜合枝。", "昭陽殿裏新翻曲，未有人知，偷取笙吹，驚覺寒蛩到曉啼。"]'),
('1e874b28-0782-4b78-9b68-edce9374c10e','采桑子 四','馮延巳','唐','唐诗','tang','','[]','酒闌睡覺天香煖，繡戶慵開，香印成灰，獨背寒屏理舊眉。',52,'全唐诗/poet.tang.49000.json','["酒闌睡覺天香煖，繡戶慵開，香印成灰，獨背寒屏理舊眉。", "朦朧却向燈前臥，窗月徘徊，曉夢初回，一夜東風綻早梅。"]'),
('22107b82-29af-4476-9267-4c413dfdd803','采桑子 五','馮延巳','唐','唐诗','tang','','[]','小堂深靜無人到，滿院春風，惆悵牆東，一樹櫻桃帶雨紅。',52,'全唐诗/poet.tang.49000.json','["小堂深靜無人到，滿院春風，惆悵牆東，一樹櫻桃帶雨紅。", "愁心似醉兼如病，欲語還慵，日暮疎鐘，雙燕歸棲畫閣中。"]'),
('dcce4f6f-97df-429f-8d93-83172191d210','采桑子 六','馮延巳','唐','唐诗','tang','','[]','畫堂燈煖簾櫳卷，禁漏丁丁，雨罷寒生，一夜西窗夢不成。',52,'全唐诗/poet.tang.49000.json','["畫堂燈煖簾櫳卷，禁漏丁丁，雨罷寒生，一夜西窗夢不成。", "玉娥重起添香印，回倚孤屏，不語含情，水調何人吹笛聲。"]'),
('ae8d510a-d2a6-418f-86c5-6b9d629c02f2','采桑子 七','馮延巳','唐','唐诗','tang','','[]','笙歌放散人歸去，獨宿江樓，月上雲收，一半珠簾掛玉鉤。',52,'全唐诗/poet.tang.49000.json','["笙歌放散人歸去，獨宿江樓，月上雲收，一半珠簾掛玉鉤。", "起來檢點經遊地，處處新愁，憑仗東流，將取離心過橘州。"]'),
('a70986a4-8883-4a0a-b8d0-f6388b2a07ad','采桑子 八','馮延巳','唐','唐诗','tang','','[]','昭陽記得神仙侶，獨自承恩，水殿燈昏，羅幕輕寒夜正春。',52,'全唐诗/poet.tang.49000.json','["昭陽記得神仙侶，獨自承恩，水殿燈昏，羅幕輕寒夜正春。", "如今別館添蕭索，滿面啼痕，舊約猶存，忍把金環別與人。"]'),
('fbaa9b93-3995-4290-9bb7-ed77eabbe4a9','采桑子 九','馮延巳','唐','唐诗','tang','','[]','微風簾幕清明近，花落春殘，尊酒留歡，添盡羅衣怯夜寒。',52,'全唐诗/poet.tang.49000.json','["微風簾幕清明近，花落春殘，尊酒留歡，添盡羅衣怯夜寒。", "愁顏恰似燒殘燭，珠淚闌干，也欲高拌，爭奈相逢情萬般。"]'),
('541abfd7-6d17-497e-b915-783944ba3340','采桑子 十','馮延巳','唐','唐诗','tang','','[]','畫堂昨夜愁無睡，風雨淒淒，林鵲爭棲，落盡燈花雞未啼。',52,'全唐诗/poet.tang.49000.json','["畫堂昨夜愁無睡，風雨淒淒，林鵲爭棲，落盡燈花雞未啼。", "年光往事如流水，休說情迷，玉筯雙垂，祗是金籠鸚鵡知。"]'),
('4414bb27-f21b-423e-9257-32b29116d3cc','采桑子 十一','馮延巳','唐','唐诗','tang','','[]','寒蟬欲報三秋候，寂靜幽居，葉落閑階，月透簾櫳遠夢回。',52,'全唐诗/poet.tang.49000.json','["寒蟬欲報三秋候，寂靜幽居，葉落閑階，月透簾櫳遠夢回。", "昭陽舊恨依前在，休說當時，玉笛纔吹，滿袖猩猩血又垂。"]'),
('0996aebe-f474-42e2-bc8e-805639113c8c','采桑子 十二','馮延巳','唐','唐诗','tang','','[]','洞房深夜笙歌散，簾幕重重，斜月朦朧，雨過殘花落地紅。',52,'全唐诗/poet.tang.49000.json','["洞房深夜笙歌散，簾幕重重，斜月朦朧，雨過殘花落地紅。", "昔年無限傷心事，依舊東風，獨倚梧桐，閑想閑思到曉鐘。"]'),
('ef2f5dfc-6a5f-4dc0-b867-2f751688488b','采桑子 十三','馮延巳','唐','唐诗','tang','','["\u601d\u5ff5", "\u5b64\u72ec", "\u5a49\u7ea6"]','花前失却遊春侶，極目尋芳，滿眼悲涼，縱有笙歌亦斷腸。',52,'全唐诗/poet.tang.49000.json','["花前失却遊春侶，極目尋芳，滿眼悲涼，縱有笙歌亦斷腸。", "林間戲蝶簾間燕，各自雙雙，忍更思量，綠樹青苔半夕陽。"]'),
('d20685bf-a54f-4964-8b46-ec4a785408d8','菩薩蠻 一','馮延巳','唐','唐诗','tang','','[]','金波遠逐行雲去，疎星時作銀河渡。',52,'全唐诗/poet.tang.49000.json','["金波遠逐行雲去，疎星時作銀河渡。", "花影臥秋千，更長人不眠。", "玉箏彈未徹，鳳髻黃釵脫。", "憶夢翠蛾低，微風吹繡衣。"]'),
('c422f547-5ef1-4f78-9a23-0c9f0078e496','菩薩蠻 二','馮延巳','唐','唐诗','tang','','[]','畫堂昨夜西風過，繡簾時拂朱門鎖。',52,'全唐诗/poet.tang.49000.json','["畫堂昨夜西風過，繡簾時拂朱門鎖。", "驚夢不成雲，雙蛾枕上顰。", "金爐煙嫋嫋，燭暗紗窗曉。", "殘日尚彎環，玉箏和淚彈。"]'),
('bf2c8e84-0958-4523-acfb-32ecf64ffb88','菩薩蠻 三','馮延巳','唐','唐诗','tang','','[]','梅花吹入誰家笛，行雲半夜凝空碧。',52,'全唐诗/poet.tang.49000.json','["梅花吹入誰家笛，行雲半夜凝空碧。", "欹枕不成眠，關山人未還。", "聲隨幽怨絕，空斷澄霜月。", "月影下重簷，輕風花滿簾。"]'),
('642f6b75-6ca4-4748-be02-1588d9bafe05','菩薩蠻 四','馮延巳','唐','唐诗','tang','','["\u95fa\u6028", "\u79cb\u5929", "\u5987\u5973", "\u6000\u8fdc"]','回廊遠砌生秋草，夢魂千里青門道。',52,'全唐诗/poet.tang.49000.json','["回廊遠砌生秋草，夢魂千里青門道。", "鸚鵡怨長更，碧籠金鎖橫。", "羅幃中夜起，霜月清如水。", "玉露不成圓，寶箏悲斷弦。"]'),
('818cb2e4-fab8-4586-8765-76e1b64b2c0e','菩薩蠻 五','馮延巳','唐','唐诗','tang','','[]','嬌鬟堆枕釵橫鳳，溶溶春水楊花夢。',52,'全唐诗/poet.tang.49000.json','["嬌鬟堆枕釵橫鳳，溶溶春水楊花夢。", "紅燭淚闌干，翠屏煙浪寒。", "錦壺催畫箭，玉佩天涯遠。", "和淚試嚴妝，落梅飛夜霜。"]'),
('3e5ca8cb-54fc-4715-b475-c9ef07b20417','菩薩蠻 六','馮延巳','唐','唐诗','tang','','[]','西風嫋嫋凌歌扇，秋期正與行雲遠。',52,'全唐诗/poet.tang.49000.json','["西風嫋嫋凌歌扇，秋期正與行雲遠。", "花葉脫霜紅，流螢殘月中。", "蘭閨人在否，千里重樓暮。", "翠被已銷香，夢隨寒漏長。"]'),
('6b8042c4-9ea3-447b-bded-055466b2d397','菩薩蠻 七','馮延巳','唐','唐诗','tang','','[]','沈沈朱戶橫金鎖，紗窗月影隨花過。',52,'全唐诗/poet.tang.49000.json','["沈沈朱戶橫金鎖，紗窗月影隨花過。", "燭淚欲闌干，落梅生晚寒。", "寶釵橫翠鳳，千里香屏夢。", "雲雨已荒涼，江南春草長。"]'),
('b6af04b2-c5bf-45a7-a8ee-03b55f04f726','菩薩蠻 八','馮延巳','唐','唐诗','tang','','[]','欹鬟墮髻搖雙槳，采蓮晚出清江上。',52,'全唐诗/poet.tang.49000.json','["欹鬟墮髻搖雙槳，采蓮晚出清江上。", "顧影約流萍，楚歌嬌未成。", "相逢顰翠黛，笑把珠璫解。", "家住柳陰中，畫橋東復東。"]'),
('db30f2d3-22b2-4826-a7c6-e186ebf589bf','謁金門 一','馮延巳','唐','唐诗','tang','','["\u7559\u604b", "\u5199\u666f", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u60dc\u522b", "\u5a49\u7ea6"]','風乍起，吹皺一池春水。',53,'全唐诗/poet.tang.49000.json','["風乍起，吹皺一池春水。", "閑引鴛鴦芳徑裏，手挼紅杏蘂。", "鬬鴨闌干獨倚，碧玉搔頭斜墜。", "終日望君君不至，舉頭聞鵲喜。"]'),
('931569e5-6d54-4620-afd7-f0ba0cfd49e0','謁金門 二','馮延巳','唐','唐诗','tang','','[]','楊柳陌，寶馬嘶空無跡。',53,'全唐诗/poet.tang.49000.json','["楊柳陌，寶馬嘶空無跡。", "新著荷衣人未識，年年江海客。", "夢覺巫山春色，醉眼飛花狼藉。", "起舞不辭無氣力，愛君吹玉笛。"]'),
('e81e6726-94e5-4a06-af01-68c4e3710f2f','清平樂 一','馮延巳','唐','唐诗','tang','','[]','深冬寒月，庭戶凝霜雪。',54,'全唐诗/poet.tang.49000.json','["深冬寒月，庭戶凝霜雪。", "風鴈過時魂斷絕，塞管數聲嗚咽。", "披衣獨立披香，流蘇亂結愁腸。", "往事總堪惆悵，前歡休更思量。"]'),
('37d62403-11c7-4f1c-b6bc-4026e26b778e','清平樂 二','馮延巳','唐','唐诗','tang','','["\u601d\u5ff5", "\u5b64\u72ec", "\u5987\u5973", "\u5199\u666f", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd"]','雨晴煙晚，綠水新池滿。',54,'全唐诗/poet.tang.49000.json','["雨晴煙晚，綠水新池滿。", "雙燕飛來垂柳院，小閣畫簾高卷。", "黃昏獨倚朱闌，西南新月眉彎。", "砌下落花風起，羅衣特地春寒。"]'),
('6f5334cc-54ec-4895-84f7-6bc2b2baefb2','清平樂 三','馮延巳','唐','唐诗','tang','','[]','西園春早，夾逕抽新草。',54,'全唐诗/poet.tang.49000.json','["西園春早，夾逕抽新草。", "冰散漪瀾生碧沼，寒在梅花先老。", "與君同飲金杯，飲餘相取徘徊。", "次第小桃將發，軒車莫厭頻來。"]'),
('72170378-5250-49bd-85cb-b12ceb07d520','更漏子 一','馮延巳','唐','唐诗','tang','','[]','風帶寒，枝正好，蘭蕙無端先老。',58,'全唐诗/poet.tang.49000.json','["風帶寒，枝正好，蘭蕙無端先老。", "情悄悄，夢依依，離人殊未歸。", "褰羅幕，凭朱閣，不獨堪悲搖落。", "月東出，雁南飛，誰家夜擣衣。"]'),
('563ea9ff-2b27-4177-9e95-a33b44448749','更漏子 二','馮延巳','唐','唐诗','tang','','[]','夜初長，人近別，夢覺一窗殘月。',58,'全唐诗/poet.tang.49000.json','["夜初長，人近別，夢覺一窗殘月。", "鸚鵡臥，蟪蛄鳴，西風寒未成。", "紅蠟燭，彈棋局，牀上畫屏山綠。", "褰繡幌，倚瑤琴，前歡淚滴襟。"]'),
('7876129b-6032-4bec-90c1-6844b78a01eb','更漏子 三','馮延巳','唐','唐诗','tang','','[]','玉爐煙，紅燭淚，偏對畫堂秋思。',58,'全唐诗/poet.tang.49000.json','["玉爐煙，紅燭淚，偏對畫堂秋思。", "眉翠薄，鬢雲殘，夜長衾枕寒。", "梧桐樹，三更雨，不道離情最苦。", "一葉葉，一聲聲，空堦滴到明。"]'),
('841e98b3-07a3-4815-bd0d-3a1dabe6d844','喜遷鶯 一','馮延巳','唐','唐诗','tang','','[]','宿鶯啼，鄉夢斷。',57,'全唐诗/poet.tang.49000.json','["宿鶯啼，鄉夢斷。", "春樹曉朦朧，殘燈和燼閉朱櫳，人語隔屏風。", "香已寒，燈已絕。", "忽憶去年離別，石城花雨倚江樓，波上木蘭舟。"]'),
('154fd3b4-3a2e-4e42-b2eb-755350f825fc','喜遷鶯 二','馮延巳','唐','唐诗','tang','','[]','霧濛濛，風淅淅。',57,'全唐诗/poet.tang.49000.json','["霧濛濛，風淅淅。", "楊柳帶疎煙，飄飄輕絮滿南園，牆下草芊綿。", "燕初飛，鶯已老。", "拂面春風長好，相逢攜酒且高歌，人生得幾何。"]'),
('56fcccb3-d805-41ab-92d8-1f3f36b5de4e','阮郎歸 一','馮延巳','唐','唐诗','tang','','["\u5b8b\u8bcd\u7cbe\u9009", "\u5987\u5973", "\u6625\u6e38", "\u5a49\u7ea6"]','南園春半踏青時，風和聞馬嘶。',56,'全唐诗/poet.tang.49000.json','["南園春半踏青時，風和聞馬嘶。", "青梅如豆柳如絲，日長蝴蝶飛。", "花露重，草煙低，人家簾幕垂。", "鞦韆慵困解羅衣，畫梁雙燕棲。"]'),
('fe5c2174-97dc-46e4-acd4-518ca15abfd5','阮郎歸 二','馮延巳','唐','唐诗','tang','','[]','角聲吹斷隴梅枝，孤窗月影低。',56,'全唐诗/poet.tang.49000.json','["角聲吹斷隴梅枝，孤窗月影低。", "塞鴻無限欲驚飛，城烏休夜啼。", "尋斷夢，掩深閨，行人去路迷。", "門前楊柳綠陰齊，何時聞馬嘶。"]'),
('c5c448ff-cf3b-4dff-bf6f-e0b799434d74','賀聖朝','馮延巳','唐','唐诗','tang','','[]','金絲帳煖牙牀穩，懷香方寸。',58,'全唐诗/poet.tang.49000.json','["金絲帳煖牙牀穩，懷香方寸。", "輕顰輕笑，汗珠微透，柳霑花潤。", "雲鬟斜墜，春應未已，不勝嬌困。", "半欹犀枕，亂纏珠被，轉羞人問。"]'),
('d57b6526-261e-4dea-901e-aee34d580371','應天長','馮延巳','唐','唐诗','tang','','[]','石城山下桃花綻，宿雨初晴雲未散。',60,'全唐诗/poet.tang.49000.json','["石城山下桃花綻，宿雨初晴雲未散。", "南去棹，北飛鴈，水闊山遙腸欲斷。", "倚樓情緒懶，[惆悵]春心無限。", "燕度蒹葭風晚，欲歸愁滿面。"]'),
('383f4c6e-6d35-40cf-b38f-07c7efff4227','醉花間 一','馮延巳','唐','唐诗','tang','','[]','獨立堦前星又月，簾櫳偏皎潔。',60,'全唐诗/poet.tang.49000.json','["獨立堦前星又月，簾櫳偏皎潔。", "霜樹盡空枝，腸斷丁香結。", "夜深寒不寐，疑恨何曾歇，凭闌干欲折。", "兩條玉筯爲君垂，此宵情，誰共說。"]'),
('d707d6fe-2b8f-4209-929e-860239d08bd4','醉花間 二','馮延巳','唐','唐诗','tang','','[]','月落霜繁深院閉，洞房人正睡。',60,'全唐诗/poet.tang.49000.json','["月落霜繁深院閉，洞房人正睡。", "桐樹倚雕簷，金井臨瑤砌。", "曉風寒不啻，獨立成顦顇，閑愁渾未已。", "離人心緒自無端，莫思量，休退悔。"]'),
('fc87a16a-2d3d-4996-b546-0858a93d5deb','芳草渡','馮延巳','唐','唐诗','tang','','[]','梧桐落，蓼花秋。',71,'全唐诗/poet.tang.49000.json','["梧桐落，蓼花秋。", "煙初冷，雨纔收。", "蕭條風物正堪愁，人去後，多少恨，在心頭。", "燕鴻遠，羌笛怨，渺渺澄波一片。", "山如黛，月如鉤。", "笙歌散，夢魂斷，倚高樓。"]'),
('7bf50ee3-438c-4cde-b7d1-addc5b3435e4','南鄉子 一','馮延巳','唐','唐诗','tang','','[]','細雨濕流光，芳草年年與恨長。',66,'全唐诗/poet.tang.49000.json','["細雨濕流光，芳草年年與恨長。", "煙鎖鳳樓無限事，茫茫，鸞鏡鴛衾兩斷腸。", "魂夢任悠揚，睡起楊花滿繡牀。", "薄倖不來門半掩，斜陽，負你殘春淚幾行。"]'),
('87667899-17f5-43b4-adb0-e3eb3b0a3236','南鄉子 二','馮延巳','唐','唐诗','tang','','[]','細雨泣秋風，金鳳花[殘]滿地紅。',70,'全唐诗/poet.tang.49000.json','["細雨泣秋風，金鳳花[殘]滿地紅。", "閑[蹙]黛眉慵不語，情緒，寂寞相思知幾許。", "玉枕擁孤衾，挹恨還聞歲月深。", "簾卷曲房誰共醉，顦顇，惆悵秦樓彈粉淚。"]'),
('edfac3cf-27cf-42e0-90ab-e9a8238aebbf','舞春風','馮延巳','唐','唐诗','tang','','[]','嚴妝纔罷怨春風，粉牆畫壁宋家東。',64,'全唐诗/poet.tang.49000.json','["嚴妝纔罷怨春風，粉牆畫壁宋家東。", "蕙蘭有恨枝尤綠，桃李無言花自紅。", "燕燕巢兒羅幕卷，鶯鶯啼處鳳樓空。", "少年薄倖知何處，每夜歸來春夢中。"]'),
('61d856b5-781d-4528-8aa4-af17582cc44d','虞美人 一','馮延巳','唐','唐诗','tang','','[]','玉鉤鸞柱調鸚鵡，宛轉留春語。',66,'全唐诗/poet.tang.49000.json','["玉鉤鸞柱調鸚鵡，宛轉留春語。", "雲屏冷落畫堂空，薄晚春寒，無奈落花風。", "搴簾燕子低飛去，拂鏡塵鸞舞。", "不知今夜月眉彎，誰佩同心雙結，倚闌干。"]'),
('3bcc3825-58cc-4634-8827-13ef623a8067','虞美人 二','馮延巳','唐','唐诗','tang','','[]','春風拂拂橫秋水，掩映遙相對。',66,'全唐诗/poet.tang.49000.json','["春風拂拂橫秋水，掩映遙相對。", "秪知長作碧窗期，誰信東風，吹散彩雲飛。", "銀屏夢與飛鸞遠，秪有珠簾卷。", "楊花零落月溶溶，塵掩玉箏弦柱，畫堂空。"]'),
('57cf05b6-5a03-4fc4-9765-4fc9739844aa','臨江仙','馮延巳','唐','唐诗','tang','','[]','冷紅飄起桃花片，青春意緒闌珊。',68,'全唐诗/poet.tang.49000.json','["冷紅飄起桃花片，青春意緒闌珊。", "高樓簾幕卷輕寒，酒餘人散，獨自倚闌干。", "夕陽千里連芳草，風光愁殺王孫。", "徘徊飛盡碧天雲，鳳城何處，明月照黃昏。"]'),
('8bfbacc6-26af-4fd4-a645-7d7ab1cb011d','蝶戀花 一','馮延巳','唐','唐诗','tang','','[]','窗外寒雞天欲曙，香印成灰，坐起渾無緒。',70,'全唐诗/poet.tang.49000.json','["窗外寒雞天欲曙，香印成灰，坐起渾無緒。", "庭際高梧凝宿霧，卷簾雙鵲驚飛去。", "屏上羅衣閑繡縷，一晌關情，憶遍江南路。", "夜夜夢魂休謾語，已知前事無情處。"]'),
('b513b4f5-7c33-4fa5-9707-88ddb7556b4c','蝶戀花 二','馮延巳','唐','唐诗','tang','','[]','蕭索清秋珠淚墜，枕簟微涼，展轉渾無寐。',70,'全唐诗/poet.tang.49000.json','["蕭索清秋珠淚墜，枕簟微涼，展轉渾無寐。", "殘酒欲醒中夜起，月明如練天如水。", "堦下寒聲啼絡緯，庭樹金風，悄悄重門閉。", "可惜舊歡攜手地，思量一夕成憔悴。"]'),
('31af4498-2d1e-42e3-851a-d31d5393d4ef','蝶戀花 三','馮延巳','唐','唐诗','tang','','[]','幾度鳳樓同飲宴，此夕相逢，却勝當時見。',70,'全唐诗/poet.tang.49000.json','["幾度鳳樓同飲宴，此夕相逢，却勝當時見。", "低語前歡頻轉面，雙眉歛恨春山遠。", "蠟燭淚流羌笛怨，偷整羅衣，欲唱情猶嬾。", "醉裏不辭金爵滿，陽關一曲腸千斷。"]'),
('8a221be8-63a7-4fe7-83db-54828ac8f9d5','蝶戀花 四','馮延巳','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5b64\u72ec", "\u5973\u5b50", "\u95fa\u6028", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd"]','幾日行雲何處去，忘了歸來，不道春將暮。',70,'全唐诗/poet.tang.49000.json','["幾日行雲何處去，忘了歸來，不道春將暮。", "百草千花寒食路，香車繫在誰家樹。", "淚眼倚樓頻獨語，雙燕飛來，陌上相逢否。", "撩亂春愁如柳絮，悠悠夢裏無尋處。"]'),
('ca6c25dd-5fd3-4242-bf68-bad5312e11c4','蝶戀花 五','馮延巳','唐','唐诗','tang','','["\u5199\u666f", "\u6e05\u660e\u8282", "\u56de\u5fc6", "\u4f24\u6000"]','六曲闌干偎碧樹，楊柳風輕，展盡黃金縷。',70,'全唐诗/poet.tang.49000.json','["六曲闌干偎碧樹，楊柳風輕，展盡黃金縷。", "誰把鈿箏移玉柱，穿簾海燕雙飛去。", "滿眼遊絲兼落絮，紅杏開時，一霎清明雨。", "濃醉覺來鶯亂語，驚殘好夢無尋處。"]'),
('cfe5f1fe-47bd-45f0-ba58-efb8eff03cec','蝶戀花 六','馮延巳','唐','唐诗','tang','','["\u4eba\u751f", "\u611f\u53f9", "\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u6625\u6101", "\u5a49\u7ea6"]','誰道閑情拋棄久，每到春來，惆悵還依舊。',70,'全唐诗/poet.tang.49000.json','["誰道閑情拋棄久，每到春來，惆悵還依舊。", "日日花前常病酒，不辭鏡裏朱顏瘦。", "河畔青蕪堤上柳，爲問新愁，何事年年有。", "獨立小樓風滿袖，平林新月人歸後。"]'),
('17121e57-7aa3-4a1d-90e5-3bc53b694574','壽山曲','馮延巳','唐','唐诗','tang','','[]','銅壺滴漏初盡，高閤雞鳴半空。',74,'全唐诗/poet.tang.49000.json','["銅壺滴漏初盡，高閤雞鳴半空。", "[催啓]五門金鎖，猶垂三殿簾櫳。", "階前御柳搖綠，仗下宮花散紅。", "鴛瓦數行曉日，[鸞]旗百尺春風。", "侍臣舞蹈重拜，聖壽南山永同。"]'),
('4e4aef7d-28c9-4235-be1f-cab5397b48ae','思越人','馮延巳','唐','唐诗','tang','','[]','酒醒情懷惡，金縷褪，玉肌如削。',55,'全唐诗/poet.tang.49000.json','["酒醒情懷惡，金縷褪，玉肌如削。", "寒食過却，海棠零落。", "乍倚遍，闌干煙淡薄，翠幕簾櫳畫閣。", "春睡著，覺來失，鞦韆期約。"]'),
('c467c217-d0b3-45fc-98a0-37b9b432f15e','上行杯','馮延巳','唐','唐诗','tang','','["\u6625\u5929", "\u6625\u5929\uff5c\u5199\u4eba"]','落梅暑雨消殘粉，雲重煙深寒食近。',58,'全唐诗/poet.tang.49000.json','["落梅暑雨消殘粉，雲重煙深寒食近。", "羅幕遮香，柳外鞦韆出畫牆。", "春山顛倒釵橫鳳，飛絮入簾春睡重。", "夢裏佳期，秪許庭花與月知。"]'),
('02b45ec9-2f4d-41ed-8c68-9253f5ac222b','薄命妾','馮延巳','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u592b\u59bb", "\u795d\u613f", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u996e\u9152", "\u5a49\u7ea6"]','春日宴，綠酒一杯歌一遍，再拜陳三願。',46,'全唐诗/poet.tang.49000.json','["春日宴，綠酒一杯歌一遍，再拜陳三願。", "一願郎君千歲，二願妾身長健，三願如同梁上燕，歲歲長相見。"]'),
('da17c64c-6313-4b73-9989-64a262ab3af8','金錯刀 一','馮延巳','唐','唐诗','tang','','[]','雙玉斗，百瓊壺，佳人歡飲笑喧呼。',64,'全唐诗/poet.tang.49000.json','["雙玉斗，百瓊壺，佳人歡飲笑喧呼。", "麒麟欲畫時難偶，鷗鷺何猜興不孤。", "歌婉轉，醉模糊，高燒銀燭臥流蘇。", "只銷幾覺懵騰睡，身外功名任有無。"]'),
('35d5771e-fc1c-4d68-99bf-c9c31c41524f','金錯刀 二','馮延巳','唐','唐诗','tang','','[]','日融融，草芊芊，黃鶯求友啼林前。',64,'全唐诗/poet.tang.49000.json','["日融融，草芊芊，黃鶯求友啼林前。", "柳條嫋嫋拖金線，花蘂茸茸簇錦氈。", "鳩逐婦，燕穿簾，狂蜂浪蝶相翩翩。", "春光堪賞還堪翫，惱殺東風悞少年。"]'),
('1d0df616-9e14-4237-a470-7520d2c7bf9d','憶江南 一','馮延巳','唐','唐诗','tang','','[]','去歲迎春樓上月，正是西窗，夜涼時節。',68,'全唐诗/poet.tang.49000.json','["去歲迎春樓上月，正是西窗，夜涼時節。", "玉人貪睡墜釵雲，粉消妝薄見天真。", "人非風月長依舊，破鏡塵箏一夢經年瘦。", "今宵簾幕颺花陰，空餘枕淚獨傷心。"]'),
('65da009a-662f-45e6-84aa-1fc9a0d1034e','憶江南 二','馮延巳','唐','唐诗','tang','','[]','今日相逢花未發，正是去年，別離時節。',68,'全唐诗/poet.tang.49000.json','["今日相逢花未發，正是去年，別離時節。", "東風次第有花開，恁時須約却重來。", "重來不怕花堪折，秪恐明年花發人離別。", "別離若向百花時，東風彈淚有誰知。"]'),
('7cc7dfdb-ae61-4f88-987e-ed530573f0e7','木蘭花','徐昌圖','唐','唐诗','tang','','[]','沈檀煙起盤紅霧，一箭霜風吹繡戶。',64,'全唐诗/poet.tang.49000.json','["沈檀煙起盤紅霧，一箭霜風吹繡戶。", "漢宮花面學梅妝，謝女雪詩栽柳絮。", "長垂夾幕孤鸞舞，旋炙銀笙雙鳳語。", "紅窗酒病嚼寒冰，冰損相思無夢處。"]'),
('b061a7ec-aecb-4e28-b87e-0f57c5862949','臨江仙','徐昌圖','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5b64\u72ec", "\u5377\u4e8c\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u5199\u666f", "\u5a49\u7ea6"]','飲散離亭西去，浮生常恨飄蓬。',68,'全唐诗/poet.tang.49000.json','["飲散離亭西去，浮生常恨飄蓬。", "回頭煙柳漸重重，淡雲孤鴈遠，寒日暮天紅。", "今夜畫船何處，潮平淮月朦朧。", "酒醒人靜奈愁濃，殘燈孤枕夢，輕浪五更風。"]'),
('af8721a5-4fb3-4f18-9d66-833baa208fca','河傳','徐昌圖','唐','唐诗','tang','','["\u79cb\u5929"]','秋光滿目，風清露白，蓮紅水綠。',71,'全唐诗/poet.tang.49000.json','["秋光滿目，風清露白，蓮紅水綠。", "何處夢回，弄珠拾翠盈盈。", "倚闌橈，眉黛蹙。", "采蓮調穩，吳侶聲相續，倚棹吳江曲。", "鷺起暮天，幾雙交頸鴛鴦，入蘆花深處宿。"]'),
('95a8b979-7512-438c-a807-b175febd539a','拋毬樂 一','徐鉉','唐','唐诗','tang','','[]','歌舞送飛毬，金觥碧玉籌。',36,'全唐诗/poet.tang.49000.json','["歌舞送飛毬，金觥碧玉籌。", "管弦桃李月，簾幕鳳皇樓。", "一笑千場醉，浮生任白頭。"]'),
('c630c840-f227-4882-9104-49bd4bfa2fb7','拋毬樂 二','徐鉉','唐','唐诗','tang','','[]','灼灼傅花枝，紛紛度畫旂。',36,'全唐诗/poet.tang.49000.json','["灼灼傅花枝，紛紛度畫旂。", "不知紅燭下，照見彩毬飛。", "借勢因期尅，巫山暮雨歸。"]'),
('3bae413a-b4af-4a64-aefe-90c024dc2bb7','木蘭花','庾傳素','唐','唐诗','tang','','[]','木蘭紅豔多情態，不似凡花人不愛。',66,'全唐诗/poet.tang.49000.json','["木蘭紅豔多情態，不似凡花人不愛。", "移來孔雀檻邊栽，折向鳳皇釵上戴。", "是何芍藥爭風彩，自共[牡]丹長作對。", "若教爲女嫁東風，除却黃鶯難匹配。"]'),
('9de57cd2-de97-4216-a48f-51a285c09ffa','生查子','劉侍讀','唐','唐诗','tang','','[]','深秋更漏長，滴盡銀臺燭。',48,'全唐诗/poet.tang.49000.json','["深秋更漏長，滴盡銀臺燭。", "獨步出幽閨，月晃波澄綠。", "菱荷風乍觸，一對鴛鴦宿。", "虛櫂玉釵驚，驚起還相續。"]'),
('56f03ec3-4715-4481-af04-af0b019ac29b','木蘭花 一','許岷','唐','唐诗','tang','','[]','小庭日晚花零落，倚戶無聊妝臉薄。',64,'全唐诗/poet.tang.49000.json','["小庭日晚花零落，倚戶無聊妝臉薄。", "寶箏金鴨任生塵，繡畫工夫全放却。", "有時覷著同心結，萬恨千愁無處說。", "當初不合儘饒伊，贏得如今長恨別。"]'),
('ec559d38-d063-4ccd-858a-36cf6461c4f8','木蘭花 二','許岷','唐','唐诗','tang','','[]','江南日暖芭蕉展，美人折得親裁翦。',64,'全唐诗/poet.tang.49000.json','["江南日暖芭蕉展，美人折得親裁翦。", "畫成小簡寄情人，臨行更把輕輕撚。", "其中撚破相思字，却恐郎疑蹤不似。", "若還猜妾倩人書，誤了平生多少事。"]'),
('776edd10-d0c0-4e09-9ad5-87b1377f4e91','菩薩蠻','林楚翹','唐','唐诗','tang','','[]','畫堂春晝垂珠箔，臥來揉惹金釵落。',52,'全唐诗/poet.tang.49000.json','["畫堂春晝垂珠箔，臥來揉惹金釵落。", "簟滑枕頭移，鬢蟬狂欲飛。", "笑拖嬌眼慢，羅袖籠花面。", "重道好郎君，人前莫惱人。"]'),
('b6936a6c-47c8-4caf-b114-fcaf9609479d','一片子','無名氏','唐','唐诗','tang','','[]','柳色青山映，梨花雪鳥藏。',24,'全唐诗/poet.tang.49000.json','["柳色青山映，梨花雪鳥藏。", "綠窗桃李下，閑坐歎春芳。"]'),
('9a3e3618-f57f-42c6-8c0e-3364db244e5d','塞姑','無名氏','唐','唐诗','tang','','[]','昨日盧梅塞口，整見諸人鎮守。',28,'全唐诗/poet.tang.49000.json','["昨日盧梅塞口，整見諸人鎮守。", "都護三年不歸，折盡江邊楊柳。"]'),
('8db991e6-cd4b-4042-b416-26965a16e294','醉公子','無名氏','唐','唐诗','tang','','["\u5a49\u7ea6", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','門外猧兒吠，知是蕭郎至。',48,'全唐诗/poet.tang.49000.json','["門外猧兒吠，知是蕭郎至。", "剗襪下香階，冤家今夜醉。", "扶得入羅幃，不肯脫羅衣。", "醉則從他醉，還勝獨睡時。"]'),
('e2aa5d4e-8685-43a4-906a-441097a51fac','菩薩蠻','無名氏','唐','唐诗','tang','','["\u7231\u60c5", "\u5973\u5b50", "\u5a49\u7ea6"]','牡丹含露真珠顆，美人折向庭前過。',52,'全唐诗/poet.tang.49000.json','["牡丹含露真珠顆，美人折向庭前過。", "含笑問檀郎，花強妾貌強。", "檀郎故相惱，須道花枝好。", "一面發嬌嗔，碎挼花打人。"]'),
('b94c8bad-e982-4625-9a9b-e9a5c6e66a24','賀聖朝','無名氏','唐','唐诗','tang','','[]','白露點，曉星明滅，秋風落葉。',58,'全唐诗/poet.tang.49000.json','["白露點，曉星明滅，秋風落葉。", "故址頹垣，冷煙衰草，前朝宮闕。", "長安道上行客，依舊利深名切。", "改變容顏，消磨今古，隴頭殘月。"]'),
('74fe7e95-9350-4357-8921-6f6d6b654998','虞美人','無名氏','唐','唐诗','tang','','[]','帳中草草軍情變，月下旌旗亂。',68,'全唐诗/poet.tang.49000.json','["帳中草草軍情變，月下旌旗亂。", "褫衣推枕愴離情，遠風吹下楚歌聲，正三更。", "撫騅欲下重相顧，豔態花無主。", "手中蓮鍔凜秋霜，九泉歸去是仙鄉，恨茫茫。"]'),
('20fac5fc-bc10-4982-842e-de5b59195b0e','後庭宴','無名氏','唐','唐诗','tang','','[]','千里故鄉，十年華屋，亂魂飛過屏山簇。',75,'全唐诗/poet.tang.49000.json','["千里故鄉，十年華屋，亂魂飛過屏山簇。", "眼重眉褪不勝春，菱花知我銷香玉。", "雙雙燕子歸來，應解笑人幽獨。", "斷歌零舞，遺恨清江曲。", "萬樹綠低迷，一庭紅{艹/撲}𫂙。"]'),
('ff4943ef-4dd7-41c8-a4fa-20a4e11f70e7','擷芳詞','無名氏','唐','唐诗','tang','','[]','風搖蕩，雨濛茸，翠條柔弱花頭重。',70,'全唐诗/poet.tang.49000.json','["風搖蕩，雨濛茸，翠條柔弱花頭重。", "春衫窄，香肌濕，記得年時，共伊曾[摘]。", "都如夢，何曾共，可憐孤似釵頭鳳。", "關山隔，晚雲碧，燕兒來也，又無消息。"]'),
('0d4845a7-22a2-4c81-820c-8460e2c913d8','魚遊春水','無名氏','唐','唐诗','tang','','["\u601d\u5ff5", "\u95fa\u6028", "\u6625\u5929", "\u5a49\u7ea6"]','秦樓東風裏，燕子還來尋舊壘。',105,'全唐诗/poet.tang.49000.json','["秦樓東風裏，燕子還來尋舊壘。", "餘寒猶峭，紅日薄侵羅綺。", "嫩草方抽碧玉茵，媚柳輕窣黃金縷。", "鶯轉上林，魚遊春水。", "幾曲闌干遍倚，又是一番新桃李。", "佳人應怪歸遲，梅妝淚洗。", "鳳簫聲絕沈孤鴈，望斷清波無雙鯉。", "雲山萬重，寸心千里。"]'),
('7f7e226a-46d9-4a9f-8efe-4525920db4a6','阿那曲','楊貴妃','唐','唐诗','tang','','[]','羅袖動香香不已，紅蕖嫋嫋秋煙裏。',32,'全唐诗/poet.tang.49000.json','["羅袖動香香不已，紅蕖嫋嫋秋煙裏。", "輕雲嶺下乍搖風，嫩柳池塘初拂水。"]'),
('978e67ae-af35-4457-aaca-1d2f3c210769','樂遊曲 一','閩后陳氏','唐','唐诗','tang','','[]','龍舟搖曳東復東，采蓮湖上紅更紅。',32,'全唐诗/poet.tang.49000.json','["龍舟搖曳東復東，采蓮湖上紅更紅。", "波淡淡，水溶溶，奴隔荷花路不通。"]'),
('e0babb46-2fb7-4710-acde-f819dfe4fc7d','樂遊曲 二','閩后陳氏','唐','唐诗','tang','','["\u897f\u6e56"]','西湖南湖鬬綵舟，青蒲紫蓼滿中洲。',32,'全唐诗/poet.tang.49000.json','["西湖南湖鬬綵舟，青蒲紫蓼滿中洲。", "波渺渺，水悠悠，長奉君王萬歲遊。"]'),
('9c619b58-00aa-418f-beb7-103c5f914bfe','楊柳枝','柳氏','唐','唐诗','tang','','[]','楊柳枝，芳菲節，可恨年年贈離別。',32,'全唐诗/poet.tang.49000.json','["楊柳枝，芳菲節，可恨年年贈離別。", "一葉隨風忽報秋，縱使君來豈堪折。"]'),
('cf19cbe0-2ec7-4f4b-823f-c21646165b82','字字雙','王麗真女郎','唐','唐诗','tang','','[]','牀頭錦衾斑復斑，架上朱衣殷復殷。',32,'全唐诗/poet.tang.49000.json','["牀頭錦衾斑復斑，架上朱衣殷復殷。", "空庭明月閑復閑，夜長路遠山復山。"]'),
('ca8992f8-291a-48ef-9988-8c0b644c3fc8','菩薩蠻','耿玉真','唐','唐诗','tang','','["\u6292\u60c5"]','玉京人去秋蕭索，畫簷鵲起梧桐落。',49,'全唐诗/poet.tang.49000.json','["玉京人去秋蕭索，畫簷鵲起梧桐落。", "欹枕悄無言，月和殘夢圓。", "背燈唯暗泣甚處砧聲急眉黛遠山攢芭蕉生暮寒。"]'),
('0488f605-2f27-4137-b127-759d53d963db','句 一','耿玉真','唐','唐诗','tang','','[]','庭空客散人歸後，畫堂半掩朱簾。',36,'全唐诗/poet.tang.49000.json','["庭空客散人歸後，畫堂半掩朱簾。", "林風[淅淅]夜厭厭，小樓新月，回首自纖纖。"]'),
('eda59a31-d907-40fb-862b-72d73b66f4ce','句 二','耿玉真','唐','唐诗','tang','','[]','春光鎮在人空老，新愁往恨何窮。',34,'全唐诗/poet.tang.49000.json','["春光鎮在人空老，新愁往恨何窮。", "金窗力困起還慵，一聲羌笛，驚起醉怡容。"]'),
('37e7c8de-bc8a-4002-ad5f-c5913329380f','句 三','耿玉真','唐','唐诗','tang','','[]','尋春須是陽春早，看花莫待花枝老。',16,'全唐诗/poet.tang.49000.json','["尋春須是陽春早，看花莫待花枝老。"]'),
('f399b1c6-13be-4dad-afa8-feb02b28ee69','句 四','耿玉真','唐','唐诗','tang','','[]','帝鄉煙雨鎖春愁，故國山川空淚眼。',16,'全唐诗/poet.tang.49000.json','["帝鄉煙雨鎖春愁，故國山川空淚眼。"]'),
('bf9d66fe-9016-43a0-b421-d333eed0923f','句 五','耿玉真','唐','唐诗','tang','','[]','金鳳欲飛遭掣搦，情脈脈，看即玉樓雲雨隔。',20,'全唐诗/poet.tang.49000.json','["金鳳欲飛遭掣搦，情脈脈，看即玉樓雲雨隔。"]'),
('3b60f722-b912-4b3c-b00e-4056521c92b4','句 六','耿玉真','唐','唐诗','tang','','[]','桃李不須誇爛熳，已輸了風吹一半。',16,'全唐诗/poet.tang.49000.json','["桃李不須誇爛熳，已輸了風吹一半。"]'),
('f3890eb4-8be2-43a9-a824-62431fd48aa2','句 七','耿玉真','唐','唐诗','tang','','[]','學著荷衣還可喜，年少多來有幾，自古閑愁無際。',22,'全唐诗/poet.tang.49000.json','["學著荷衣還可喜，年少多來有幾，自古閑愁無際。"]'),
('a2225ec3-c939-423d-acd9-3b5430bb6c6e','句 八','耿玉真','唐','唐诗','tang','','[]','初離蜀道心將碎，離恨綿綿，春日如年，馬上時時聞杜鵑。',26,'全唐诗/poet.tang.49000.json','["初離蜀道心將碎，離恨綿綿，春日如年，馬上時時聞杜鵑。"]'),
('8753a366-a20a-496d-b53a-1807f85dd14f','梧桐影','呂巖','唐','唐诗','tang','','["\u601d\u5ff5", "\u53cb\u4eba", "\u5a49\u7ea6"]','落日斜，秋風冷。',24,'全唐诗/poet.tang.49000.json','["落日斜，秋風冷。", "今夜故人來不來，教人立盡梧桐影。"]'),
('c8e060c0-34aa-4623-a1f9-6b003a635212','憶江南 一','呂巖','唐','唐诗','tang','','[]','淮南法，秋石最堪誇。',32,'全唐诗/poet.tang.49000.json','["淮南法，秋石最堪誇。", "位應乾坤白露節，象移寅卯紫河車，子午結朝霞。"]'),
('8d623962-e293-4cc8-ae05-4fd069c71eec','憶江南 二','呂巖','唐','唐诗','tang','','[]','王陽術，得祕是黃牙。',32,'全唐诗/poet.tang.49000.json','["王陽術，得祕是黃牙。", "萬蘂初生將此類，黃鍾應律始歸家，十月定君誇。"]'),
('f7e6cfc6-3b1f-47d9-87c5-1b8a58c710dc','憶江南 三','呂巖','唐','唐诗','tang','','[]','黃帝術，玄妙美金花。',32,'全唐诗/poet.tang.49000.json','["黃帝術，玄妙美金花。", "玉液初凝紅粉見，乾坤覆載暗交加，龍虎變成砂。"]'),
('e99d2274-cdbe-47d4-a7ca-d78c6aa946a1','憶江南 四','呂巖','唐','唐诗','tang','','[]','長生術，玄要補泥丸。',32,'全唐诗/poet.tang.49000.json','["長生術，玄要補泥丸。", "彭祖得之年八百，世人因此轉傷殘，誰是識陰丹。"]'),
('8a192a67-78fe-4baa-9e92-6b0ab508cfb7','憶江南 五','呂巖','唐','唐诗','tang','','[]','陰丹訣，三五合玄圖。',32,'全唐诗/poet.tang.49000.json','["陰丹訣，三五合玄圖。", "二八應機堪采運，玉瓊回首免榮枯，顏貌勝凡姝。"]'),
('91452add-317c-4c8f-8159-a1a722320013','憶江南 六','呂巖','唐','唐诗','tang','','[]','長生術，初九祕潛龍。',32,'全唐诗/poet.tang.49000.json','["長生術，初九祕潛龍。", "慎勿從高宜作客，丹田流注氣交通，耆老反嬰童。"]'),
('32ac9a3e-2d42-4662-884f-5d26c51cf4c3','憶江南 七','呂巖','唐','唐诗','tang','','[]','修身客，莫誤入迷津。',32,'全唐诗/poet.tang.49000.json','["修身客，莫誤入迷津。", "氣術金丹傳在世，象天象地象人身，不用問東鄰。"]'),
('39de066b-2f43-4a77-9528-3b09819fa0f0','憶江南 八','呂巖','唐','唐诗','tang','','[]','還丹訣，九九最幽玄。',32,'全唐诗/poet.tang.49000.json','["還丹訣，九九最幽玄。", "三性本同一體內，要燒靈藥切尋鉛，尋得是神仙。"]'),
('ef0b88fc-b0fd-41d2-a236-818dbb9dcdc7','憶江南 九','呂巖','唐','唐诗','tang','','[]','長生藥，不用問他人。',32,'全唐诗/poet.tang.49000.json','["長生藥，不用問他人。", "八卦九宮看掌上，五行四象在人身，明了自通神。"]'),
('d60c46c5-fd75-4ff5-916a-6085e89f2e68','憶江南 十','呂巖','唐','唐诗','tang','','[]','學道客，修養莫遲遲。',32,'全唐诗/poet.tang.49000.json','["學道客，修養莫遲遲。", "光景斯須如夢裏，還丹粟粒變金姿，死去莫回歸。"]'),
('b1ed58ca-02c5-49b3-81f5-a20752f98f8d','憶江南 十一','呂巖','唐','唐诗','tang','','[]','治生客，審細察微言。',32,'全唐诗/poet.tang.49000.json','["治生客，審細察微言。", "百歲夢中看即過，勸君修煉保尊年，不久是神仙。"]'),
('2b0cf058-9216-48a3-898f-9a4868c36c77','憶江南 十二','呂巖','唐','唐诗','tang','','[]','瑤池上，瑞霧靄羣仙。',64,'全唐诗/poet.tang.49000.json','["瑤池上，瑞霧靄羣仙。", "素練金童鏘鳳板，青衣玉女嘯鸞弦，身在大羅天。", "沉醉處，縹渺玉京山。", "唱徹步虛清燕罷，不知今夕是何年，海水又桑田。"]'),
('6560bcad-c106-4db5-9a4f-13201b9d820b','西江月 一','呂巖','唐','唐诗','tang','','[]','著意黃庭歲久，留心金碧年深。',58,'全唐诗/poet.tang.49000.json','["著意黃庭歲久，留心金碧年深。", "爲憂白髮鬢相侵，仙訣朝朝討論。", "秘要俱皆覽過，神仙奧旨重吟。", "至人親指水中金，不負平生志性。"]'),
('890c7427-d465-45d2-a05a-ce7d2bd339cd','西江月 二','呂巖','唐','唐诗','tang','','[]','任是聰明志士，常迷東竈黃庭。',58,'全唐诗/poet.tang.49000.json','["任是聰明志士，常迷東竈黃庭。", "參同大易事分明，不曉醉眠難醒。", "若遇高人指引，都來不費功程。", "北方坎子是金精，忍得黃牙方盛。"]'),
('f79b2166-8d8d-4543-8a03-561230d5a256','沁園春 一','呂巖','唐','唐诗','tang','','[]','七返還丹，在我先須，煉已待時。',140,'全唐诗/poet.tang.49000.json','["七返還丹，在我先須，煉已待時。", "正一陽初動，中宵漏永。", "溫溫鉛鼎，光透簾幃。", "造化爭馳，虎龍交媾，進火功夫牛斗危。", "曲江上，看月華瑩淨，有箇烏飛。", "當時，自飲刀圭，又誰信無中就養兒。", "辨水源清濁，木金間隔。", "不因師指，此事難知。", "道要玄微，天機深遠，下手忙修猶太遲。", "蓬萊路，待三千行滿，獨步雲歸。"]'),
('c1e456f2-641f-45a6-840c-fc798915730b','沁園春 二','呂巖','唐','唐诗','tang','','[]','火宅牽纏，夜去明來，早晚擔憂。',140,'全唐诗/poet.tang.49000.json','["火宅牽纏，夜去明來，早晚擔憂。", "奈今日茫然，不知明日。", "波波劫劫，有甚來由。", "人世風燈，草頭珠露，我見傷心眼淚流。", "不堅久，似石中迸火，水上浮漚。", "休休，及早回頭，把往日風流一筆鉤。", "但麤衣淡飯，隨緣度日。", "任人笑我，我又何求。", "限到頭來，不論貧富，著甚干忙日夜憂。", "勸年少，把家緣棄了，海上來遊。"]'),
('49080a9f-d874-49f6-811f-4d7207698bb1','沁園春 三','呂巖','唐','唐诗','tang','','[]','詩曲文章，任汝空留，數千萬篇。',140,'全唐诗/poet.tang.49000.json','["詩曲文章，任汝空留，數千萬篇。", "奈日推一日，月推一月。", "今年不了，又待來年。", "有限光陰，無涯火院，只恐蹉跎老却賢。", "貪癡漢，望成家學道，兩事雙全。", "凡間，只戀塵緣，又誰信壺中別有天。", "這道本無情，不親富貴。", "不疎貧賤，只要心堅。", "不在勞神，不須苦行，息慮忘機合自然。", "長生事，待明公放下，方可相傳。"]'),
('cb40d068-a6dd-4c64-9da2-e45a0a26be64','卜算子','呂巖','唐','唐诗','tang','','[]','心空道亦空，風靜林還靜。',52,'全唐诗/poet.tang.49000.json','["心空道亦空，風靜林還靜。", "卷盡浮雲月自明，中有山河影。", "供養及修行，舊話成重省。", "豆爆生蓮火裏時，痛撥寒灰冷。"]'),
('a2058921-ae4f-4946-9e42-236f5e63fd8b','步蟾宮','呂巖','唐','唐诗','tang','','[]','坎離乾兌逢子午，須認取，自家根祖。',66,'全唐诗/poet.tang.49000.json','["坎離乾兌逢子午，須認取，自家根祖。", "地雷震動山頭雨，要洗濯黃牙土。", "捉得金精牢閉錮，煉甲庚，要生龍虎。", "待他問汝甚人傳，但說道，先生姓呂。"]'),
('2cf0801e-a524-479a-bdeb-e7988496e86c','滿庭芳','呂巖','唐','唐诗','tang','','[]','大道淵源，高真隱秘，風流豈可知聞。',118,'全唐诗/poet.tang.49000.json','["大道淵源，高真隱秘，風流豈可知聞。", "先天一氣，清濁自然分。", "不識坎離顛倒，誰能辨，金木浮沈。", "幽微處，無中產有，澗畔虎龍吟。", "壺中，真造化，天精地髓，陰魄陽魂。", "運周天水火，燮理寒溫。", "十月脫胎丹就，除此外，皆是傍門。", "君知否，塵寰走徧，端的少知音。"]'),
('693a5119-99c3-430b-9ece-110bc27a1339','酹江月','呂巖','唐','唐诗','tang','','[]','仙風道骨，顛倒運乾坤，平分時節。',119,'全唐诗/poet.tang.49000.json','["仙風道骨，顛倒運乾坤，平分時節。", "金木相交坎離位，一粒刀圭凝結。", "水虎潛形，火龍伏體，萬丈毫光烈。", "仙花朵秀，聖男靈女扳折。", "霄漢此夜中秋，銀蟾離海，浪卷千層雪。", "此是天關地軸，誰解推窮圓缺。", "片晌功夫，霎時丹聚，到此憑何訣。", "倚天長嘯，洞中無限風月。"]'),
('5e3afafd-08b0-455f-96ec-cbf6b42a17f8','水龍吟','呂巖','唐','唐诗','tang','','[]','目前咫尺長生路，多少愚人不悟。',129,'全唐诗/poet.tang.49000.json','["目前咫尺長生路，多少愚人不悟。", "愛河浪闊，洪波風緊，舟船難渡。", "略聽仙師語，到彼岸。", "只消一句，煉金丹換了，凡胎濁骨。", "免輪迴，三塗苦。", "萬事澄心定意，聚真陽，都歸一處。", "分明認得，靈光真趣，本來面目。", "此箇幽微理，莫容易，等閑分付。", "知蓬萊自有，神仙伴侶，同攜手，朝天去。"]'),
('fe347a3d-272c-4630-80cb-2c9ca3433f05','豆葉黃','呂巖','唐','唐诗','tang','','[]','二月江南山水路，李花零落春無主。',36,'全唐诗/poet.tang.49000.json','["二月江南山水路，李花零落春無主。", "一箇魚兒無覓處，風和雨，玉龍生甲歸天去。"]'),
('0a3c409c-7d6e-4585-9d7b-dc8c154d2287','浪淘沙','呂巖','唐','唐诗','tang','','[]','我有屋三椽，住在靈源。',64,'全唐诗/poet.tang.49000.json','["我有屋三椽，住在靈源。", "無遮四壁任蕭然，萬象森羅爲斗拱，瓦蓋青天。", "無漏得多年，結就因緣。", "修成功行滿三千，降得火龍伏得虎，陸路神仙。"]'),
('3a8a4be0-3124-4c39-863e-6ee781d79817','蘇幙遮','呂巖','唐','唐诗','tang','','[]','天不高，地不大，惟有真心，物物俱含載。',76,'全唐诗/poet.tang.49000.json','["天不高，地不大，惟有真心，物物俱含載。", "不用之時全體在，用即拈來，萬象周沙界。", "虛無中，塵色內，盡是還丹，歷歷堪收采。", "這箇鼎鑪解不解，養就靈烏，飛出光明海。"]'),
('05fd3d42-ee74-4b05-a06b-281d697b4ec4','雨中花','呂巖','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','三百年間，功標青史，幾多俱委埃塵。',114,'全唐诗/poet.tang.49000.json','["三百年間，功標青史，幾多俱委埃塵。", "悟黃粱棄事，厭世藏身。", "將我一枝丹桂，換他千載青春。", "岳陽樓上，綸巾羽扇，誰識天人。", "蓬萊願應仙舉，誰知會合仙賓。", "遙想望，吹笙玉殿，奏舞鸞裀。", "風馭雲軿不散，碧桃紫奈長新。", "願逢一粒，九霞光裏，相繼朝真。"]'),
('13b52eb4-5bf0-4112-9281-abd4be0295d2','促拍滿路花','呂巖','唐','唐诗','tang','','["\u5e90\u5c71"]','西風吹渭水，落葉滿長安。',104,'全唐诗/poet.tang.49000.json','["西風吹渭水，落葉滿長安。", "茫茫塵世裏，獨清閑。", "自然鑪鼎，虎繞與龍盤。", "九轉丹砂就，一粒刀圭，便成陸地神仙。", "任萬釘寶帶貂蟬，富貴欲熏天。", "黃粱炊未熟，夢驚殘。", "是非海裏，直道作人難。", "袖手江南去，白蘋紅蓼，又尋湓浦廬山。"]'),
('63e1f80b-f679-407a-b139-9f954c3b5a07','六么令','呂巖','唐','唐诗','tang','','[]','東與西，眼與眉。',38,'全唐诗/poet.tang.49000.json','["東與西，眼與眉。", "偃月爐中運坎離，靈砂且上飛。", "最幽微，是天機。", "你休癡，你不知。"]'),
('5b1a44fe-ef38-45a2-ad78-57c404cadd32','漢宮春','呂巖','唐','唐诗','tang','','[]','橫笛聲沉，倚危樓紅日，江轉天斜。',120,'全唐诗/poet.tang.49000.json','["橫笛聲沉，倚危樓紅日，江轉天斜。", "黃塵邊火澒洞，何處吾家。", "胎禽怨夜，來乘風，玄露丹霞。", "先生笑，飛空一劒，東風猶自天涯。", "情知道山中好，早翠囂含隱，瑤草新芽。", "青溪故人信斷，夢[逐]飆車。", "乾坤星火，歸來了，煮石煎沙。", "回首處，幅巾蒲帳，雲邊獨是桃花。"]'),
('50f6e7cb-74f5-4e76-a22a-890b7ac28cfb','減蘭','呂巖','唐','唐诗','tang','','[]','暫遊大庾，白鶴飛來誰共語。',52,'全唐诗/poet.tang.49000.json','["暫遊大庾，白鶴飛來誰共語。", "嶺畔人家，曾見寒梅幾度花。", "春來春去，人在落花流水處。", "花滿前蹊，藏盡神仙人不知。"]'),
('0e973a86-9936-4893-bf0a-433a8fa0c092','憶江南','伊用昌','唐','唐诗','tang','','[]','江南鼓，梭肚兩頭欒。',32,'全唐诗/poet.tang.49000.json','["江南鼓，梭肚兩頭欒。", "釘著不知侵骨髓，打來只是沒心肝，空腹被人謾。"]'),
('54736eff-4076-4768-8069-1d5981f2639f','送日本使','明皇帝','唐','唐诗','tang','','[]','日下非殊俗，天中嘉會朝。',50,'全唐诗/poet.tang.49000.json','["日下非殊俗，天中嘉會朝。", "念余懷義遠，矜爾畏途遙。", "漲海寬秋月，歸帆[駛]夕飆。", "因驚彼君子，王化遠昭昭。"]'),
('1abdb4a3-6d67-4ddd-a722-ea5f80ee90a8','賜新羅王','明皇帝','唐','唐诗','tang','','[]','四維分景緯，萬象含中樞。',120,'全唐诗/poet.tang.49000.json','["四維分景緯，萬象含中樞。", "玉帛遍天下，梯杭歸上都。", "緬懷阻青陸，歲月勤黃圖。", "漫漫窮地際，蒼蒼連海隅。", "興言名義國，豈謂山河殊。", "使去傳風教，人來習典謨。", "衣冠知奉禮，忠信識尊儒。", "誠矣天其鑒，賢哉德不孤。", "擁旄同作牧，厚貺比生蒭。", "益重青青志，風霜恆不渝。"]'),
('6e8d7241-5bba-4134-95a2-f683e230b8c8','句','德宗皇帝','唐','唐诗','tang','','[]','玉殿笙歌宜此夜，更看明月照高樓。',16,'全唐诗/poet.tang.49000.json','["玉殿笙歌宜此夜，更看明月照高樓。"]'),
('2c3bf850-5c5e-414e-b9cf-4d1d003aefd4','采蓮','楊師道','唐','唐诗','tang','','[]','采蓮江浦覓同心，日暮風生江水深。',32,'全唐诗/poet.tang.49000.json','["采蓮江浦覓同心，日暮風生江水深。", "莫言花重船應沒，自解凌波不畏沈。"]'),
('43ae7d31-c83f-45b6-a168-2f6be3066f4e','句','上官儀','唐','唐诗','tang','','[]','曙色隨行漏，早吹入繁笳。',60,'全唐诗/poet.tang.49000.json','["曙色隨行漏，早吹入繁笳。", "旗文縈桂葉，騎影拂桃華。", "碧潭寫春照，青山籠雪花。", "池牑風月清，閒居遊客情。", "蘭泛樽中色，松今弦上聲。"]'),
('2b8b78ea-df36-4678-bd16-e35ec6705cbe','句','張諤','唐','唐诗','tang','','[]','天上姮娥遙解意，偏教月向踏歌明。',32,'全唐诗/poet.tang.49000.json','["天上姮娥遙解意，偏教月向踏歌明。", "共待山頭明月上，照君行棹出長川。"]'),
('0a8e5f5b-69b3-42db-8623-c807e5be700f','句','丁仙芝','唐','唐诗','tang','','[]','雨鳴鴛瓦收炎氣，風卷珠簾送曉涼。',16,'全唐诗/poet.tang.49000.json','["雨鳴鴛瓦收炎氣，風卷珠簾送曉涼。"]'),
('e970b631-7a9d-401a-887c-6403f63c1226','句','殷遙','唐','唐诗','tang','','[]','歸心靜對螢飛月，遠夢長驚角滿樓。',16,'全唐诗/poet.tang.49000.json','["歸心靜對螢飛月，遠夢長驚角滿樓。"]'),
('c23f40ec-9c73-4910-90bf-2ba86de0d95d','句','王維','唐','唐诗','tang','','[]','自恨開遲還落早，縱橫只是怨春風。',16,'全唐诗/poet.tang.49000.json','["自恨開遲還落早，縱橫只是怨春風。"]'),
('2f0d92d2-79a2-43b2-9c07-5502bf7fc531','句','李頎','唐','唐诗','tang','','[]','巴路千山秋水上，江村獨樹夕陽時。',16,'全唐诗/poet.tang.49000.json','["巴路千山秋水上，江村獨樹夕陽時。"]'),
('79281dbc-069e-4143-9538-2082395cafec','旅次盩厔過韓士別業','王昌齡','唐','唐诗','tang','','[]','春煙桑柘林，落日隱荒墅。',36,'全唐诗/poet.tang.49000.json','["春煙桑柘林，落日隱荒墅。", "泱漭平原夕，清吟久延佇。", "故人家於此，招我漁樵所。"]'),
('ead5758b-2fac-46bb-a69d-a6eb160e0f3c','上侍御士兄','王昌齡','唐','唐诗','tang','','[]','天人俟明路，益稷分堯心。',36,'全唐诗/poet.tang.49000.json','["天人俟明路，益稷分堯心。", "利器必先舉，非賢安可任。", "吾兄執嚴憲，時佐能釣深。"]'),
('b11acf95-785c-4cc1-be74-f2c7ec39dba7','上同州使君伯','王昌齡','唐','唐诗','tang','','[]','大賢本孤立，有時起絲綸。',24,'全唐诗/poet.tang.49000.json','["大賢本孤立，有時起絲綸。", "伯父自天稟，元功載生人。"]'),
('6adcac53-3a5b-449e-94d2-e6ee701167a7','留別','王昌齡','唐','唐诗','tang','','[]','桑林映陂水，雨過宛城西。',24,'全唐诗/poet.tang.49000.json','["桑林映陂水，雨過宛城西。", "留醉楚山別，陰雲暮霋霋。"]'),
('912b3271-6087-4685-8c7d-a4aaa7edb5be','贈李侍御','王昌齡','唐','唐诗','tang','','[]','青冥孤雲去，終當暮歸山。',24,'全唐诗/poet.tang.49000.json','["青冥孤雲去，終當暮歸山。", "志士杖苦節，何時見龍顏。"]'),
('3d1fdcbe-228a-47e4-bda9-594778992438','又贈李侍御','王昌齡','唐','唐诗','tang','','[]','渺然客子魂，倏鑠川上暉。',24,'全唐诗/poet.tang.49000.json','["渺然客子魂，倏鑠川上暉。", "還雲慘知暮，九月仍未歸。"]'),
('5808be9d-483e-4767-b645-d8ae678ca8f7','送別','王昌齡','唐','唐诗','tang','','[]','春江愁送君，蕙草生氤氳。',24,'全唐诗/poet.tang.49000.json','["春江愁送君，蕙草生氤氳。", "醉後不能語，鄉山雨雰雰。"]'),
('bfcf86d4-859d-43ef-8dad-702de538edff','失題','王昌齡','唐','唐诗','tang','','[]','時與醉林壑，因之墮農桑。',24,'全唐诗/poet.tang.49000.json','["時與醉林壑，因之墮農桑。", "槐煙漸含夜，樓月深蒼茫。"]'),
('88b0021d-0e69-4c42-bf2c-a60ebe56a22c','失題','王昌齡','唐','唐诗','tang','','[]','桑葉下墟落，鵾雞鳴渚田。',24,'全唐诗/poet.tang.49000.json','["桑葉下墟落，鵾雞鳴渚田。", "物情每衰極，吾道方淵然。"]'),
('0df2eed5-f4ec-4f8f-a22e-4f61f470d180','句','王昌齡','唐','唐诗','tang','','[]','與君遠相知，不道雲海深。',192,'全唐诗/poet.tang.49000.json','["與君遠相知，不道雲海深。", "得罪由己招，本性易然諾。", "黃葉亂秋雨，空齋愁暮心。", "通經彼上人，無迹任勤苦。", "楓橋延海岸，客帆歸富春。", "寒江映村林，亭上納高潔。", "陵藪寒蒼茫，登城遂懷古。", "孤煙曳長林，春水聊一望。", "河口餞南客，進帆清江水。", "遷客又相送，風悲蟬更號。", "微雨隨雲收，濛濛傍山去。", "海客時獨飛，永然滄洲意。", "日夕辨靈藥，空山松桂香。", "墟落有懷縣，長煙溪樹邊。", "青桂花未吐，江中獨鳴琴。", "還家望炎海，楚葉下秋水。"]'),
('ad74f084-1837-4cc8-838c-e6d3be1c393d','句','劉長卿','唐','唐诗','tang','','[]','春苔滿地無行處，深映桃花獨閉門。',16,'全唐诗/poet.tang.49000.json','["春苔滿地無行處，深映桃花獨閉門。"]'),
('1372742b-f030-4946-81ff-3e69f1675dd9','句','崔曙','唐','唐诗','tang','','[]','夜臺一閉無時盡，逝水東流何處還？田家收已盡，蒼蒼只白茅。',28,'全唐诗/poet.tang.49000.json','["夜臺一閉無時盡，逝水東流何處還？田家收已盡，蒼蒼只白茅。"]'),
('66be92b1-a992-42a5-899b-7b02b0b7cf91','句','李白','唐','唐诗','tang','','[]','玉堦一夜留明月，金殿三春滿落花。',16,'全唐诗/poet.tang.49000.json','["玉堦一夜留明月，金殿三春滿落花。"]'),
('8baea0b6-bdfc-460a-88a7-c079ae0f8c7b','題故人別業','張謂','唐','唐诗','tang','','[]','平子歸田處，園林接汝濆。',48,'全唐诗/poet.tang.49000.json','["平子歸田處，園林接汝濆。", "落花開戶入，啼鳥隔窗聞。", "池淨流春水，山明斂霽雲。", "晝遊仍不厭，乘月夜尋君。"]'),
('30129b3a-7cef-44d9-89ef-2f793a42103a','句','李嘉祐','唐','唐诗','tang','','[]','巴峽猿聲催客淚，銅梁山翠入江樓。',32,'全唐诗/poet.tang.49000.json','["巴峽猿聲催客淚，銅梁山翠入江樓。", "千峰鳥路含梅雨，五月蟬聲送麥秋。"]'),
('6dc32df8-ef28-4f13-8ab9-b5d97ce9d1de','失題','錢起','唐','唐诗','tang','','[]','胡風迎馬首，漢月學蛾眉。',24,'全唐诗/poet.tang.49000.json','["胡風迎馬首，漢月學蛾眉。", "久戍人將老，長征馬不肥。"]'),
('8a629ef8-9aaf-429e-9af2-65362af378c4','句','顧況','唐','唐诗','tang','','[]','野人誤向人閒老，爲謝金華洞裏雲。',32,'全唐诗/poet.tang.49000.json','["野人誤向人閒老，爲謝金華洞裏雲。", "莫言歸去無人伴，自有中天月正明。"]'),
('89740c4e-5567-498f-8381-21c0dced6b67','句','陳潤','唐','唐诗','tang','','["\u9ec4\u6cb3"]','兩岸楊花風作雪，一池荷葉雨成珠。',48,'全唐诗/poet.tang.49000.json','["兩岸楊花風作雪，一池荷葉雨成珠。", "暮猿啼處三聲絕，寒雁歸時一葉秋。", "一雙淚滴黃河水，願得東流入漢宮。"]'),
('76cf322d-42b0-4774-b508-3173bd98a1a6','句','崔膺','唐','唐诗','tang','','[]','不隨暮雨蒼江去，且向朝雲白雪歌。',32,'全唐诗/poet.tang.49000.json','["不隨暮雨蒼江去，且向朝雲白雪歌。", "欲于北闕辭蒼海，却望東山愧白雲。"]'),
('48552172-3cad-409b-9777-cc8a33064105','句','馮宿','唐','唐诗','tang','','[]','九衢車馬傳佳句，萬戶鶯花接勝遊。',16,'全唐诗/poet.tang.49000.json','["九衢車馬傳佳句，萬戶鶯花接勝遊。"]'),
('85376101-c4ff-489b-9dde-9b7bd7d093b9','句','于鵠','唐','唐诗','tang','','[]','曾讀列仙王母傳，九天未勝此中遊。',16,'全唐诗/poet.tang.49000.json','["曾讀列仙王母傳，九天未勝此中遊。"]'),
('f459add3-8a52-4d5e-8459-2f97d4810ab5','句','楊巨源','唐','唐诗','tang','','[]','鳴鞭秋色詩情遠，拂匣寒花劒力多。',176,'全唐诗/poet.tang.49000.json','["鳴鞭秋色詩情遠，拂匣寒花劒力多。", "籍通蓮闕秋光遍，詩答蓬山晚思遙。", "青門日暖塵光動，紫陌花晴風色來。", "豔欺藤蔓鶯無限，香壓荆花蝶不飛。", "內史舊山空日暮，南朝古木向人秋。", "夢中鄉信驚秋鴈，窗下林聲帶夜蟬。", "獨向曉山知露溼，遠臨秋水愛雲明。", "新河柳色千株暗，故國雲帆萬里歸。", "一院綠錢童子拂，千竿青玉主人栽。", "露凝丹地初疑雨，煙著紅樓半是霞。", "空門水定埃塵遠，真偈金書世界稀。"]'),
('817910cd-954c-4124-998c-93eb97361f0c','句','劉禹錫','唐','唐诗','tang','','[]','煙波半落新沙地，鳥雀羣飛欲雪天。',80,'全唐诗/poet.tang.49000.json','["煙波半落新沙地，鳥雀羣飛欲雪天。", "櫻桃帶雨胭脂溼，楊柳當風綠線低。", "山似屏風江似簟，叩舷來往月明中。", "晴日碧空雲腳斷，一條如練挂山尖。", "飛文鬬疾敲銅器，陪宴會歡吐錦茵。"]'),
('2297314f-6b78-4a4a-a7ae-3aff6ce9e10d','奉和白舍人遊鏡湖夜歸','周元範','唐','唐诗','tang','','[]','風前酒醒看山笑，湖上詩成共客吟。',32,'全唐诗/poet.tang.49000.json','["風前酒醒看山笑，湖上詩成共客吟。", "畫燭滿堤燒月色，澄江繞樹浸城陰。"]'),
('07cdb34b-3ba7-4759-bc9b-4eb3458ab943','句','周元範','唐','唐诗','tang','','[]','路出胥門深淺浪，月殘吳苑兩三星。',32,'全唐诗/poet.tang.49000.json','["路出胥門深淺浪，月殘吳苑兩三星。", "石橋路上千峯月，山殿雲中半夜鐘。"]'),
('e125e56c-4de2-425e-ad1a-85139399300f','水樓','王魯復','唐','唐诗','tang','','[]','山銜落日溪光動，岸轉回風檻影浮。',32,'全唐诗/poet.tang.49000.json','["山銜落日溪光動，岸轉回風檻影浮。", "座內數聲來遠鶴，煙中一派辨孤舟。"]'),
('feb3e82e-c4fa-47b8-b8c5-2143ee6e8f57','句','王魯復','唐','唐诗','tang','','[]','清泉遶屋澄心遠，曙月銜山出定遲。',16,'全唐诗/poet.tang.49000.json','["清泉遶屋澄心遠，曙月銜山出定遲。"]'),
('8210a13a-4b36-42ed-987a-1319d932283a','句','陸暢','唐','唐诗','tang','','[]','滿手香傳金菊酒，漏聲遙滴上陽宮。',16,'全唐诗/poet.tang.49000.json','["滿手香傳金菊酒，漏聲遙滴上陽宮。"]'),
('ab0f1587-8078-4834-8c33-3657c7148323','句','鮑溶','唐','唐诗','tang','','[]','徑草漸生長短綠，庭花欲綻淺深紅。',80,'全唐诗/poet.tang.49000.json','["徑草漸生長短綠，庭花欲綻淺深紅。", "夜瑟絃驚綠流水，暖松花放碧香煙。", "窗間夜學凝殘燭，軒下朝吟向暖風。", "幽客攜琴好歸去，七絲閑和百泉聲。", "野寺訪僧歸帶月，芳林攜客醉眠花。"]'),
('20e63df4-bbf6-4c4f-80e5-c7d15f97078a','句','張蕭遠','唐','唐诗','tang','','[]','須臾滿寺泉聲合，百尺飛簷挂玉繩。',112,'全唐诗/poet.tang.49000.json','["須臾滿寺泉聲合，百尺飛簷挂玉繩。", "座客醉來雲雨散，一行高鳥萬山秋。", "綺羅香裏春長在，絲管聲中水暗流。", "何事不歸巫峽去，故來人世斷人腸。", "身居曉嶂紅霞外，書讀秋窗紫竹間。", "瀑布水高清漢冷，莓苔橋滑碧煙虛。", "日月在天常照耀，了無塵垢汙清光。"]'),
('be165166-a03c-4103-b3eb-6d916db99235','句','殷堯藩','唐','唐诗','tang','','[]','雲收碧海連天水，風動紅蕉滴露光。',16,'全唐诗/poet.tang.49000.json','["雲收碧海連天水，風動紅蕉滴露光。"]'),
('9f83a186-f453-477d-8652-c648d170655f','句','施肩吾','唐','唐诗','tang','','[]','空巖雨暴泉聲亂，幽徑苔深鳥跡重。',16,'全唐诗/poet.tang.49000.json','["空巖雨暴泉聲亂，幽徑苔深鳥跡重。"]'),
('adf3a6a0-6bee-4d10-b766-3d41664a2fa9','送張孝廉歸吳','章孝標','唐','唐诗','tang','','[]','吳將勤苦見高科，藝至春官不奈何。',32,'全唐诗/poet.tang.49000.json','["吳將勤苦見高科，藝至春官不奈何。", "想得江南諸父老，因君鞭韃子孫多。"]'),
('fa53e505-2e5a-489f-8341-ae3c6558cd0f','夜笛詞','章孝標','唐','唐诗','tang','','[]','皎潔西樓月未斜，笛聲寥亮入東家。',32,'全唐诗/poet.tang.49000.json','["皎潔西樓月未斜，笛聲寥亮入東家。", "頓令燈下裁衣婦，誤翦同心一片依。"]'),
('01e01cde-5d71-46c9-ae30-67331f2422f0','題碧山寺塔','章孝標','唐','唐诗','tang','','[]','六時佛火明珠綴，午後茶煙出翠微。',32,'全唐诗/poet.tang.49000.json','["六時佛火明珠綴，午後茶煙出翠微。", "縈砌乳泉梳石髮，滴松銀露洗牆衣。"]'),
('dffe7755-e690-4a82-9919-b15b4879de47','翫月遇雲','章孝標','唐','唐诗','tang','','[]','無端玉葉連天起，不放金波到曉流。',32,'全唐诗/poet.tang.49000.json','["無端玉葉連天起，不放金波到曉流。", "暗惜蚌胎沈海面，仰思鵬翼破風頭。"]'),
('bb8dfaf4-16fb-44f9-b6b4-3681901dda91','句','章孝標','唐','唐诗','tang','','[]','錢塘去國三千里，一道風光任意看。',256,'全唐诗/poet.tang.49000.json','["錢塘去國三千里，一道風光任意看。", "珠呈夜浦螢無影，鶻坐秋林鳥失行。", "昨日見君親下筆，五花牋上黑龍飛。", "何人枉折教狼籍，孤負春風長養情。", "梅花帶雪飛琴上，柳色和煙入酒中。", "阮籍嘯場人步月，子猷看處鳥棲煙。", "白練鳥迷山芍藥，紅妝妓妒水林檎。", "今日華山秋頂上，聞天長叫在長空。", "天風更送新聲出，不放行雲過鳳樓。", "昨日天宮吹樂府，六官絃管一時新。", "通傳勝事因風月，打破愁腸是酒杯。", "姑蘇臺上煙花月，寧負春風簫管聲。", "玉輪低月中天曉，金鐸縱風上界秋。", "蕭灑竹房塵境外，滿天雲月共清虛。", "言若浚川流巨海，戒如秋月挂長空。", "金殿月中看擣藥，玉樓風裏聽吹笙。"]'),
('9c2a13bd-9f4f-44bb-9748-8dc25fb18140','句','陳標','唐','唐诗','tang','','[]','長把酒杯憑夜月，每將詩思泥春風。',64,'全唐诗/poet.tang.49000.json','["長把酒杯憑夜月，每將詩思泥春風。", "襄陽樂事經過盡，峴首煙花倒瀉空。", "猶疑波底鮫人淚，滴在衣裳半欲零。", "春明門外襄陽路，落日秋風送客歸。"]'),
('ef76c64b-fad1-44a7-8e87-8b4326d95bcd','入洞庭望岳陽','楊收','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','飛鷗撒浪三千里，暮草搖風一萬畦。',32,'全唐诗/poet.tang.49000.json','["飛鷗撒浪三千里，暮草搖風一萬畦。", "黛色淺深山遠近，碧煙濃淡樹高低。"]'),
('f6c85f0c-3d84-4e5f-bd8d-151ab3ab4d29','句','許渾','唐','唐诗','tang','','[]','蒹葭水暗螢知夜，楊柳風高鴈送秋。',32,'全唐诗/poet.tang.49000.json','["蒹葭水暗螢知夜，楊柳風高鴈送秋。", "露滴曉花疑錦繡，風吹寒竹認笙簧。"]'),
('eee7e201-d9b5-4287-9079-c3fb93083e25','句','喻鳧','唐','唐诗','tang','','[]','虹橫布水臺南雨，鴈返爐峰頂北霞。',48,'全唐诗/poet.tang.49000.json','["虹橫布水臺南雨，鴈返爐峰頂北霞。", "閑臥東風燈漸曉，溪南花氣雨中來。", "一別山陰詩酒客，水風花片夢蘭亭。"]'),
('3bcb052c-634d-4358-814c-f9cbdae5d625','句','祝元膺','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','卻覓終南山色看，倚天橫展玉屏風。',48,'全唐诗/poet.tang.49000.json','["卻覓終南山色看，倚天橫展玉屏風。", "杜甫一生憐李白，應緣孔聖道才難。", "終南山腳盤龍勢，紫閣雲心望鶴歸。"]'),
('2e09efea-eef0-424a-8c3b-bc4526edc355','句','趙嘏','唐','唐诗','tang','','[]','池上昔遊夫子鳳，雲間初起武侯龍。',112,'全唐诗/poet.tang.49000.json','["池上昔遊夫子鳳，雲間初起武侯龍。", "亭分楚寺依依樹，水應公臺夜夜琴。", "鴝鵒舞酣人自醉，琵琶聲緩客初來。", "高鳥過時秋色動，征帆落處暮煙生。", "夜吟孤枕潮聲近，晚過千山雪氣寒。", "望臘早花緣路見，隨巖寒水隔林聞。", "宿處客塵隨夜靜，坐中煙水向人閑。"]'),
('e8a81203-6597-4aa3-b5b6-bd2218888417','句','崔澹','唐','唐诗','tang','','[]','九重城裏春來早，百尺樓頭日落遲。',16,'全唐诗/poet.tang.49000.json','["九重城裏春來早，百尺樓頭日落遲。"]'),
('ff7b71cd-cb8d-4240-9a4f-3500a1864be6','句','賈島','唐','唐诗','tang','','[]','莫是上天宮裏唱，歌聲飄下玉梁塵。',16,'全唐诗/poet.tang.49000.json','["莫是上天宮裏唱，歌聲飄下玉梁塵。"]'),
('1fc21f8f-8132-47a8-be2f-db3b9bf32089','句','溫庭筠','唐','唐诗','tang','','[]','沿澗水聲喧戶外，卷簾山色入窗來。',64,'全唐诗/poet.tang.49000.json','["沿澗水聲喧戶外，卷簾山色入窗來。", "自有晚風推楚浪，不勞春色染湘煙。", "卓氏壚前金綫柳，隋家隄畔錦帆風。", "門外白雲何處雨，一條清澗遶溪流。"]'),
('ca5beaf9-2be9-4d66-8553-cc64395e1122','句','方干','唐','唐诗','tang','','[]','巖溜噴空晴似雨，林蘿礙日夏多寒。',16,'全唐诗/poet.tang.49000.json','["巖溜噴空晴似雨，林蘿礙日夏多寒。"]'),
('3c0fd958-281c-489c-9c9a-58fafb07acc7','句','羅隱','唐','唐诗','tang','','[]','庾樓宴罷三更月，宏閣談時一座風。',16,'全唐诗/poet.tang.49000.json','["庾樓宴罷三更月，宏閣談時一座風。"]'),
('28c1bdf1-9bcb-4a48-966b-36801722bacb','過友人故居','羅虬','唐','唐诗','tang','','[]','隄草裊空垂露眼，渚浦穿浪湊煙芽。',32,'全唐诗/poet.tang.49000.json','["隄草裊空垂露眼，渚浦穿浪湊煙芽。", "晴樓談罷山橫黛，夜局碁酣燭墜花。"]'),
('949526b9-964c-474c-ae5e-8ad2f48e1956','句','羅虬','唐','唐诗','tang','','[]','雪中放馬朝尋跡，雲外聞鴻夜射聲。',64,'全唐诗/poet.tang.49000.json','["雪中放馬朝尋跡，雲外聞鴻夜射聲。", "龍鱗柳弱垂朝露，麈尾松高揮夜風。", "猿隔亂雲啼暮嶺，鴈和微雨下寒湖。", "夜渡酒酣千頃月，晝樓碁罷一窗山。"]'),
('197f558f-a056-4baa-b7b3-5e3e8a430609','句','杜荀鶴','唐','唐诗','tang','','[]','千嶂雪消溪影綠，幾家梅綻酒波清。',32,'全唐诗/poet.tang.49000.json','["千嶂雪消溪影綠，幾家梅綻酒波清。", "風拂亂燈山磬曙，露沾仙杏石壇春。"]'),
('163aeb63-9e47-4b97-90e9-c702d43ff884','句','神穎','唐','唐诗','tang','','[]','手邊雲起何時雨，筆下波生不待風。',16,'全唐诗/poet.tang.49000.json','["手邊雲起何時雨，筆下波生不待風。"]'),
('833981e9-ced0-4dc6-a926-dd5e842b9809','句','惠文太子','唐','唐诗','tang','','[]','渭水橋邊春已渡，灞陵原上雨初晴。',80,'全唐诗/poet.tang.49000.json','["渭水橋邊春已渡，灞陵原上雨初晴。", "清冷池裏冰初合，紅粉樓中月未圓。", "可惜韶年三日暮，風光由繞碧燕觴。", "晚日半銜西苑樹，晴雲直卷上天風。", "離筵風日三晡晚，歸路雲霞一道開。"]'),
('1ac51264-5721-44f5-8d8c-b97db570f0ef','蓬州野望','元兢','唐','唐诗','tang','','[]','飄颻宕渠域，曠望蜀門隈。',48,'全唐诗/poet.tang.49000.json','["飄颻宕渠域，曠望蜀門隈。", "水共三巴遠，山隨八陣開。", "橋形疑漢接，石勢似煙迴。", "欲下他鄉淚，猿聲幾處催。"]'),
('db278499-b987-4182-8c15-7854be54d079','贈日本僧空海離合詩','馬總','唐','唐诗','tang','','[]','仍可萬里來，可非衒其才。',24,'全唐诗/poet.tang.49000.json','["仍可萬里來，可非衒其才。", "增學助元機，土人如子稀。"]'),
('1db23ff3-fb03-4e31-ad17-6c5998f261d4','贈釋空海歌','胡伯崇','唐','唐诗','tang','','[]','說四句，演毘尼，凡夫聽者盡歸依。',32,'全唐诗/poet.tang.49000.json','["說四句，演毘尼，凡夫聽者盡歸依。", "天假吾師多伎術，就中草聖最狂逸。"]'),
('ca325dea-15a9-4c3b-a7a2-efcda1fac3ce','因使日本願謁鑒真和尚既滅度不覲尊顏嗟而述懷','高鶴林','唐','唐诗','tang','','[]','上方傳佛燈，名僧號鑒真。',60,'全唐诗/poet.tang.49000.json','["上方傳佛燈，名僧號鑒真。", "懷藏通鄰國，真如轉付民。", "早嫌居五濁，寂滅離囂塵。", "禪院從今古，青松遶塔新。", "斯法留千載，名記萬年春。"]'),
('6762f8c9-aeeb-4621-b159-fe3be2f063c1','句','朱千乘','唐','唐诗','tang','','[]','錦纜扁舟花岸靜，玉壺春酒管絃清。',16,'全唐诗/poet.tang.49000.json','["錦纜扁舟花岸靜，玉壺春酒管絃清。"]'),
('954fd1b9-b55c-40d6-bb78-8976410f74a8','句','清觀','唐','唐诗','tang','','[]','叡山新月冷，台嶠古風清。',12,'全唐诗/poet.tang.49000.json','["叡山新月冷，台嶠古風清。"]'),
('fd602deb-e5f1-4140-9b28-40c06eddf3d1','罷官後卻歸舊居','陳閏','唐','唐诗','tang','','[]','不歸江畔久，舊業已凋殘。',48,'全唐诗/poet.tang.49000.json','["不歸江畔久，舊業已凋殘。", "露草蟲絲溼，湖泥鳥跡乾。", "買山開客舍，選竹作漁竿。", "何必勞州縣，驅馳効一官。"]'),
('39b78820-e9ce-4962-8720-af1c5ee56e1b','句','李堪','唐','唐诗','tang','','[]','此心復何已，新月清江長。',24,'全唐诗/poet.tang.49000.json','["此心復何已，新月清江長。", "雲歸石壁盡，月照霜林清。"]'),
('fae586d8-3b75-4075-9806-214666fab3d4','兗州留獻李員外','崔致遠','唐','唐诗','tang','','[]','芙蓉零落秋池雨，楊柳蕭疎曉岸風。',32,'全唐诗/poet.tang.49000.json','["芙蓉零落秋池雨，楊柳蕭疎曉岸風。", "神思只勞書卷上，年光任過酒杯中。"]'),
('7184e7d3-95b3-4140-84da-fc34e3b9446d','句','崔致遠','唐','唐诗','tang','','[]','畫角聲中朝暮浪，青山影裏古今人。',112,'全唐诗/poet.tang.49000.json','["畫角聲中朝暮浪，青山影裏古今人。", "煙低紫陌千行柳，日暮朱樓一曲歌。", "洛水波聲新草樹，嵩山雲影舊樓臺。", "雲布長天龍勢逸，風高秋月雁行齊。", "風遞鶯聲喧座上，日移花影倒林中。", "芳園醉散花盈袖，幽逕吟歸月在帷。", "極目遠山煙外暮，傷心歸棹月邊遲。"]'),
('25884f7d-64b7-4c32-9688-9811d89ed41e','句','金立之','唐','唐诗','tang','','[]','煙破樹頭驚宿鳥，露凝苔上暗流螢。',112,'全唐诗/poet.tang.49000.json','["煙破樹頭驚宿鳥，露凝苔上暗流螢。", "山人見月寧思寢，更掬寒泉滿手霜。", "紺殿雨晴松色冷，禪林風起竹聲餘。", "風過古殿香煙散，月到前林竹露清。", "更有閑宵清淨境，曲江澄月對心虛。", "寒露已催鴻北去，火雲漸散月西流。", "園梅坼甲迎春笑，庭草抽心待節芳。"]'),
('0d1bc452-707b-49ad-8709-938c1dbe9ef6','句','金可紀','唐','唐诗','tang','','[]','波衝亂石長如雨，風激疎松鎮似秋。',16,'全唐诗/poet.tang.49000.json','["波衝亂石長如雨，風激疎松鎮似秋。"]'),
('86d0d593-db39-4135-afcf-8caaf9f49f29','尋幽居不遇','莊翱','唐','唐诗','tang','','[]','滿庭花落迷行路，遶院泉聲寫半山。',32,'全唐诗/poet.tang.49000.json','["滿庭花落迷行路，遶院泉聲寫半山。", "向暮此中回首去，洞門深處鳥關關。"]'),
('649c0ac9-a18f-4eee-9ae1-a38820d2033e','句','莊翱','唐','唐诗','tang','','[]','天外夜深風漸遠，高松長似水流聲。',64,'全唐诗/poet.tang.49000.json','["天外夜深風漸遠，高松長似水流聲。", "焚香暮入飜花殿，凈手秋開貝葉經。", "野性本憐松下月，幽情唯愛洞中春。", "慇懃笑喻人間事，遙指庭花對夕陽。"]'),
('829126ea-3a84-40d4-80e5-24e2278a1f52','春日','陸翬','唐','唐诗','tang','','[]','鶯歸樹頂繁聲轉，雁去天邊細影斜。',32,'全唐诗/poet.tang.49000.json','["鶯歸樹頂繁聲轉，雁去天邊細影斜。", "雨拂青青行處草，煙含灼灼望中花。"]'),
('8ce5f755-0b1b-409c-b019-e0830399c24b','句','陸翬','唐','唐诗','tang','','[]','三尺寒光冰在手，一張弓勢月當心。',48,'全唐诗/poet.tang.49000.json','["三尺寒光冰在手，一張弓勢月當心。", "巖下光陰生戶牗，澗邊形勢入池臺。", "孤帆影入江煙盡，百舌聲流浦樹新。"]'),
('9586f26a-c78e-48fe-a06e-780d5dbebbdb','夜泊越州逢北使','沈佺期','唐','唐诗','tang','','[]','天地降雷雨，放逐還國都。',123,'全唐诗/poet.tang.5000.json','["天地降雷雨，放逐還國都。", "重以風潮事，年月戒回艫。", "容顏荒外老，心想域中愚。", "憩泊在茲夜，炎雲逐斗樞。", "䬓{風兪}縈海若，霹靂耿天吳。", "鼇抃羣島失，鯨吞衆流輸。", "偶逢金華使，握手淚相濡。", "飢共噬齊棗，眠共席秦蒲。", "既北思攸濟，將南睿所圖。", "往來固無咎，何忽憚前桴。"]'),
('604e1a1a-9ecf-47d1-97fa-efb08357d492','紹隆寺','沈佺期','唐','唐诗','tang','','[]','吾從釋迦久，無上師涅槃。',120,'全唐诗/poet.tang.5000.json','["吾從釋迦久，無上師涅槃。", "探道三十載，得道天南端。", "非勝適殊方，起諠歸理難。", "放棄乃良緣，世慮不曾干。", "香界縈北渚，花龕隱南巒。", "危昂階下石，演漾窗中瀾。", "雲蓋看木秀，天空見藤盤。", "處俗勒宴坐，居貧業行壇。", "試將有漏軀，聊作無生觀。", "了然究諸品，彌覺靜者安。"]'),
('b525f817-8750-43db-bdfc-7366b7ef5936','神龍初廢逐南荒途出郴口北望蘇耽山','沈佺期','唐','唐诗','tang','','[]','少曾讀仙史，知有蘇耽君。',120,'全唐诗/poet.tang.5000.json','["少曾讀仙史，知有蘇耽君。", "流望來南國，依然會昔聞。", "泊舟問耆老，遙指孤山雲。", "孤山郴郡北，不與衆山羣。", "重崖下縈映，嶛嶢上乣紛。", "碧峰泉附落，紅壁樹傍分。", "選地今方爾，昇天因可云。", "不才予竄迹，羽化子遺芬。", "將覽成麟鳳，旋驚禦鬼文。", "此中迷出處，含思獨氛氳。"]'),
('d12566ee-cd4c-4927-af6e-28e20a6df6c1','初達驩州','沈佺期','唐','唐诗','tang','','[]','流子一十八，命予偏不偶。',84,'全唐诗/poet.tang.5000.json','["流子一十八，命予偏不偶。", "配遠天遂窮，到遲日最後。", "水行儋耳國，陸行雕題藪。", "魂魄遊鬼門，骸骨遺鯨口。", "夜則忍飢臥，朝則抱病走。", "搔首向南荒，拭淚看北斗。", "何年赦書來？重飲洛陽酒。"]'),
('f5e61ffe-83a4-4e5f-be6f-9f42c6ecadfa','被彈','沈佺期','唐','唐诗','tang','','[]','知人昔不易，舉非貴易失。',216,'全唐诗/poet.tang.5000.json','["知人昔不易，舉非貴易失。", "爾何按國章，無罪見呵叱。", "平生守直道，遂爲衆所嫉。", "少以文作吏，手不曾開律。", "一旦法相持，荒忙意如漆。", "幼子雙囹圄，老夫一念室。", "昆弟兩三人，相次俱囚桎。", "萬鑠當衆怒，千謗無片實。", "庶以白黑讒，顯此涇渭質。", "劾吏何咆哮，晨夜聞撲抶。", "事間拾虛證，理外存枉筆。", "懷痛不見伸，抱冤竟難悉。", "窮囚多垢膩，愁坐饒蟣虱。", "三日唯一飯，兩旬不再櫛。", "是時盛夏中，暵赫多瘵疾。", "瞪目眠欲閉，暗嗚氣不出。", "有風自扶搖，鼓蕩無倫匹。", "安得吹浮雲，令我見白日。"]'),
('dfda4102-2446-4daa-a7bb-1539ec77c5d3','枉繫二首 一','沈佺期','唐','唐诗','tang','','[]','吾憐曾家子，昔有投杼疑。',48,'全唐诗/poet.tang.5000.json','["吾憐曾家子，昔有投杼疑。", "吾憐姬公旦，非無鴟鴞詩。", "臣子竭忠孝，君親惑讒欺。", "萋斐離骨肉，含愁興此辭。"]'),
('312131ec-449f-405a-ac52-8a6b33845b17','枉繫二首 二','沈佺期','唐','唐诗','tang','','[]','昔日公冶長，非罪遇縲絏。',48,'全唐诗/poet.tang.5000.json','["昔日公冶長，非罪遇縲絏。", "聖人降其子，古來歎獨絕。", "我無毫髪瑕，苦心懷冰雪。", "今代多秀士，誰能繼明轍。"]'),
('6ebb6d7a-d5ce-4e4d-9d95-cdc2cffe687e','黃鶴','沈佺期','唐','唐诗','tang','','[]','黃鶴佐丹鳳，不能羣白鷴。',48,'全唐诗/poet.tang.5000.json','["黃鶴佐丹鳳，不能羣白鷴。", "拂雲遊四海，弄影到三山。", "遙憶君軒上，來下天池間。", "明珠世不重，知有報恩環。"]'),
('b58dc484-b3dc-4d76-b38d-dcc46793c594','傷王學土','沈佺期','唐','唐诗','tang','','[]','閉囚斷外事，昧坐半餘朞。',180,'全唐诗/poet.tang.5000.json','["閉囚斷外事，昧坐半餘朞。", "有言頴叔子，亡來已一時。", "初聞宛不信，中話涕漣洏。", "痛哉玄夜重，何遽青春姿。", "憶汝曾旅食，屢空瀍澗湄。", "吾徒祿未厚，筲斗愧相貽。", "原憲貧無愁，顏回樂自持。", "詔書擇才善，君爲王子師。", "寵儒名可尚，論秩官猶欺。", "化往不復見，情來安可思。", "目絕毫翰灑，耳無歌諷期。", "靈柩寄何處，精魂今何之？", "恨予在丹棘，不得看素旗。", "孀妻知己歎，幼子路人悲。", "感遊值商日，絕弦留此詞。"]'),
('c2d38f74-b343-4833-ac18-4d72ae70f225','古鏡','沈佺期','唐','唐诗','tang','','[]','莓苔翳清池，蝦蟆蝕明月。',36,'全唐诗/poet.tang.5000.json','["莓苔翳清池，蝦蟆蝕明月。", "埋落今如此，照心未嘗歇。", "願垂拂拭恩，爲君鑒玄髪。"]'),
('35dcfd2c-5afd-48d1-a906-541d5cac7017','鳳簫曲','沈佺期','唐','唐诗','tang','','[]','八月涼風動高閣，千金麗人捲綃幕。',120,'全唐诗/poet.tang.5000.json','["八月涼風動高閣，千金麗人捲綃幕。", "已憐池上歇芳菲，不念君恩坐搖落。", "世上榮華如轉蓬，朝隨阡陌暮雲中。", "飛燕侍寢昭陽殿，班姬飲恨長信宮。", "長信宮，昭陽殿，春來歌舞妾自知，秋至簾櫳君不見。", "昔時嬴女厭世紛，學吹鳳簫乘彩雲。", "含情轉睞向蕭史，千載紅顏持贈君。"]'),
('01b06a31-10d7-448a-9207-04096ca4610a','古歌','沈佺期','唐','唐诗','tang','','[]','落葉流風向玉臺，夜寒秋思洞房開。',96,'全唐诗/poet.tang.5000.json','["落葉流風向玉臺，夜寒秋思洞房開。", "水晶簾外金波下，雲母窗前銀漢回。", "玉階陰陰苔蘚色，君王屢綦難再得。", "璇閨窈窕秋夜長，繡戶徘徊明月光。", "燕姬綵帳芙蓉色，秦女金爐蘭麝香。", "北斗七星橫夜半，清歌一曲斷君腸。"]'),
('03602668-16a3-449f-9898-3e082aa82e4a','七夕曝衣篇','沈佺期','唐','唐诗','tang','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282", "\u548f\u53f2"]','君不見昔日宜春太液邊，披香畫閣與天連。',219,'全唐诗/poet.tang.5000.json','["君不見昔日宜春太液邊，披香畫閣與天連。", "燈火灼爍九微暎，香氣氛氳百和然。", "此夜星繁河正白，人傳織女牽牛客。", "宮中擾擾曝衣樓，天上娥娥紅粉席。", "曝衣何許曛半黃，宮中綵女提玉箱。", "珠履奔騰上蘭砌，金梯宛轉出梅梁。", "絳河裏，碧煙上，雙花伏兔畫屏風，四子盤龍擎斗帳。", "舒羅散縠雲霧開，綴玉垂珠星漢回。", "朝霞散彩羞衣架，晚月分光劣鏡臺。", "上有仙人長命綹，中看玉女迎歡繡。", "玳瑁簾中別作春，珊瑚窗裏翻成晝。", "椒房金屋寵新流，意氣嬌奢不自由。", "漢文宜惜露臺費，晉武須焚前殿裘。"]'),
('84d64ee8-b6de-4160-9047-5bc297dc4b9e','入少密溪','沈佺期','唐','唐诗','tang','','[]','雲峯苔壁繞溪斜，江路香風夾岸花。',96,'全唐诗/poet.tang.5000.json','["雲峯苔壁繞溪斜，江路香風夾岸花。", "樹密不言通鳥道，雞鳴始覺有人家。", "人家更在深巖口，澗水周流宅前後。", "遊魚瞥瞥雙釣童，伐木丁丁一樵叟。", "自言避喧非避秦，薜衣耕鑿帝堯人。", "相留且待雞黍熟，夕臥深山蘿月春。"]'),
('70241001-7757-4bf2-aa33-9eb69f6f5dc2','霹靂引','沈佺期','唐','唐诗','tang','','[]','歲七月，火伏而金生。',146,'全唐诗/poet.tang.5000.json','["歲七月，火伏而金生。", "客有鼓琴於門者，奏霹靂之商聲。", "始戛羽以騞砉，終扣宮而砰駖。", "電耀耀兮龍躍，雷闐闐兮雨冥。", "氣嗚唅以會雅，態歘翕以橫生。", "有如驅千旗，制五兵。", "截荒虺，斮長鯨。", "孰與廣陵比，意別鶴儔精而已。", "俾我雄子魄動，毅夫髪立。", "懷恩不淺，武義雙輯。", "視胡若芥，剪羯如拾。", "豈徒慷慨中筵，備羣娛之翕習哉。"]'),
('0c1b9462-bc83-4f35-950d-ada6442017e9','立春日內出綵花應制','沈佺期','唐','唐诗','tang','','[]','合殿春應早，開箱綵預知。',48,'全唐诗/poet.tang.5000.json','["合殿春應早，開箱綵預知。", "花迎宸翰發，葉待御筵披。", "梅訝香全少，桃驚色頓移。", "輕生承剪拂，長伴萬年枝。"]'),
('babd3684-1745-4346-95d0-fc383fd0e443','晦日滻水應制','沈佺期','唐','唐诗','tang','','[]','素滻接宸居，青門盛祓除。',48,'全唐诗/poet.tang.5000.json','["素滻接宸居，青門盛祓除。", "摘蘭喧鳳野，浮藻溢龍渠。", "苑蝶飛殊懶，宮鶯囀不疎。", "星移天上入，歌舞向儲胥。"]'),
('b12a161c-6a4f-4313-8f9f-a9d7f5dee0c1','奉和洛陽翫雪應制','沈佺期','唐','唐诗','tang','','[]','周王甲子旦，漢后德陽宮。',48,'全唐诗/poet.tang.5000.json','["周王甲子旦，漢后德陽宮。", "灑瑞天庭裏，驚春御苑中。", "氛氳生浩氣，颯杳舞回風。", "宸藻光盈尺，賡歌樂歲豐。"]'),
('9b5c9844-6e46-4d8d-8714-bd7c23382376','三日梨園侍宴','沈佺期','唐','唐诗','tang','','[]','九重馳道出，三巳禊堂開。',48,'全唐诗/poet.tang.5000.json','["九重馳道出，三巳禊堂開。", "畫鷁中流動，青龍上苑來。", "野花飄御座，河柳拂天杯。", "日晚迎祥處，笙鏞下帝臺。"]'),
('70585fc1-31c6-4d25-92a0-f8c52cc26957','幸梨園亭觀打毬應制','沈佺期','唐','唐诗','tang','','[]','今春芳苑遊，接武上瓊樓。',48,'全唐诗/poet.tang.5000.json','["今春芳苑遊，接武上瓊樓。", "宛轉縈香騎，飄颻拂畫毬。", "俯身迎未落，迴轡逐傍流。", "秖爲看花鳥，時時誤失籌。"]'),
('83486b6d-e84b-481b-aa2b-577bd03b32af','九日臨渭亭侍宴應制得長字','沈佺期','唐','唐诗','tang','','[]','御氣幸金方，憑高薦羽觴。',48,'全唐诗/poet.tang.5000.json','["御氣幸金方，憑高薦羽觴。", "魏文頒菊蕋，漢武賜萸房。", "秋變銅池色，晴添銀樹光。", "年年重九慶，日月奉天長。"]'),
('64274b57-6ee8-424e-8989-a67214e491cc','歲夜安樂公主滿月侍宴','沈佺期','唐','唐诗','tang','','[]','除夜子星回，天孫滿月杯。',48,'全唐诗/poet.tang.5000.json','["除夜子星回，天孫滿月杯。", "詠歌麟趾合，簫管鳳雛來。", "歲炬常然桂，春盤預折梅。", "聖皇千萬壽，垂曉御樓開。"]'),
('91af8429-3dbe-4152-8493-679e074bb548','安樂公主移入新宅','沈佺期','唐','唐诗','tang','','[]','初聞衡漢來，移住斗城隈。',36,'全唐诗/poet.tang.5000.json','["初聞衡漢來，移住斗城隈。", "錦帳迎風轉，瓊筵拂霧開。", "馬香遺舊埒，鳳吹繞新臺。"]'),
('9cd66d8d-eeb4-4945-9e35-8488993e994f','仙萼亭初成侍宴應制','沈佺期','唐','唐诗','tang','','[]','山中氣色和，宸賞第中過。',48,'全唐诗/poet.tang.5000.json','["山中氣色和，宸賞第中過。", "輦路披仙掌，帷宮拂帝蘿。", "泉臨香澗落，峰入翠雲多。", "無異登玄圃，東南望白河。"]'),
('a1303b08-746e-48e9-93a2-66797e60da94','送金城公主適西蕃應制','沈佺期','唐','唐诗','tang','','[]','金牓扶丹掖，銀河屬紫閽。',48,'全唐诗/poet.tang.5000.json','["金牓扶丹掖，銀河屬紫閽。", "那堪將鳳女，還以嫁烏孫。", "玉就歌中怨，珠辭掌上恩。", "西戎非我匹，明主至公存。"]'),
('47aaf877-96fe-4ebf-80f4-56d48ce6217e','幸白鹿觀應制','沈佺期','唐','唐诗','tang','','[]','紫鳳真人府，斑龍太上家。',48,'全唐诗/poet.tang.5000.json','["紫鳳真人府，斑龍太上家。", "天流芝蓋下，山轉桂旗斜。", "聖藻垂寒露，仙杯落晚霞。", "唯應問王母，桃作幾時花。"]'),
('e2266376-60c8-4d9b-ac64-4d37bbabd721','洛陽道','沈佺期','唐','唐诗','tang','','[]','九門開洛邑，雙闕對河橋。',48,'全唐诗/poet.tang.5000.json','["九門開洛邑，雙闕對河橋。", "白日青春道，軒裳半下朝。", "乘羊稚子看，拾翠美人嬌。", "行樂歸恆晚，香塵撲地遙。"]'),
('a10509b0-ebb7-44c2-8a8f-068ff75d9b89','驄馬','沈佺期','唐','唐诗','tang','','[]','西北五花驄，來時道向東。',48,'全唐诗/poet.tang.5000.json','["西北五花驄，來時道向東。", "四蹄碧玉片，雙眼黃金瞳。", "鞍上留明月，嘶間動朔風。", "借君馳沛艾，一戰取雲中。"]'),
('5aa31f21-9af5-40bc-9480-3672fc88dd5b','銅雀臺','沈佺期','唐','唐诗','tang','','[]','昔年分鼎地，今日望陵臺。',48,'全唐诗/poet.tang.5000.json','["昔年分鼎地，今日望陵臺。", "一旦雄圖盡，千秋遺令開。", "綺羅君不見，歌舞妾空來。", "恩共漳河水，東流無重回。"]'),
('9780108b-bb66-41f2-be89-7535fc3b694e','長門怨','沈佺期','唐','唐诗','tang','','[]','月皎風泠泠，長門次掖庭。',48,'全唐诗/poet.tang.5000.json','["月皎風泠泠，長門次掖庭。", "玉階聞墜葉，羅幌見飛螢。", "清露凝珠綴，流塵下翠屏。", "妾心君未察，愁歎劇繁星。"]'),
('f5a94e24-96f3-4645-a628-3ea2359b872d','巫山高二首 一','沈佺期','唐','唐诗','tang','','[]','巫山峯十二，合沓隱昭回。',48,'全唐诗/poet.tang.5000.json','["巫山峯十二，合沓隱昭回。", "俯眺琵琶峽，平看雲雨臺。", "古槎天外倚，瀑水日邊來。", "何忍猿啼夜，荆王枕席開。"]'),
('84070be0-fa7c-4b1b-a7bb-65e8d74844dd','巫山高二首 二','沈佺期','唐','唐诗','tang','','[]','神女向高唐，巫山下夕陽。',48,'全唐诗/poet.tang.5000.json','["神女向高唐，巫山下夕陽。", "裴回作行雨，婉孌逐荆王。", "電影江前落，雷聲峽外長。", "霽雲無處所，臺館曉蒼蒼。"]'),
('9d06a3cc-bddb-49e9-a80d-5b3adc3de3e1','巫山高','沈佺期','唐','唐诗','tang','','[]','巫山高不極，合沓狀奇新。',48,'全唐诗/poet.tang.5000.json','["巫山高不極，合沓狀奇新。", "暗谷疑風雨，陰崖若鬼神。", "月明三峽曙，潮滿九江春。", "爲問陽臺客，應知入夢人。"]'),
('04d92f40-d412-4eb5-ab64-d58aa0a779c6','七夕','沈佺期','唐','唐诗','tang','','[]','秋近雁行稀，天高鵲夜飛。',48,'全唐诗/poet.tang.5000.json','["秋近雁行稀，天高鵲夜飛。", "妝成應懶織，今夕渡河歸。", "月皎宜穿線，風輕得曝衣。", "來時不可覺，神驗有光輝。"]'),
('fd19c09d-4d11-4209-870a-0fc03e73e647','春閨','沈佺期','唐','唐诗','tang','','[]','鐵馬三軍去，金閨二月還。',48,'全唐诗/poet.tang.5000.json','["鐵馬三軍去，金閨二月還。", "邊愁離上國，春夢失陽關。", "池水琉璃淨，園花玳瑁斑。", "歲華空自擲，憂思不勝顏。"]'),
('dcc690c1-ca11-4142-8d78-dc2505a4ebc7','奉和聖製同皇太子遊慈恩寺應制','沈佺期','唐','唐诗','tang','','[]','肅肅蓮花界，熒熒貝葉宮。',48,'全唐诗/poet.tang.5000.json','["肅肅蓮花界，熒熒貝葉宮。", "金人來夢裏，白馬出城中。", "湧塔初從地，焚香欲遍空。", "天歌應春籥，非是爲春風。"]'),
('49be49dc-b305-4bba-9319-72aa0a8186b1','和洛州康士曹庭芝望月有懷','沈佺期','唐','唐诗','tang','','[]','天使下西樓，光含萬象秋。',48,'全唐诗/poet.tang.5000.json','["天使下西樓，光含萬象秋。", "臺前疑挂鏡，簾外似懸鉤。", "張尹將眉學，班姬取扇儔。", "佳期應借問，爲報在刀頭。"]'),
('5fb8bbab-4b48-4f00-a090-54ff850713fb','壽陽王花燭','沈佺期','唐','唐诗','tang','','[]','仙媛乘龍夕，天孫捧雁來。',48,'全唐诗/poet.tang.5000.json','["仙媛乘龍夕，天孫捧雁來。", "可憐桃李樹，更遶鳳皇臺。", "燭送香車入，花臨寶扇開。", "莫令銀箭曉，爲盡合歡杯。"]'),
('916f9fab-d4c9-4619-8b63-aab55d467d35','隴頭水','沈佺期','唐','唐诗','tang','','[]','隴山飛落葉，隴雁度寒天。',48,'全唐诗/poet.tang.5000.json','["隴山飛落葉，隴雁度寒天。", "愁見三秋水，分爲兩地泉。", "西流入羗郡，東下向秦川。", "征客重回首，肝腸空自憐。"]'),
('27bb726e-3b6f-41b3-941a-66db00f46d51','關山月','沈佺期','唐','唐诗','tang','','[]','漢月生遼海，朣朧出半暉。',48,'全唐诗/poet.tang.5000.json','["漢月生遼海，朣朧出半暉。", "合昏玄菟郡，中夜白登圍。", "暈落關山迥，光含霜霰微。", "將軍聽曉角，戰馬欲南歸。"]'),
('23617543-e0f3-44bf-9360-2772ec9ca8d9','折楊柳','沈佺期','唐','唐诗','tang','','[]','玉窗朝日暎，羅帳春風吹。',48,'全唐诗/poet.tang.5000.json','["玉窗朝日暎，羅帳春風吹。", "拭淚攀楊柳，長條踠地垂。", "白花飛歷亂，黃鳥思參差。", "妾自肝腸斷，傍人那得知。"]'),
('7fee8bf1-2306-4b76-96a2-6d014212f320','梅花落','沈佺期','唐','唐诗','tang','','[]','鐵騎幾時回，金閨怨早梅。',48,'全唐诗/poet.tang.5000.json','["鐵騎幾時回，金閨怨早梅。", "雪寒花已落，風暖葉應開。", "夕逐新春管，香迎小歲杯。", "盛時何足貴，書裏報輪臺。"]'),
('17e061a9-a122-419c-aa21-215d37c4e3e1','紫騮馬','沈佺期','唐','唐诗','tang','','[]','青玉紫騮鞍，驕多影屢盤。',48,'全唐诗/poet.tang.5000.json','["青玉紫騮鞍，驕多影屢盤。", "荷君能剪拂，躞蹀噴桑乾。", "踠足追奔易，長鳴遇賞難。", "摐金一萬里，霜露不辭寒。"]'),
('1f8bdfa2-20aa-45a4-a460-77df1ebab288','上之回','沈佺期','唐','唐诗','tang','','[]','制書下關右，天子問回中。',48,'全唐诗/poet.tang.5000.json','["制書下關右，天子問回中。", "壇墠經過遠，威儀侍從雄。", "黃麾搖晝日，青幰曳松風。", "迴望甘泉道，龍山隱漢宮。"]'),
('10d47f62-8f26-4045-a296-7579def9fbde','王昭君','沈佺期','唐','唐诗','tang','','[]','非君惜鸞殿，非妾妬蛾眉。',48,'全唐诗/poet.tang.5000.json','["非君惜鸞殿，非妾妬蛾眉。", "薄命由驕虜，無情是畫師。", "嫁來胡地日，不並漢宮時。", "心苦無聊賴，何堪馬上辭。"]'),
('e9d7d787-1068-4c53-a6a2-0abc4a020545','被試出塞','沈佺期','唐','唐诗','tang','','[]','十年通大漠，萬里出長平。',48,'全唐诗/poet.tang.5000.json','["十年通大漠，萬里出長平。", "寒日生戈劒，陰雲拂斾旌。", "飢烏啼舊壘，疲馬戀空城。", "辛苦臯蘭北，胡霜損漢兵。"]'),
('ce55c20d-64c1-4dbf-ad70-4aae1c0b9e92','牛女','沈佺期','唐','唐诗','tang','','[]','粉席秋期緩，針樓別怨多。',48,'全唐诗/poet.tang.5000.json','["粉席秋期緩，針樓別怨多。", "奔龍爭度日，飛鵲亂填河。", "失喜先臨鏡，含羞未解羅。", "誰能留夜色，來夕倍還梭。"]'),
('0e568765-f484-4616-9ca7-676b6831dc32','雜詩三首 一','沈佺期','唐','唐诗','tang','','[]','落葉驚秋婦，高砧促暝機。',48,'全唐诗/poet.tang.5000.json','["落葉驚秋婦，高砧促暝機。", "蜘蛛尋月度，螢火傍人飛。", "清鏡紅埃入，孤燈綠焰微。", "怨啼能至曉，獨自懶縫衣。"]'),
('12e099e7-7474-41c3-a332-76035325ef81','雜詩三首 二','沈佺期','唐','唐诗','tang','','[]','妾家臨渭北，春夢著遼西。',48,'全唐诗/poet.tang.5000.json','["妾家臨渭北，春夢著遼西。", "何苦朝鮮郡，年年事鼓鼙。", "燕來紅壁語，鶯向綠窗啼。", "爲許長相憶，闌干玉筯齊。"]'),
('1fb10ea4-f46c-4c08-bd06-f039f1907be6','雜詩三首 三','沈佺期','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6218\u4e89", "\u5987\u5973", "\u4e94\u8a00\u5f8b\u8bd7", "\u76f8\u601d"]','聞道黃龍戍，頻年不解兵。',48,'全唐诗/poet.tang.5000.json','["聞道黃龍戍，頻年不解兵。", "可憐閨裏月，長在漢家營。", "少婦今春意，良人昨夜情。", "誰能將旗鼓，一爲取龍城。"]'),
('0391d0b5-e133-4042-b2f6-cda55cbcdd5c','剪綵','沈佺期','唐','唐诗','tang','','[]','宮女憐芳樹，裁花競早榮。',48,'全唐诗/poet.tang.5000.json','["宮女憐芳樹，裁花競早榮。", "寒依刀尺盡，春向綺羅生。", "弱蔕盤絲發，香蕤結素成。", "纖枝幸不棄，長就玉階傾。"]'),
('378811bc-7daf-4769-b8c1-e0dc27f5110c','和中書侍郎楊再思春夜宿直','沈佺期','唐','唐诗','tang','','[]','西禁青春滿，南端皓月微。',48,'全唐诗/poet.tang.5000.json','["西禁青春滿，南端皓月微。", "千廬宵駕合，五夜曉鐘稀。", "星斗橫綸閣，天河度瑣闈。", "煙光章奏裏，紛向夕郎飛。"]'),
('6374eebf-a2b0-4dca-82af-9dbe01305e0d','和常州崔使君寒食夜','沈佺期','唐','唐诗','tang','','[]','聞道清明近，春闈向夕闌。',48,'全唐诗/poet.tang.5000.json','["聞道清明近，春闈向夕闌。", "行遊晝不厭，風物夜宜看。", "斗柄更初轉，梅香暗裏殘。", "無勞秉華燭，晴月在南端。"]'),
('850d9fba-c517-4de4-b391-61aa0e254673','和崔正諫登秋日早朝','沈佺期','唐','唐诗','tang','','[]','雞鳴朝謁滿，露白禁門秋。',48,'全唐诗/poet.tang.5000.json','["雞鳴朝謁滿，露白禁門秋。", "爽氣臨旌戟，朝光暎冕旒。", "河宗來獻寶，天子命焚裘。", "獨負池陽議，言從建禮遊。"]'),
('b52e374f-ebc9-4e26-a96b-73553f987953','答甯處州書','沈佺期','唐','唐诗','tang','','[]','書報天中赦，人從海上聞。',48,'全唐诗/poet.tang.5000.json','["書報天中赦，人從海上聞。", "九泉開白日，六翮起青雲。", "質幸恩先貸，情孤枉未分。", "自憐涇渭別，誰與奏明君。"]'),
('0c70f20d-13fe-412e-8f42-c5a39ee16831','李舍人山園送龐邵','沈佺期','唐','唐诗','tang','','[]','符傳有光輝，諠諠出帝畿。',48,'全唐诗/poet.tang.5000.json','["符傳有光輝，諠諠出帝畿。", "東隣借山水，南陌駐驂騑。", "握手涼風至，當歌秋日微。", "高幨去勿緩，人吏待霜威。"]'),
('f16cd2b4-b395-432f-888b-27a1246fdb32','送陸侍御餘慶北使','沈佺期','唐','唐诗','tang','','[]','古人貴將命，之子出輶軒。',48,'全唐诗/poet.tang.5000.json','["古人貴將命，之子出輶軒。", "受委當不辱，隨時敢贈言。", "朔途際遼海，春思繞轘轅。", "安得回白日，留歡盡綠樽。"]'),
('00a68422-3760-4d1a-bb1b-81adad61c08b','洛州蕭司兵謁兄還赴洛成禮','沈佺期','唐','唐诗','tang','','[]','棠棣日光輝，高襟應序歸。',48,'全唐诗/poet.tang.5000.json','["棠棣日光輝，高襟應序歸。", "來成鴻雁聚，去作鳳皇飛。", "細草乘輕傳，驚花慘別衣。", "灞亭春有酒，岐路惜芬菲。"]'),
('5eb45a70-3279-4487-9268-18758f290cb7','餞高唐州詢','沈佺期','唐','唐诗','tang','','[]','弱冠相知早，中年不見多。',48,'全唐诗/poet.tang.5000.json','["弱冠相知早，中年不見多。", "生涯在王事，客鬢各蹉跎。", "良守初分岳，嘉聲即潤河。", "還從漢闕下，傾耳聽中和。"]'),
('82d50614-2c93-46eb-bed1-82740842146b','餞唐郎中洛陽令','沈佺期','唐','唐诗','tang','','[]','一臺推往妙，三史佇來修。',48,'全唐诗/poet.tang.5000.json','["一臺推往妙，三史佇來修。", "應宰鳧還集，辭郎雉少留。", "郊筵乘落景，亭傳理殘秋。", "願以弦歌暇，芝蘭想舊遊。"]'),
('e4c988e1-7771-45dc-8c48-80fe1451233c','樂城白鶴寺','沈佺期','唐','唐诗','tang','','[]','碧海開龍藏，青雲起雁堂。',48,'全唐诗/poet.tang.5000.json','["碧海開龍藏，青雲起雁堂。", "潮聲迎法鼓，雨氣濕天香。", "樹接前山暗，溪承瀑水涼。", "無言謫居遠，清淨得空王。"]'),
('1a5ba65c-a7b6-4059-92c9-31c088efaa48','遊少林寺','沈佺期','唐','唐诗','tang','','[]','長歌遊寶地，徙倚對珠林。',48,'全唐诗/poet.tang.5000.json','["長歌遊寶地，徙倚對珠林。", "雁塔風霜古，龍池歲月深。", "紺園澄夕霽，碧殿下秋陰。", "歸路煙霞晚，山蟬處處吟。"]'),
('7dd79e76-4b32-43c0-9516-6f17a87c016c','嶽館','沈佺期','唐','唐诗','tang','','[]','洞壑仙人館，孤峰玉女臺。',48,'全唐诗/poet.tang.5000.json','["洞壑仙人館，孤峰玉女臺。", "空濛朝氣合，窈窕夕陽開。", "流澗含輕雨，虛巖應薄雷。", "正逢鸞與鶴，歌舞出天來。"]'),
('6ff9bf9f-7434-4851-995f-43f366500c9e','早發平昌島','沈佺期','唐','唐诗','tang','','[]','解纜春風後，鳴榔曉漲前。',48,'全唐诗/poet.tang.5000.json','["解纜春風後，鳴榔曉漲前。", "陽烏出海樹，雲雁下江煙。", "積氣衝長島，浮光溢大川。", "不能懷魏闕，心賞獨泠然。"]'),
('63250717-a10a-4815-bcaf-175ede125559','夜宿七盤嶺','沈佺期','唐','唐诗','tang','','["\u5b64\u72ec", "\u601d\u4e61", "\u5199\u666f"]','獨遊千里外，高臥七盤西。',48,'全唐诗/poet.tang.5000.json','["獨遊千里外，高臥七盤西。", "曉月臨窗近，天河入戶低。", "芳春平仲綠，清夜子規啼。", "浮客空留聽，褒城聞曙雞。"]'),
('616c4630-6fe7-46fb-8108-928e1425706a','十三四時嘗從巫峽過他日偶然有思','沈佺期','唐','唐诗','tang','','[]','小度巫山峽，荆南春欲分。',48,'全唐诗/poet.tang.5000.json','["小度巫山峽，荆南春欲分。", "使君灘上草，神女館前雲。", "樹悉江中見，猿多天外聞。", "別來如夢裏，一想一氛氳。"]'),
('b8645670-f21b-4437-96f7-bb8a6a6d5972','初達驩州','沈佺期','唐','唐诗','tang','','[]','自昔聞銅柱，行來向一年。',48,'全唐诗/poet.tang.5000.json','["自昔聞銅柱，行來向一年。", "不知林邑地，猶隔道明天。", "雨露何時及？京華若個邊。", "思君無限淚，堪作日南泉。"]'),
('e308da2f-7092-4d52-9bfd-0e60197017f1','嶺表逢寒食','沈佺期','唐','唐诗','tang','','[]','嶺外無寒食，春來不見餳。',48,'全唐诗/poet.tang.5000.json','["嶺外無寒食，春來不見餳。", "洛陽新甲子，何日是清明？", "花柳爭朝發，軒車滿路迎。", "帝鄉遙可念，腸斷報親情。"]'),
('40d32391-64e6-4c4c-bc8b-61cbe581b6da','驩州南亭夜望','沈佺期','唐','唐诗','tang','','[]','昨夜南亭望，分明夢洛中。',48,'全唐诗/poet.tang.5000.json','["昨夜南亭望，分明夢洛中。", "室家誰道別，兒女案嘗同。", "忽覺猶言是，沈思始悟空。", "肝腸餘幾寸，拭淚坐春風。"]'),
('49590ad5-2e5d-424d-8e89-be28ddb4adb0','少遊荆湘因有是題','沈佺期','唐','唐诗','tang','','[]','峴北焚蛟浦，巴東射雉田。',48,'全唐诗/poet.tang.5000.json','["峴北焚蛟浦，巴東射雉田。", "歲時宜楚俗，耆舊在襄川。", "憶昨經過處，離今二十年。", "因君訪生死，相識幾人全。"]'),
('10b11d93-1d65-4449-bc10-24dc2494a5dd','咸陽覽古','沈佺期','唐','唐诗','tang','','[]','咸陽秦帝居，千載坐盈虛。',48,'全唐诗/poet.tang.5000.json','["咸陽秦帝居，千載坐盈虛。", "版築林光盡，壇場霤聽疎。", "野橋疑望日，山火類焚書。", "唯有驪峰在，空聞厚葬餘。"]'),
('ef89af2c-3616-46ad-a2e9-4bb3300fe7e1','覽鏡','沈佺期','唐','唐诗','tang','','[]','霏霏日搖蕙，騷騷風灑蓮。',48,'全唐诗/poet.tang.5000.json','["霏霏日搖蕙，騷騷風灑蓮。", "時芳固相奪，俗態豈恆堅。", "恍忽夜川裏，蹉跎朝鏡前。", "紅顏與壯志，太息此流年。"]'),
('72d0b232-6662-4199-a74f-ce4000d620df','題椰子樹','沈佺期','唐','唐诗','tang','','[]','日南椰子樹，香褭出風塵。',48,'全唐诗/poet.tang.5000.json','["日南椰子樹，香褭出風塵。", "叢生調木首，圓實檳榔身。", "玉房九霄露，碧葉四時春。", "不及塗林果，移根隨漢臣。"]'),
('3f711032-2b3d-4603-9578-51209add995d','同獄者歎獄中無燕','沈佺期','唐','唐诗','tang','','[]','何許乘春燕，多知辨夏臺。',48,'全唐诗/poet.tang.5000.json','["何許乘春燕，多知辨夏臺。", "三時欲併盡，雙影未嘗來。", "食蕋嫌叢棘，銜泥怯死灰。", "不如黃雀語，能雪冶長猜。"]'),
('31dd857a-849d-42bf-a9ce-5eda1bdf0a08','則天門赦改年','沈佺期','唐','唐诗','tang','','[]','聖人宥天下，幽鑰動圜狴。',48,'全唐诗/poet.tang.5000.json','["聖人宥天下，幽鑰動圜狴。", "六甲迎黃氣，三元降紫泥。", "籠僮上西鼓，振迅廣陽雞。", "歌舞將金帛，汪洋被遠黎。"]'),
('2eea58f3-4c5c-411b-92ac-8abf530fae6d','喜赦','沈佺期','唐','唐诗','tang','','[]','去歲投荒客，今春肆眚歸。',48,'全唐诗/poet.tang.5000.json','["去歲投荒客，今春肆眚歸。", "律通幽谷暖，盆舉太陽輝。", "喜氣迎冤氣，青衣報白衣。", "還將合浦葉，俱向洛城飛。"]'),
('781d15eb-381b-4c8e-8484-b5e072c8ba20','秦州薛都督挽詞','沈佺期','唐','唐诗','tang','','[]','十里絳山幽，千年汾水流。',48,'全唐诗/poet.tang.5000.json','["十里絳山幽，千年汾水流。", "碑傳門客建，劒是故人留。", "隴樹烟含夕，山門月對秋。", "古來鐘鼎盛，共盡一蒿丘。"]'),
('72b48e21-072a-464e-afc5-1576f7357086','天官崔侍郎夫人盧氏挽歌','沈佺期','唐','唐诗','tang','','[]','偕老言何謬，香魂事永違。',48,'全唐诗/poet.tang.5000.json','["偕老言何謬，香魂事永違。", "潘魚從此隔，陳鳳宛然飛。", "埋鏡泉中暗，藏鐙地下微。", "猶憑少君術，彷彿覩容輝。"]'),
('09bf1776-d49a-4d9a-a6fa-def40be46fe0','章懷太子靖妃挽詞','沈佺期','唐','唐诗','tang','','[]','彤史佳聲載，青宮懿範留。',48,'全唐诗/poet.tang.5000.json','["彤史佳聲載，青宮懿範留。", "形將鸞鏡隱，魂伴鳳笙遊。", "送馬嘶殘日，新螢落晚秋。", "不知蒿里曙，空見隴雲愁。"]'),
('0eb289a8-73e9-4284-9132-d30b5118ba83','奉和立春遊苑迎春','沈佺期','唐','唐诗','tang','','[]','東郊暫轉迎春仗，上苑初飛行慶杯。',64,'全唐诗/poet.tang.5000.json','["東郊暫轉迎春仗，上苑初飛行慶杯。", "風射蛟冰千片斷，氣衝魚鑰九關開。", "林中覓草纔生蕙，殿裏爭花併是梅。", "歌吹銜恩歸路晚，棲烏半下鳳城來。"]'),
('0d7195e8-759e-494d-9b4e-3aa59a3693a8','人日重宴大明宮賜綵縷人勝應制','沈佺期','唐','唐诗','tang','','[]','拂旦雞鳴仙衞陳，憑高龍首帝城春。',64,'全唐诗/poet.tang.5000.json','["拂旦雞鳴仙衞陳，憑高龍首帝城春。", "千官黼帳杯前壽，百福香匳勝裏人。", "山鳥初來猶怯囀，林花未發已偷新。", "天文正應韶光轉，設報懸知用此辰。"]'),
('57b7d0ea-19f2-4248-b147-77347054baae','奉和春初幸太平公主南莊應制','沈佺期','唐','唐诗','tang','','[]','主家山第早春歸，御輦春遊繞翠微。',64,'全唐诗/poet.tang.5000.json','["主家山第早春歸，御輦春遊繞翠微。", "買地鋪金曾作埒，尋河取石舊支機。", "雲間樹色千花滿，竹裏泉聲百道飛。", "自有神仙鳴鳳曲，併將歌舞報恩暉。"]'),
('20380cb7-de3d-467b-a111-075dbc0400c0','奉和春日幸望春宮應制','沈佺期','唐','唐诗','tang','','[]','芳郊綠野散春晴，複道離宮煙霧生。',64,'全唐诗/poet.tang.5000.json','["芳郊綠野散春晴，複道離宮煙霧生。", "楊柳千條花欲綻，蒲萄百丈蔓初縈。", "林香酒氣元相入，鳥囀歌聲各自成。", "定是風光牽宿醉，來晨復得幸昆明。"]'),
('05a58c18-1ae7-4405-9361-e35f7a5bcd3f','侍宴安樂公主新宅應制','沈佺期','唐','唐诗','tang','','[]','皇家貴主好神仙，別業初開雲漢邊。',64,'全唐诗/poet.tang.5000.json','["皇家貴主好神仙，別業初開雲漢邊。", "山出盡如鳴鳳嶺，池成不讓飲龍川。", "妝樓翠幌教春住，舞閣金鋪借日懸。", "敬從乘輿來此地，稱觴獻壽樂鈞天。"]'),
('3c9876a4-e979-4233-898b-d11f96311f25','龍池篇','沈佺期','唐','唐诗','tang','','[]','龍池躍龍龍已飛，龍德先天天不違。',64,'全唐诗/poet.tang.5000.json','["龍池躍龍龍已飛，龍德先天天不違。", "池開天漢分黃道，龍向天門入紫微。", "邸第樓臺多氣色，君王鳧雁有光輝。", "爲報寰中百川水，來朝此地莫東歸。"]'),
('4921a827-1bf3-4b5c-90d6-cc124406f5ba','興慶池侍宴應制','沈佺期','唐','唐诗','tang','','[]','碧水澄潭暎遠空，紫雲香駕御微風。',64,'全唐诗/poet.tang.5000.json','["碧水澄潭暎遠空，紫雲香駕御微風。", "漢家城闕疑天上，秦地山川似鏡中。", "向浦回舟萍已綠，分林蔽殿槿初紅。", "古來徒羨橫汾賞，今日宸遊聖藻雄。"]'),
('18a656df-00f4-4000-b36e-2d0e490fbb99','從幸香山寺應制','沈佺期','唐','唐诗','tang','','[]','南山奕奕通丹禁，北闕峨峨連翠雲。',66,'全唐诗/poet.tang.5000.json','["南山奕奕通丹禁，北闕峨峨連翠雲。", "嶺上樓臺千地起，城中鐘鼓四天聞。", "旃檀曉閣金輿度，鸚鵡晴林采眊分。", "願以醍醐參聖酒，還將[衹]苑當秋汾。"]'),
('25de0765-6846-4da5-b966-ae1bade948e9','紅樓院應制','沈佺期','唐','唐诗','tang','','[]','紅樓疑見白毫光，寺逼宸居福盛唐。',64,'全唐诗/poet.tang.5000.json','["紅樓疑見白毫光，寺逼宸居福盛唐。", "支遁愛山情謾切，曇摩泛海路空長。", "經聲夜息聞天語，爐氣晨飄接御香。", "誰謂此中難可到，自憐深院得徊翔。"]'),
('7875082b-2898-40df-bfab-681426ed3a03','再入道場紀事應制','沈佺期','唐','唐诗','tang','','[]','南方歸去再生天，內殿今年異昔年。',64,'全唐诗/poet.tang.5000.json','["南方歸去再生天，內殿今年異昔年。", "見闢乾坤新定位，看題日月更高懸。", "行隨香輦登仙路，坐近爐煙講法筵。", "自喜恩深陪侍從，兩朝長在聖人前。"]'),
('7d249927-ee35-46b1-8c00-05d4b6adadfb','嵩山石淙侍宴應制','沈佺期','唐','唐诗','tang','','[]','金輿旦下綠雲衢，綵殿晴臨碧澗隅。',64,'全唐诗/poet.tang.5000.json','["金輿旦下綠雲衢，綵殿晴臨碧澗隅。", "溪水泠泠雜行漏，山煙片片繞香爐。", "仙人六膳調神鼎，玉女三漿捧帝壺。", "自惜汾陽紆道駕，無如太室覽真圖。"]'),
('b9521e2b-963e-4d90-acf3-d87c2a135071','古意呈補闕喬知之','沈佺期','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u95fa\u6028", "\u4e50\u5e9c"]','盧家少婦鬱金堂，海燕雙棲玳瑁梁。',64,'全唐诗/poet.tang.5000.json','["盧家少婦鬱金堂，海燕雙棲玳瑁梁。", "九月寒砧催木葉，十年征戍憶遼陽。", "白狼河北音書斷，丹鳳城南秋夜長。", "誰謂含愁獨不見，更教明月照流黃。"]'),
('052d46fe-db9c-42ec-a42a-0ac433f26a65','遙同杜員外審言過嶺','沈佺期','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61", "\u5199\u666f"]','天長地闊嶺頭分，去國離家見白雲。',48,'全唐诗/poet.tang.5000.json','["天長地闊嶺頭分，去國離家見白雲。", "洛浦風光何所似，崇山瘴癘不堪聞。", "南浮漲海人何處？北望衡陽雁幾羣。"]'),
('a04655d3-9d60-4544-a046-3c3f0785bcfc','和上巳連寒食有懷京洛','沈佺期','唐','唐诗','tang','','[]','天津御柳碧遙遙，軒騎相從半下朝。',64,'全唐诗/poet.tang.5000.json','["天津御柳碧遙遙，軒騎相從半下朝。", "行樂光輝寒食借，太平歌舞晚春饒。", "紅妝樓下東迴輦，青草洲邊南渡橋。", "坐見司空掃西第，看君侍從落花朝。"]'),
('63e0fa21-7f2a-449f-b5fb-1b20d7ced3a9','陪幸太平公主南莊詩','沈佺期','唐','唐诗','tang','','[]','主第山門起灞川，宸遊風景入初年。',64,'全唐诗/poet.tang.5000.json','["主第山門起灞川，宸遊風景入初年。", "鳳皇樓下交天仗，烏鵲橋頭敞御筵。", "往往花間逢綵石，時時竹裏見紅泉。", "今朝扈蹕平陽館，不羨乘槎雲漢邊。"]'),
('a3253a45-9c78-4b9f-b9ad-a07644697800','守歲應制','沈佺期','唐','唐诗','tang','','[]','南渡輕冰解渭橋，東方樹色起招搖。',64,'全唐诗/poet.tang.5000.json','["南渡輕冰解渭橋，東方樹色起招搖。", "天子迎春取今夜，王公獻壽用明朝。", "殿上燈人爭烈火，宮中侲子亂驅妖。", "宜將歲酒調神藥，聖祚千春萬國朝。"]'),
('13a09b36-f435-47c6-b751-ebbe59d799d8','陪幸韋嗣立山莊','沈佺期','唐','唐诗','tang','','[]','台階好赤松，別業對青峯。',96,'全唐诗/poet.tang.5000.json','["台階好赤松，別業對青峯。", "茆室承三顧，花源接九重。", "虹旗縈秀木，鳳輦拂疎筇。", "逕直千官擁，溪長萬騎容。", "水堂開禹膳，山閣獻堯鍾。", "皇鑑清居遠，天文睿獎濃。", "巖泉他夕夢，漁釣往年逢。", "共榮丞相府，偏降逸人封。"]'),
('86060c5d-4655-4bfd-8e5d-35fa45e3b448','扈從出長安應制','沈佺期','唐','唐诗','tang','','["\u9ec4\u5c71"]','漢宅規模壯，周都景命隆。',132,'全唐诗/poet.tang.5000.json','["漢宅規模壯，周都景命隆。", "西賓讓東主，法駕幸天中。", "太史占星應，春官奏日同。", "旌門起長樂，帳殿出新豐。", "翕習黃山下，紆徐清渭東。", "金麾張畫月，珠幰戴松風。", "是節嚴陰始，寒郊散野蓬。", "薄霜沾上路，殘雪繞離宮。", "賜帛矜耆老，褰旒問小童。", "復除恩載洽，望秩禮新崇。", "臣忝承明召，多慙獻賦雄。"]'),
('0bc62fb4-dd3d-40ed-8ee5-11dafbefe8a0','初冬從幸漢故青門應制','沈佺期','唐','唐诗','tang','','[]','漢王建都邑，渭水對青門。',120,'全唐诗/poet.tang.5000.json','["漢王建都邑，渭水對青門。", "朝市俱東逝，墳陵共北原。", "荒涼蕭相闕，蕪沒邵平園。", "全盛今何在，英雄難重論。", "故基仍嶽立，遺堞尚雲屯。", "當極土功壯，安知人力煩。", "天遊戒東首，懷昔駐龍軒。", "何必金湯固，無如道德藩。", "微臣諒多幸，參乘偶殊恩。", "預此陳古事，敢奏興亡言。"]'),
('aa53e079-7b40-4f59-bffd-3f6b1841afa7','昆明池侍宴應制','沈佺期','唐','唐诗','tang','','[]','武帝伐昆明，穿池習五兵。',96,'全唐诗/poet.tang.5000.json','["武帝伐昆明，穿池習五兵。", "水同河漢在，館有豫章名。", "我后光天德，垂衣文教成。", "黷兵非帝念，勞物豈皇情。", "春仗過鯨沼，雲旗出鳳城。", "靈魚銜寶躍，仙女廢機迎。", "柳拂旌門暗，蘭依帳殿生。", "還如流水曲，日晚棹歌清。"]'),
('f9a36948-1419-49f4-86ab-799bc8b95168','白蓮花亭侍宴應制','沈佺期','唐','唐诗','tang','','[]','九日陪天仗，三秋幸禁林。',72,'全唐诗/poet.tang.5000.json','["九日陪天仗，三秋幸禁林。", "霜威變綠樹，雲氣落青岑。", "水殿黃花合，山亭絳葉深。", "朱旗夾小徑，寶馬駐清潯。", "苑吏收寒果，饔人膳野禽。", "承歡不覺暝，遙響素秋砧。"]'),
('61592830-5a9b-4356-93e0-793bd3c8138f','仙萼池亭侍宴應制','沈佺期','唐','唐诗','tang','','[]','步輦尋丹嶂，行宮在翠微。',72,'全唐诗/poet.tang.5000.json','["步輦尋丹嶂，行宮在翠微。", "川長看鳥滅，谷轉聽猿稀。", "天磴扶階迥，雲泉透戶飛。", "閑花開石竹，幽葉吐薔薇。", "徑狹難留騎，亭寒欲進衣。", "白龜來獻壽，仙吹返彤闈。"]'),
('5d2bcb20-4765-47e9-9d3b-c7c4e6a7d9f4','奉和晦日駕幸昆明池應制','沈佺期','唐','唐诗','tang','','[]','法駕乘春轉，神池象漢廻。',72,'全唐诗/poet.tang.5000.json','["法駕乘春轉，神池象漢廻。", "雙星移舊石，孤月隱殘灰。", "戰鷁逢時去，恩魚望幸來。", "山花緹騎繞，堤柳幔城開。", "思逸橫汾唱，歡留宴鎬杯。", "微臣雕朽質，羞覩豫章材。"]'),
('2bf96549-f3c6-43cb-82b1-a990710e1975','奉和聖製幸禮部尚書竇希玠宅','沈佺期','唐','唐诗','tang','','[]','北闕垂旒暇，南宮聽履廻。',72,'全唐诗/poet.tang.5000.json','["北闕垂旒暇，南宮聽履廻。", "天臨翔鳳轉，恩向躍龍開。", "蘭氣薰仙帳，榴花引御杯。", "水從金穴吐，雲是玉衣來。", "池影搖歌席，林香散舞臺。", "不知行漏晚，清蹕尚裴徊。"]'),
('28c616fa-2fab-40c7-b4e1-eec241c762cc','釣竿篇','沈佺期','唐','唐诗','tang','','[]','朝日斂紅煙，垂竿向綠川。',72,'全唐诗/poet.tang.5000.json','["朝日斂紅煙，垂竿向綠川。", "人疑天上坐，魚似鏡中懸。", "避檝時驚透，猜鉤每誤牽。", "湍危不理轄，潭靜欲留船。", "釣玉君徒尚，徵金我未賢。", "爲看芳餌下，貪得會無筌。"]'),
('dbef852a-ec34-4833-8957-d82450693f91','和戶部岑尚書參迹樞揆','沈佺期','唐','唐诗','tang','','[]','大君制六合，良佐參萬機。',120,'全唐诗/poet.tang.5000.json','["大君制六合，良佐參萬機。", "大業永開泰，臣道日光輝。", "鹽梅和鼎食，家聲衆所歸。", "漢章題楚劒，鄭武襲緇衣。", "理識當朝遠，文華振古希。", "風雲神契合，舟檝道心微。", "廟堂喜容與，時物逓芳菲。", "御柳垂仙掖，公槐覆禮闈。", "昔陪鵷鷺後，今望鵾鵬飛。", "徒御清風頌，巴歌聊自揮。"]'),
('f5a05db5-cc5b-484f-9517-0782135c2b3b','同李舍人冬日集安樂公主山池','沈佺期','唐','唐诗','tang','','[]','嘗聞天女貴，家即帝宮連。',96,'全唐诗/poet.tang.5000.json','["嘗聞天女貴，家即帝宮連。", "亭插宜春果，山衝太液泉。", "橋低烏鵲夜，臺起鳳皇年。", "故事猶如此，新圖更可憐。", "紫巖妝閣透，青嶂妓樓懸。", "峰奪香爐巧，池偷明鏡圓。", "梅花寒待雪，桂葉晚留煙。", "興盡方投轄，金聲還復傳。"]'),
('d8e61a77-dc28-4e92-a954-fbfa49eabdde','酬蘇員外味道夏晚寓直省中見贈','沈佺期','唐','唐诗','tang','','[]','並命登仙閣，分曹直禮闈。',72,'全唐诗/poet.tang.5000.json','["並命登仙閣，分曹直禮闈。", "大官供宿膳，侍史護朝衣。", "卷幔天河入，開窗月露微。", "小池殘暑退，高樹早涼歸。", "冠劒無時釋，軒車待漏飛。", "明朝題漢柱，三署有光輝。"]'),
('69292dcc-3a7e-4048-badd-aa403d6b35c7','和韋舍人早朝','沈佺期','唐','唐诗','tang','','[]','閶闔連雲起，巖廊拂霧開。',72,'全唐诗/poet.tang.5000.json','["閶闔連雲起，巖廊拂霧開。", "玉珂龍影度，珠履雁行來。", "長樂宵鐘盡，明光曉奏催。", "一經推舊德，五字擢英才。", "儼若神仙去，紛從霄漢廻。", "千春奉休曆，分禁喜趨陪。"]'),
('4af7c006-1f82-42d4-8792-47f0fb5dda77','自考功員外授給事中','沈佺期','唐','唐诗','tang','','[]','南省推丹地，東曹拜瑣闈。',120,'全唐诗/poet.tang.5000.json','["南省推丹地，東曹拜瑣闈。", "惠移雙管筆，恩降五時衣。", "出入宜真選，遭逢每濫飛。", "器慙公理拙，才謝子雲微。", "案牘遺常禮，朋僚隔等威。", "上台行揖讓，中禁動光輝。", "旭日千門起，初春八舍歸。", "贈蘭聞宿昔，談樹隱芳菲。", "何幸鹽梅處，唯憂對問機。", "省躬知任重，寧止冒榮非。"]'),
('bdd45a2c-15e1-4b40-b243-0f127d9e0151','和元舍人萬頃臨池翫月戲爲新體','沈佺期','唐','唐诗','tang','','[]','春風搖碧樹，秋霧卷丹臺。',120,'全唐诗/poet.tang.5000.json','["春風搖碧樹，秋霧卷丹臺。", "復有相宜夕，池清月正開。", "玉流含吹動，金魄度雲來。", "熠爚光如沸，翩翾景若摧。", "半環投積草，碎璧聚流杯。", "夜久平無煥，天晴皎未隤。", "鏡將池作匣，珠以岸爲胎。", "有美司言暇，高興獨悠哉。", "揮翰初難擬，飛名豈易陪。", "夜光殊在握，了了見沈灰。"]'),
('57d2e886-c491-487c-aa74-7526a30434a0','酬楊給事兼見贈臺中','沈佺期','唐','唐诗','tang','','[]','子雲推辨博，公理擅詞雄。',96,'全唐诗/poet.tang.5000.json','["子雲推辨博，公理擅詞雄。", "始自尚書省，旋聞給事中。", "言從溫室祕，籍向瑣闈通。", "顧我叨郎署，慙無草奏功。", "分曹八舍斷，解袂五時空。", "宿昔陪餘論，平生賴擊蒙。", "神仙應東掖，雲霧限南宮。", "忽枉瓊瑤贈，長歌蘭渚風。"]'),
('09ce8658-5174-43e6-a693-f58a7ef8dd32','九真山淨居寺謁無礙上人','沈佺期','唐','唐诗','tang','','[]','大士生天竺，分身化日南。',120,'全唐诗/poet.tang.5000.json','["大士生天竺，分身化日南。", "人中出煩惱，山下即伽藍。", "小澗香爲剎，危峰石作龕。", "候禪青鴿乳，窺講白猿參。", "藤愛雲間壁，花憐石下潭。", "泉行幽供好，林挂浴衣堪。", "弟子哀無識，醫王惜未談。", "機疑聞不二，蒙昧即朝三。", "欲究因緣理，聊寬放棄慙。", "超然虎溪夕，雙樹下虛嵐。"]'),
('3eaef5d7-9118-435a-ac36-e26540edbcf2','夜遊','沈佺期','唐','唐诗','tang','','[]','今夕重門啟，遊春得夜芳。',72,'全唐诗/poet.tang.5000.json','["今夕重門啟，遊春得夜芳。", "月華連晝色，燈影雜星光。", "南陌青絲騎，東鄰紅粉妝。", "管弦遙辨曲，羅綺暗聞香。", "人擁行歌路，車攢鬬舞場。", "經過猶未已，鐘鼓出長楊。"]'),
('de11b09a-25f2-4267-b9a9-6334da20f73c','登瀛州南城樓寄遠','沈佺期','唐','唐诗','tang','','[]','層城起麗譙，憑覽出重霄。',84,'全唐诗/poet.tang.5000.json','["層城起麗譙，憑覽出重霄。", "茲地多形勝，中天宛寂寥。", "四榮摩鸛鶴，百拱厲風飆。", "北際燕王館，東連秦帝橋。", "晴光七郡滿，春色兩河遙。", "傲睨非吾土，躊躇適遠囂。", "離居欲有贈，春草寄長謠。"]'),
('385583d6-9a4d-4e07-baf6-256cb67f49bf','塞北二首 一','沈佺期','唐','唐诗','tang','','[]','虜障天驕起，秦城地脉分。',96,'全唐诗/poet.tang.5000.json','["虜障天驕起，秦城地脉分。", "柏壇飛五將，梅吹動三軍。", "鋒刃奔濤色，旌旗焰火文。", "朔風吹汗漫，飄礫灑轒輼。", "海氣如秋雨，邊烽似夏雲。", "二庭無歲月，百戰有功勳。", "形影隨魚貫，音書在雁羣。", "歸來拜天子，凱樂助南薰。"]'),
('a611c4f0-e97c-4cb1-ab4c-fcd5b4a8a19d','塞北二首 二','沈佺期','唐','唐诗','tang','','[]','胡騎犯邊埃，風從丑上來。',98,'全唐诗/poet.tang.5000.json','["胡騎犯邊埃，風從丑上來。", "五原烽火急，六郡羽書催。", "冰壯飛狐[冷]，霜濃候雁哀。", "將軍朝授鉞，戰士夜銜枚。", "紫塞金河裏，蔥山鐵勒隈。", "蓮花秋劒發，桂葉曉旗開。", "秘略三軍動，妖氛百戰摧。", "何言投筆去，終作勒銘回。"]'),
('dbce5180-34f2-4d50-9a36-9db07635d349','李員外秦援宅觀妓','沈佺期','唐','唐诗','tang','','[]','盈盈粉署郎，五日宴春光。',72,'全唐诗/poet.tang.5000.json','["盈盈粉署郎，五日宴春光。", "選客虛前館，徵聲徧後堂。", "玉釵翠羽飾，羅袖鬱金香。", "拂黛隨時廣，挑鬟出意長。", "囀歌遙合態，度舞暗成行。", "巧落梅庭裏，斜光暎曉妝。"]'),
('afeff31f-dad6-4dd6-b457-4e3ece085554','送韋商州弼','沈佺期','唐','唐诗','tang','','[]','會府應文昌，商山鎮國陽。',72,'全唐诗/poet.tang.5000.json','["會府應文昌，商山鎮國陽。", "聞君監郡史，蹔罷尚書郎。", "王事嗟相失，人情貴不忘。", "累年同畫省，四海接文場。", "點翰芳春色，傳杯明月光。", "故交從此去，遙憶紫芝香。"]'),
('e9e8d5ae-9d08-4440-a38c-76bfbaf6f6ff','夏日梁王席送張岐州','沈佺期','唐','唐诗','tang','','[]','秦雞常下雍，周鳳昔鳴岐。',96,'全唐诗/poet.tang.5000.json','["秦雞常下雍，周鳳昔鳴岐。", "此地推雄撫，惟良寄在斯。", "家傳七豹貴，人擅八龍奇。", "高傳生光彩，長林歎別離。", "天人開祖席，朝寀候征麾。", "翠帟當郊敞，彤幨向野披。", "芃芃秋麥盛，苒苒夏條垂。", "奏計何時入？臺階望羽儀。"]'),
('c7584ad7-2866-40d5-84d9-21d3e025dcb3','夏日都門送司馬員外逸客孫員外佺北征','沈佺期','唐','唐诗','tang','','[]','二庭追虜騎，六月動周師。',72,'全唐诗/poet.tang.5000.json','["二庭追虜騎，六月動周師。", "廟略天人授，軍麾相國持。", "復言徵二妙，才命重當時。", "畫省連征橐，橫門共別詞。", "雲迎出塞馬，風卷度河旗。", "計日方夷寇，旋聞杕杜詩。"]'),
('cb4e691a-d674-4e78-8c42-2ed9d49274f5','送盧管記仙客北伐','沈佺期','唐','唐诗','tang','','[]','羽檄西北飛，交城日夜圍。',72,'全唐诗/poet.tang.5000.json','["羽檄西北飛，交城日夜圍。", "廟堂盛徵選，戎幕生光輝。", "雁行度函谷，馬首向金微。", "湛湛山川暮，蕭蕭涼氣稀。", "餞途予憫默，赴敵子英威。", "今日楊朱淚，無將灑鐵衣。"]'),
('f3a5ebb9-28b5-4a9f-b31f-c0f94b07498d','移禁司刑','沈佺期','唐','唐诗','tang','','[]','疇昔參鄉賦，中年忝吏途。',290,'全唐诗/poet.tang.5000.json','["疇昔參鄉賦，中年忝吏途。", "丹脣曾學史，白首不成儒。", "天子開昌籙，羣生偶大爐。", "散材仍葺廈，弱羽遽[摶]扶。", "寵邁乘軒鶴，榮過食稻鳧。", "何功遊畫省，何德理黃樞。", "弔影慙非據，傾心事遠圖。", "盜泉寧止渴，惡木匪投軀。", "任直翻多毀，安身遂少徒。", "一朝逢糺謬，三省竟無虞。", "白簡初心屈，黃紗始望孤。", "患平終不怒，持劾每相驅。", "埋劒誰當辨，偷金以自誣。", "誘言雖委答，流議亦真符。", "首夏方憂圄，高秋獨向隅。", "嚴城看熠耀，圜戶對蜘蛛。", "累餉唯妻子，披冤是友于。", "物情牽倚伏，人事限榮枯。", "門客心誰在，隣交迹倘無。", "撫襟雙涕落，危坐日憂趨。", "聖旨垂明德，冤囚豈濫誅。", "會希恩免理，終望罪矜愚。", "司寇宜哀獄，台庭幸恤辜。", "漢皇虛詔上，容有報恩珠。"]'),
('d46c4f3d-5cf0-429c-af46-b233f3495bd1','入鬼門關','沈佺期','唐','唐诗','tang','','[]','昔傳瘴江路，今到鬼門關。',72,'全唐诗/poet.tang.5000.json','["昔傳瘴江路，今到鬼門關。", "土地無人老，流移幾客還。", "自從別京洛，頹鬢與衰顏。", "夕宿含沙裏，晨行岡路間。", "馬危千仞谷，舟險萬重灣。", "問我投何地？西南盡百蠻。"]'),
('d694744e-af07-4de8-98c9-2bd1936db3bb','三日獨坐驩州思憶舊遊','沈佺期','唐','唐诗','tang','','[]','兩京多節物，三日最遨遊。',204,'全唐诗/poet.tang.5000.json','["兩京多節物，三日最遨遊。", "麗日風徐卷，香塵雨暫收。", "紅桃初下地，綠柳半垂溝。", "童子成春服，宮人罷射鞲。", "禊堂通漢苑，解席繞秦樓。", "束皙言談妙，張華史漢遒。", "無亭不駐馬，何浦不橫舟。", "舞籥千門度，帷屏百道流。", "金丸向鳥落，芳餌接魚投。", "濯穢憐清淺，迎祥樂獻酬。", "靈芻陳欲棄，神藥曝應休。", "誰念招魂節，翻爲禦魅囚。", "朋從天外盡，心賞日南求。", "銅柱威丹徼，朱崖鎮火陬。", "炎蒸連曉夕，瘴癘滿冬秋。", "西水何時貸？南方詎可留。", "無人對爐酒，寧緩去鄉憂。"]'),
('31be9ea6-b3ed-4e25-a5f0-fbe317c8b4a7','從驩州廨宅移住山間水亭贈蘇使君','沈佺期','唐','唐诗','tang','','[]','遇坎即乘流，西南到火洲。',168,'全唐诗/poet.tang.5000.json','["遇坎即乘流，西南到火洲。", "鬼門應苦夜，瘴浦不宜秋。", "歲貸胸穿老，朝飛鼻飲頭。", "死生離骨肉，榮辱間朋遊。", "棄置一身在，平生萬事休。", "鷹鸇遭誤逐，豺虎怯真投。", "憶昨京華子，傷今邊地囚。", "願陪鸚鵡樂，希並鷓鴣留。", "日月渝鄉思，煙花換客愁。", "幸逢蘇伯玉，回借水亭幽。", "山柏張青蓋，江蕉卷綠油。", "乘閑無火宅，因放有漁舟。", "適越心當是，居夷迹可求。", "古來堯禪舜，何必罪驩兜。"]'),
('595db240-dab3-4527-b116-788c8e141313','赦到不得歸題江上石','沈佺期','唐','唐诗','tang','','[]','家住東京裏，身投南海西。',290,'全唐诗/poet.tang.5000.json','["家住東京裏，身投南海西。", "風烟萬里隔，朝夕幾行啼。", "聖主謳歌洽，賢臣法令齊。", "忽聞銅柱使，走馬報金雞。", "棄市沾皇渥，投荒漏紫泥。", "魂疲山鶴路，心醉[跕]鳶溪。", "天鑒誅元惡，宸慈恤遠黎。", "五方思寄刃，萬姓喜然臍。", "自幼輸丹懇，何嘗玷白圭。", "承言竄遐魅，雪枉間深狴。", "墳壠無由謁，京華豈重躋。", "炎方誰謂廣，地盡覺天低。", "百卉雜殊怪，昆蟲理賴暌。", "閉藏元不蟄，搖落反生荑。", "瘧瘴因茲苦，窮愁益復迷。", "火雲蒸毒霧，陽雨濯陰霓。", "周乘安交趾，王恭輯畫題。", "少寬窮涸鮒，猶愍觸藩羝。", "配宅隣州廨，斑苗接野畦。", "山空聞鬬象，江靜見游犀。", "翰墨思諸季，裁縫憶老妻。", "小兒應離褓，幼女未攀筓。", "夢蝶翻無定，蓍龜詎有倪。", "誰能竟此曲，曲盡氣酸嘶。"]'),
('bc4a4c2d-38b3-457e-bdb8-6f3bcb3b63b5','答魑魅代書寄家人','沈佺期','唐','唐诗','tang','','[]','魑魅來相問，君何失帝鄉。',288,'全唐诗/poet.tang.5000.json','["魑魅來相問，君何失帝鄉。", "龍鍾辭北闕，蹭蹬守南荒。", "覽鏡憐雙鬢，沾衣惜萬行。", "抱愁那去國，將老更垂裳。", "影答余他歲，恩私宦洛陽。", "三春給事省，五載尚書郎。", "黃閤遊鸞署，青縑御史香。", "扈巡行太液，陪宴坐明光。", "渭北昇高苑，河南祓禊場。", "煙花恆獻賦，泉石每稱觴。", "暇日從休澣，高車暎道傍。", "迎賓就丞相，選士謁昭王。", "侍寵言猶得，承歡謂不忘。", "一朝貽厚譴，五宅竟同防。", "兇豎曾軀策，權豪豈易當。", "款顏因侍從，接武在文章。", "且懼威非贙，寧知心是狼。", "身猶納履誤，情爲覆盆傷。", "可歎緣成業，非關行昧藏。", "喜逢今改旦，正朔復歸唐。", "河讖隨龍馬，天書逐鳳皇。", "朝容欣舊則，宸化美初綱。", "告善雕旌建，收冤錦斾張。", "宰臣更獻納，郡守各明揚。"]'),
('f3cb5c79-1406-41cb-8744-eb77c22ceb77','度安海入龍編','沈佺期','唐','唐诗','tang','','[]','我來交趾郡，南與貫胸連。',120,'全唐诗/poet.tang.5000.json','["我來交趾郡，南與貫胸連。", "四氣分寒少，三光置日偏。", "尉佗曾馭國，翁仲久遊泉。", "邑屋遺甿在，魚鹽舊產傳。", "越人遙捧翟，漢將下看鳶。", "北斗崇山挂，南風漲海牽。", "別離頻破月，容鬢驟催年。", "昆弟推由命，妻孥割付緣。", "夢來魂尚擾，愁委疾空纏。", "虛道崩城淚，明心不應天。"]'),
('c577ccc9-300b-4231-a774-ef6d4f615558','從崇山向越常','沈佺期','唐','唐诗','tang','','[]','朝發崇山下，暮坐越常陰。',96,'全唐诗/poet.tang.5000.json','["朝發崇山下，暮坐越常陰。", "西從杉谷度，北上竹溪深。", "竹溪道明水，杉谷古崇岑。", "差池將不合，繚繞復相尋。", "桂葉藏金嶼，藤花閉石林。", "天窗虛的的，雲竇下沈沈。", "造化功偏厚，真仙跡每臨。", "豈徒探怪異，聊欲緩歸心。"]'),
('0759e3b4-d0d9-448d-8687-3a549bf89a53','哭蘇眉州崔司業二公','沈佺期','唐','唐诗','tang','','[]','渙汗天中發，伶俜海外旋。',216,'全唐诗/poet.tang.5000.json','["渙汗天中發，伶俜海外旋。", "長沙遇太守，問舊幾人全。", "國寶亡雙傑，天才喪兩賢。", "大名齊弱歲，高德並中年。", "禮樂羊叔子，文章王仲宣。", "相看尚玄鬢，相次入黃泉。", "流放蠻陬闊，鄉關帝里偏。", "親朋雲霧擁，生死歲時傳。", "崔昔揮宸翰，蘇嘗濟巨川。", "絳衣陪下列，黃閤謬差肩。", "及此俱冥昧，云誰敘播遷。", "隼輿懷舊轍，鱣館想虛筵。", "家愛方休杵，皇慈更撤縣。", "銘旌西蜀路，騎吹北邙田。", "隴樹應秋矣，江帆故杳然。", "罷琴明月夜，留劒白雲天。", "涕泗湘潭水，淒涼衡嶠煙。", "古來修短分，神理竟難筌。"]'),
('008c5fd9-9ad5-4a28-93cc-6bfd11f05338','哭道土劉無得','沈佺期','唐','唐诗','tang','','[]','聞有玄都客，成仙不易祈。',96,'全唐诗/poet.tang.5000.json','["聞有玄都客，成仙不易祈。", "蓬萊向清淺，桃杏欲芳菲。", "縮地黃泉出，昇天白日飛。", "少微星夜落，高掌露朝晞。", "吐甲龍應出，銜符鳥自歸。", "國人思負局，天子惜被衣。", "花月留丹洞，琴笙閣翠微。", "嗟來子桑扈，爾獨返於幾。"]'),
('1b474cf5-b27b-462b-8785-c5a2d84147e1','寒食','沈佺期','唐','唐诗','tang','','["\u5bd2\u98df\u8282", "\u5b64\u72ec"]','普天皆滅焰，匝地盡藏煙。',24,'全唐诗/poet.tang.5000.json','["普天皆滅焰，匝地盡藏煙。", "不知何處火？來就客心然。"]'),
('bd74ae2a-94ae-4f9c-a276-a426fe90d49f','回波詞','沈佺期','唐','唐诗','tang','','[]','回波爾時佺期，流向嶺外生歸。',28,'全唐诗/poet.tang.5000.json','["回波爾時佺期，流向嶺外生歸。", "身名已蒙齒錄，袍笏未復牙緋。"]'),
('9c8aa5a5-27a5-4e32-a650-61ace91fdd6c','上巳日祓禊渭濱應制','沈佺期','唐','唐诗','tang','','[]','寶馬香車清渭濱，紅桃碧柳禊堂春。',32,'全唐诗/poet.tang.5000.json','["寶馬香車清渭濱，紅桃碧柳禊堂春。", "皇情尚憶垂竿佐，天祚先呈捧劒人。"]'),
('df1c3ef2-b6f5-443d-95aa-b78f7fa51afc','奉和幸韋嗣立山莊應制','沈佺期','唐','唐诗','tang','','[]','東山朝日翠屏開，北闕晴空綵仗來。',32,'全唐诗/poet.tang.5000.json','["東山朝日翠屏開，北闕晴空綵仗來。", "喜遇天文七曜動，少微今夜近三台。"]'),
('5b6ad252-a63c-40c6-bea4-52b2157a4f87','夜宴安樂公主宅','沈佺期','唐','唐诗','tang','','[]','濯龍門外主家親，鳴鳳樓中天上人。',32,'全唐诗/poet.tang.5000.json','["濯龍門外主家親，鳴鳳樓中天上人。", "自有金杯迎甲夜，還將綺席代陽春。"]'),
('dcaded9d-ce29-4afe-bca4-f4521f85bd71','苑中遇雪應制','沈佺期','唐','唐诗','tang','','[]','北闕彤雲掩曙霞，東風吹雪舞仙家。',32,'全唐诗/poet.tang.5000.json','["北闕彤雲掩曙霞，東風吹雪舞仙家。", "瓊章定少千人和，銀樹長芳六出花。"]'),
('bb771da6-427d-437a-856a-4a7826c74b1a','餞唐永昌','沈佺期','唐','唐诗','tang','','[]','洛陽舊有神明宰，輦轂由來天地中。',32,'全唐诗/poet.tang.5000.json','["洛陽舊有神明宰，輦轂由來天地中。", "餘邑政成何足貴，因君取則四方同。"]'),
('4002135f-389e-4273-a3f3-979c10422ffc','獄中聞駕幸長安二首 一','沈佺期','唐','唐诗','tang','','[]','傳聞聖旨向秦京，誰念羈囚滯洛城。',32,'全唐诗/poet.tang.5000.json','["傳聞聖旨向秦京，誰念羈囚滯洛城。", "扈從由來是方朔，爲申冤氣在長平。"]'),
('315cc2e1-f329-425d-a2b0-e3f4994110c1','獄中聞駕幸長安二首 二','沈佺期','唐','唐诗','tang','','[]','無事今朝來下獄，誰期十月是橫河。',32,'全唐诗/poet.tang.5000.json','["無事今朝來下獄，誰期十月是橫河。", "君看鷹隼俱堪擊，爲報蜘蛛收網羅。"]'),
('5909e17d-a969-44ef-8e09-383f21387492','邙山','沈佺期','唐','唐诗','tang','','[]','北邙山上列墳塋，萬古千秋對洛城。',32,'全唐诗/poet.tang.5000.json','["北邙山上列墳塋，萬古千秋對洛城。", "城中日夕歌鐘起，山上唯聞松栢聲。"]'),
('a1016bc1-1af5-4bf3-862d-98bf3406c2aa','句','沈佺期','唐','唐诗','tang','','[]','周原五稼起，雲海百川歸。',24,'全唐诗/poet.tang.5000.json','["周原五稼起，雲海百川歸。", "願此零陵燕，長隨征斾飛。"]'),
('89491143-3bbb-4ad5-8df9-9515ea941015','陪張燕公登南樓','趙冬曦','唐','唐诗','tang','','[]','抑鬱何以歡，陰氛亦登望。',48,'全唐诗/poet.tang.5000.json','["抑鬱何以歡，陰氛亦登望。", "孤島輕霧裏，行舟白波上。", "目勞西北雲，心醉東南嶂。", "昔日青谿子，胡然此無狀。"]'),
('5c4020cb-b7e6-42dc-9f05-e153d36a755d','酬燕公出湖見寄','趙冬曦','唐','唐诗','tang','','[]','綸綍有成命，旌麾不可攀。',96,'全唐诗/poet.tang.5000.json','["綸綍有成命，旌麾不可攀。", "湘川朝目斷，荆闕夕波還。", "果枉東瞻唱，興言夕放閑。", "攜琴仙洞中，置酒㴩湖上。", "芳景恣行樂，謫居忽如忘。", "聚散本相因，離情自悲悵。", "鸞翮非常戢，鵬天會昭曠。", "永懷宛洛游，曾是彈冠望。"]'),
('ad12bb3c-dbe8-4c41-9ebe-da5b313f889e','奉和張燕公早霽南樓','趙冬曦','唐','唐诗','tang','','[]','方曙躋南樓，凭軒肆遐矚。',120,'全唐诗/poet.tang.5000.json','["方曙躋南樓，凭軒肆遐矚。", "物華蕩暄氣，春景媚晴旭。", "川霽湘山孤，林芳楚郊縟。", "列巖重疊翠，遠岸逶迤綠。", "風帆摩天垠，魚艇散彎曲。", "鴻歸鶴舞送，猨叫鶯聲續。", "羣動皆熙熙，噫予獨羈束。", "常欽才子意，忌鵩傷踡跼。", "雅尚騷人文，懷沙何迫促。", "未知二賢意，去矣從所欲。"]'),
('0f488ad9-8a17-4df1-b00f-fbfee7acfebd','㴩湖作','趙冬曦','唐','唐诗','tang','','[]','三湖返入兩山間，畜作㴩湖彎復彎。',176,'全唐诗/poet.tang.5000.json','["三湖返入兩山間，畜作㴩湖彎復彎。", "暑雨奔流潭正滿，微霜及潦水初還。", "水還波卷谿潭涸，綠草芊芊岸嶄岝。", "適來飛櫂共迴旋，已復揚鞭恣行樂。", "道旁耆老步躚躚，楚言茲事不知年。", "試就湖邊披草徑，莫疑東海變桑田。", "君訝今時盡陵陸，我看明歲更淪漣。", "來今自昔無終始，人事迴環常若是。", "應思闕下聲華日，誰謂江潭旅遊子。", "初貞正喜固當然，往蹇來譽宜可俟。", "盈虛用舍輪輿旋，勿學靈均遠問天。"]'),
('97cffb75-465a-42fd-a6af-7e36e99fa979','和燕公岳州山城','趙冬曦','唐','唐诗','tang','','[]','爲吏恩猶舊，投沙惠此蒙。',48,'全唐诗/poet.tang.5000.json','["爲吏恩猶舊，投沙惠此蒙。", "江邊悠爾處，泗上宛然同。", "訪道精言合，論經大義通。", "鳴琴有真氣，況已沐清風。"]'),
('8d29893e-e945-4b03-a082-65fb9149ed69','和尹懋秋夜遊㴩湖二首 一','趙冬曦','唐','唐诗','tang','','[]','政理常多暇，方舟此泝洄。',48,'全唐诗/poet.tang.5000.json','["政理常多暇，方舟此泝洄。", "吹笙虛洞荅，舉楫便風催。", "山暗雲猶辨，潭幽月稍來。", "清谿無數曲，未盡莫先迴。"]'),
('56be5791-18a9-4829-9e5b-ced1593803fa','和尹懋秋夜遊㴩湖二首 二','趙冬曦','唐','唐诗','tang','','[]','煙靄夕微蒙，幽灣賞未窮。',48,'全唐诗/poet.tang.5000.json','["煙靄夕微蒙，幽灣賞未窮。", "艤舟待初月，褰幌招遠風。", "鶴聲聒前浦，漁火明暗叢。", "東山雲壑意，不謂爾來同。"]'),
('b279486b-e374-46a1-bbf6-4827c2c172cf','陪燕公遊㴩湖','趙冬曦','唐','唐诗','tang','','[]','江上多山水，招要步馬來。',48,'全唐诗/poet.tang.5000.json','["江上多山水，招要步馬來。", "琴將天籟合，酒共鳥聲催。", "巖坐攀紅藥，谿行愛綠苔。", "所懷非此地，遊望亦裴回。"]'),
('1ffc70fa-ee83-4148-800a-2eb6203e14d4','荅張燕公翻著葛巾見呈之作','趙冬曦','唐','唐诗','tang','','[]','美酒值芳春，醒餘氣益真。',48,'全唐诗/poet.tang.5000.json','["美酒值芳春，醒餘氣益真。", "降歡時倒履，乘興偶翻巾。", "徐榻思方建，左車理自均。", "傲然歌一曲，一醉濯纓人。"]'),
('82badfaa-a20f-4946-9171-f89b314d8316','奉荅燕公','趙冬曦','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','語別意淒淒，零陵湘水西。',48,'全唐诗/poet.tang.5000.json','["語別意淒淒，零陵湘水西。", "佳人金谷返，愛子洞庭迷。", "舊館逢花發，他山值鳥啼。", "江天千里望，誰見綠蘋齊。"]'),
('4e096f75-70b8-43b3-86e0-ff23b282d155','奉和聖製同二相已下羣官樂遊園宴','趙冬曦','唐','唐诗','tang','','[]','爽塏三秦地，芳華二月初。',72,'全唐诗/poet.tang.5000.json','["爽塏三秦地，芳華二月初。", "酺承奠璧罷，宴是合錢餘。", "柳翠垂堪結，桃紅卷欲舒。", "從容會鵷鷺，延曼戲龍魚。", "喜氣流雲物，歡聲浹里閭。", "聖恩將報厚，請述記言書。"]'),
('fd656857-3054-4245-a998-e7daa58fc6e5','奉和聖製荅張說扈從南出雀鼠谷','趙冬曦','唐','唐诗','tang','','[]','軒轅應順動，力牧正趨陪。',72,'全唐诗/poet.tang.5000.json','["軒轅應順動，力牧正趨陪。", "道合殷爲礪，時行楚有材。", "省方西禮設，振旅北京迴。", "地理分中壤，天文照上臺。", "寒依汾谷去，春入晉郊來。", "竊比康衢者，長歌仰大哉。"]'),
('16c8d29a-1765-4b57-9d0e-6a1755a741a7','奉和聖製送張說上集賢學士賜宴賦得蓮字','趙冬曦','唐','唐诗','tang','','[]','淺術方觀海，深恩忽見天。',72,'全唐诗/poet.tang.5000.json','["淺術方觀海，深恩忽見天。", "學開丹殿籍，名與石渠賢。", "良輔膺休命，微生謬采甄。", "春餘仍哢鳥，夏近未舒蓮。", "牋札來宸禁，衣冠集詔筵。", "史臣知醉德，欲記升中年。"]'),
('8c365dba-2125-4979-b810-c5fca99a154b','奉荅燕公','趙冬曦','唐','唐诗','tang','','[]','誰道零陵守，東過此地遊。',72,'全唐诗/poet.tang.5000.json','["誰道零陵守，東過此地遊。", "友僚同省閣，昆弟接荆州。", "我逐江潭鴈，君隨海上鷗。", "屢傷神氣阻，久別鬢毛秋。", "疑嶺春應徧，陽臺雨欲收。", "主人情未盡，高駕少淹留。"]'),
('c5462333-23d9-4459-b674-5d11858c800c','陪張燕公行郡竹籬','趙冬曦','唐','唐诗','tang','','[]','良臣乃國寶，麾守去承明。',72,'全唐诗/poet.tang.5000.json','["良臣乃國寶，麾守去承明。", "外戶人無閉，浮江獸已行。", "隨來晉盜逸，民化蜀風清。", "郛郭從彝典，州閭荷德聲。", "小人投天涯，流落巴丘城。", "所賴中和作，優游鑿與耕。"]'),
('a7b13d1c-1a3a-4851-8491-0e0f98fac97d','和燕公別㴩湖','趙冬曦','唐','唐诗','tang','','[]','南湖美泉石，君子翫幽奇。',72,'全唐诗/poet.tang.5000.json','["南湖美泉石，君子翫幽奇。", "灣澳陪臨泛，巖峿共踐窺。", "秋風赬桂竦，春景綠楊垂。", "郢路委分竹，湘濱擁去麾。", "枉帆懷勝賞，留景惜差池。", "水木且不棄，情由良可知。"]'),
('8173fbc6-3427-4723-a388-d974fd193c60','奉酬燕公見歸田賦垂贈之作','趙冬曦','唐','唐诗','tang','','[]','窮鳥嬰籠綴，孤飛任播遷。',84,'全唐诗/poet.tang.5000.json','["窮鳥嬰籠綴，孤飛任播遷。", "鷦鷯王佐用，復此挫沖天。", "楚雲何掩鬱，湘水亦迴邅。", "懷哉愧木鴈，忽爾枉蘭荃。", "愈疾同枚叔，銷憂比仲宣。", "歸途書可畏，弱操石猶堅。", "覆載雖云廣，涔陽直塊然。"]'),
('6cfa3832-a852-4780-b995-72e10c724b05','和張燕公耗磨日飲 一','趙冬曦','唐','唐诗','tang','','[]','上月今朝減，流傳耗磨辰。',24,'全唐诗/poet.tang.5000.json','["上月今朝減，流傳耗磨辰。", "還將不事事，同醉俗中人。"]'),
('816b98a8-2757-4645-b931-e2ee9ceffc9a','和張燕公耗磨日飲 二','趙冬曦','唐','唐诗','tang','','[]','春來半月度，俗忌一朝閑。',24,'全唐诗/poet.tang.5000.json','["春來半月度，俗忌一朝閑。", "不酌他鄉酒，無堪對楚山。"]'),
('7b07f0f8-43aa-46a2-9169-ead6a5715141','奉陪張燕公登南樓','尹懋','唐','唐诗','tang','','[]','君子每垂眷，江山共流眄。',48,'全唐诗/poet.tang.5000.json','["君子每垂眷，江山共流眄。", "水遠林外明，巖近霧中見。", "終日西北望，何處是京縣。", "屢登高春臺，徒使淚如霰。"]'),
('c86e65c7-7639-401b-a6e6-d02220a9c88b','秋夜陪張丞相趙侍御游㴩湖二首 一','尹懋','唐','唐诗','tang','','[]','熊軾巴陵地，鷁舟湘水潯。',48,'全唐诗/poet.tang.5000.json','["熊軾巴陵地，鷁舟湘水潯。", "江山與勢遠，泉石自幽深。", "杳靄入天壑，冥茫見道心。", "超然無俗事，清宴有空林。"]'),
('b8f5e043-c0d9-430b-94fd-9f608d05f423','秋夜陪張丞相趙侍御游㴩湖二首 二','尹懋','唐','唐诗','tang','','[]','江上饒奇山，巑羅雲水間。',48,'全唐诗/poet.tang.5000.json','["江上饒奇山，巑羅雲水間。", "風和樹色雜，苔古石文斑。", "巴俗將千溠，㴩湖凡幾灣。", "嬉遊竟不盡，乘月汎舟還。"]'),
('e832479a-ea3f-4242-9b05-e298bbcda7fc','同燕公汎洞庭','尹懋','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','風光淅淅草中飄，日彩熒熒水上搖。',32,'全唐诗/poet.tang.5000.json','["風光淅淅草中飄，日彩熒熒水上搖。", "幸奏瀟湘雲壑意，山旁容與動仙橈。"]'),
('5a9c5446-7f0e-4e81-8f25-2e3a5f19b7ab','奉荅燕公','王琚','唐','唐诗','tang','','[]','郡遠途且艱，宜悲良自得。',144,'全唐诗/poet.tang.5000.json','["郡遠途且艱，宜悲良自得。", "胡爲心獨爾，惠好在南國。", "亦既清顏披，冏然良願克。", "與君蘭時會，羣物如藻飾。", "煙景惜歡賞，雲山起翰墨。", "接藝奇思微，偶談玄言直。", "永日不知倦，逾旬猶謂亟。", "如何酌離尊，移櫂巴城側。", "浦口勞長望，舟中獨太息。", "疾風吹飛帆，倏忽南與北。", "目盡不復見，懷哉無終極。", "唯當衡峰上，遙辨湖水色。"]'),
('85f57df7-3297-4a4f-b78e-7e8e20ae0b6e','美女篇','王琚','唐','唐诗','tang','','[]','東鄰美女實名倡，絕代容華無比方。',192,'全唐诗/poet.tang.5000.json','["東鄰美女實名倡，絕代容華無比方。", "濃纖得中非短長，紅素天生誰飾妝。", "桂樓椒閣木蘭堂，繡戶雕軒文杏梁。", "屈曲屏風繞象牀，萎蕤翠帳綴香囊。", "玉臺龍鏡洞徹光，金爐沈煙酷烈芳。", "遙聞行佩音鏘鏘，含嬌欲笑出洞房。", "二八三五閨心切，褰簾捲幔迎春節。", "清歌始發詞怨咽，鳴琴一弄心斷絕。", "借問哀怨何所爲，盛年情多心自悲。", "須臾破顏倏斂態，一悲一喜倂相宜。", "何能見此不注心，惜無媒氏爲傳音。", "可憐盈盈直千金，誰家君子爲藁砧。"]'),
('f54f7fc8-8f1f-407a-81c7-1a1a3507890d','自荆湖入朝至岳陽奉別張燕公','王琚','唐','唐诗','tang','','["\u957f\u6c5f"]','五載朝天子，三湘逢舊僚。',48,'全唐诗/poet.tang.5000.json','["五載朝天子，三湘逢舊僚。", "扁舟方輟櫂，清論遂終朝。", "遠樹煙間沒，長江地際遙。", "帝城馳夢想，歸帆滿風飆。"]'),
('76e019f8-3fb8-4fd4-8e91-43ee9648455d','游㴩湖上寺','王琚','唐','唐诗','tang','','[]','春山臨遠壑，水木自幽清。',48,'全唐诗/poet.tang.5000.json','["春山臨遠壑，水木自幽清。", "夙昔懷微尚，茲焉一放情。", "雲間聽弄鳥，煙上摘初英。", "地僻方無悶，逾知道思精。"]'),
('2c741285-0d51-406d-b1ce-af12a1c7deb9','和張燕公湘中九日登高','陰行先','唐','唐诗','tang','','["\u5199\u666f", "\u6292\u60c5", "\u767b\u9ad8", "\u91cd\u9633\u8282"]','重陽初啟節，無射正飛灰。',48,'全唐诗/poet.tang.5000.json','["重陽初啟節，無射正飛灰。", "寂寞風蟬至，連翩霜鴈來。", "山棠紅葉下，岸菊紫花開。", "今日桓公座，多愧孟嘉才。"]'),
('e35d7274-f338-4c0c-a42e-b1717d4d3e59','奉別張岳州說二首 一','王熊','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','長沙辭舊國，洞庭逢故人。',48,'全唐诗/poet.tang.5000.json','["長沙辭舊國，洞庭逢故人。", "薰蘭敦久要，披霧轉相親。", "歲月空嗟老，江山不惜春。", "忽聞黃鶴曲，更作白頭新。"]'),
('6b479f86-38e9-470b-aa81-2cae585e99aa','奉別張岳州說二首 二','王熊','唐','唐诗','tang','','[]','平生共風月，倏忽間山川。',48,'全唐诗/poet.tang.5000.json','["平生共風月，倏忽間山川。", "不期交淡水，暫得欵忘年。", "興逸方罷釣，帆開欲解船。", "離心若危斾，朝夕爲君懸。"]'),
('00e003b2-2fa3-4a7c-acbe-08b6a0b64da7','入朝別張燕公','梁知微','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','華容佳山水，之子厭承明。',96,'全唐诗/poet.tang.5000.json','["華容佳山水，之子厭承明。", "符竹紆小郡，江湖被德聲。", "三年計吏入，路指巴丘城。", "鳧舟纔結纜，騶駕已相迎。", "別離他鄉酒，委曲故人情。", "孤嶼早煙薄，長波晚氣清。", "辛勤方遠騖，勝賞屢難幷。", "迴瞻洞庭浦，日暮愁雲生。"]'),
('b11c0a85-b5f4-4f3f-b2b1-37f1246c6347','桐竹贈張燕公','李伯魚','唐','唐诗','tang','','[]','北竹青桐北，南桐綠竹南。',48,'全唐诗/poet.tang.5000.json','["北竹青桐北，南桐綠竹南。", "竹林君早愛，桐樹我初貪。", "鳳栖桐不媿，鳳食竹何慙。", "棲食更如此，餘非鳳所堪。"]'),
('603c3920-60eb-470b-820b-b6488c18441e','正朝上左相張燕公','楊重玄','唐','唐诗','tang','','[]','歲去愁終在，春還命不來。',24,'全唐诗/poet.tang.5000.json','["歲去愁終在，春還命不來。", "長吁問丞相，東閣幾時開。"]'),
('c4ae0646-a2ad-4d64-8a65-714e916c4774','道峽似巫山','朱使欣','唐','唐诗','tang','','[]','江如曉天靜，石似暮雲張。',48,'全唐诗/poet.tang.5000.json','["江如曉天靜，石似暮雲張。", "征帆一流覽，宛若巫山陽。", "楚客思歸路，秦人謫異鄉。", "猨鳴孤月夜，再使淚霑裳。"]'),
('de131cd3-20c4-496b-9b97-d52fc86fe6e2','巫山高','張循之','唐','唐诗','tang','','[]','巫山高不極，合沓狀奇新。',48,'全唐诗/poet.tang.5000.json','["巫山高不極，合沓狀奇新。", "暗谷疑風雨，陰崖若鬼神。", "月明三峽曉，潮滿九江春。", "爲問陽臺客，應知入夢人。"]'),
('867e0cbb-0c17-4792-aea5-3f40e7b1c2b9','送泉州李使君之任','張循之','唐','唐诗','tang','','[]','傍海皆荒服，分符重漢臣。',48,'全唐诗/poet.tang.5000.json','["傍海皆荒服，分符重漢臣。", "雲山百越路，市井十洲人。", "執玉來朝遠，還珠入貢頻。", "連年不見雪，到處即行春。"]'),
('33a94fdf-32d2-4fad-b42d-6a7d209381ba','長門怨','張循之','唐','唐诗','tang','','[]','長門落景盡，洞房秋月明。',48,'全唐诗/poet.tang.5000.json','["長門落景盡，洞房秋月明。", "玉階草露積，金屋網塵生。", "妾妬今應改，君恩惜未平。", "寄語臨邛客，何時作賦成。"]'),
('488868f6-d037-45bb-86e1-8f89d2688159','巫山','張循之','唐','唐诗','tang','','[]','流景一何速，年華不可追。',24,'全唐诗/poet.tang.5000.json','["流景一何速，年華不可追。", "解佩安所贈，怨咽空自悲。"]'),
('64d3d86d-8f57-4485-81a1-3c856ba259e6','送王汶宰江陰','張循之','唐','唐诗','tang','','[]','郡北乘流去，花間竟日行。',48,'全唐诗/poet.tang.5000.json','["郡北乘流去，花間竟日行。", "海魚朝滿市，江鳥夜喧城。", "讓酒非關病，援琴不在聲。", "應緣五斗米，數日滯淵明。"]'),
('652c8519-b075-4ddd-b6ed-af260588d7ec','婺州留別鄧使君','張循之','唐','唐诗','tang','','[]','西掖馳名久，東陽出守時。',48,'全唐诗/poet.tang.5000.json','["西掖馳名久，東陽出守時。", "江山婺女分，風月隱侯詩。", "別恨雙溪急，留歡五馬遲。", "迴舟暎沙嶼，未遠剩相思。"]'),
('406881a1-3678-4187-a07d-ef4cba5a2b27','祭汾陰樂章 太和','王晙','唐','唐诗','tang','','[]','於穆聖皇，六葉重光。',40,'全唐诗/poet.tang.5000.json','["於穆聖皇，六葉重光。", "太原刻頌，后土疏場。", "寶鼎呈符，歊雲孕祥。", "禮樂備矣，降福穰穰。"]'),
('88f7cb25-d675-46cc-88f6-6a9e612ddd2b','大堤曲','張柬之','唐','唐诗','tang','','[]','南國多佳人，莫若大堤女。',48,'全唐诗/poet.tang.5000.json','["南國多佳人，莫若大堤女。", "玉牀翠羽帳，寶袜蓮花距。", "魂處自目成，色授開心許。", "迢迢不可見，日暮空愁予。"]'),
('8c7d1c00-c6ee-4b78-bbbb-8d58d55dd27c','東飛伯勞歌','張柬之','唐','唐诗','tang','','[]','青田白鶴丹山鳳，婺女姮娥兩相送。',80,'全唐诗/poet.tang.5000.json','["青田白鶴丹山鳳，婺女姮娥兩相送。", "誰家絕世綺帳前，豔粉紅脂映寶鈿。", "窈窕玉堂褰翠幙，參差繡戶懸珠箔。", "絕世三五愛紅妝，冶袖長裙蘭麝香。", "春去花枝俄易改，可歎年光不相待。"]'),
('80ad2bc3-dd03-48a3-aa9e-3001c0448b40','出塞','張柬之','唐','唐诗','tang','','[]','俠客重恩光，驄馬飾金裝。',132,'全唐诗/poet.tang.5000.json','["俠客重恩光，驄馬飾金裝。", "瞥聞傳羽檄，馳突救邊荒。", "歙野山川動，囂天旌斾揚。", "吳鉤明似月，楚劒利如霜。", "電斷衝胡塞，風飛出洛陽。", "轉戰磨笄俗，橫行戴斗鄉。", "手擒郅支長，面縛谷蠡王。", "將軍占太白，小婦怨流黃。", "騕褭青絲騎，娉婷紅粉妝。", "三春鶯度曲，八月鴈成行。", "誰堪坐愁思，羅袖拂空牀。"]'),
('31d6ef79-4aec-4e95-aa6e-6ab79a1b45a0','與國賢良夜歌二首 一','張柬之','唐','唐诗','tang','','[]','柳臺臨新堰，樓堞相重複。',24,'全唐诗/poet.tang.5000.json','["柳臺臨新堰，樓堞相重複。", "窈窕鳳皇姝，傾城復傾國。"]'),
('425fe4c2-d80b-461b-b7ad-4cb8b865400e','與國賢良夜歌二首 二','張柬之','唐','唐诗','tang','','[]','杏間花照灼，樓上月裴回。',24,'全唐诗/poet.tang.5000.json','["杏間花照灼，樓上月裴回。", "帶嬌移玉柱，含笑捧金杯。"]'),
('e31997de-b936-45db-9463-20c0e1a44693','詠屏風','袁恕己','唐','唐诗','tang','','[]','綺閣雲霞滿，芳林草樹新。',48,'全唐诗/poet.tang.5000.json','["綺閣雲霞滿，芳林草樹新。", "鳥驚疑欲曙，花笑不關春。", "山對彈琴客，谿留垂釣人。", "請看車馬客，行處有風塵。"]'),
('25de451b-7c61-45d1-8291-061bdfc5e166','書懷','劉幽求','唐','唐诗','tang','','[]','心爲明時盡，君門尚不容。',24,'全唐诗/poet.tang.5000.json','["心爲明時盡，君門尚不容。", "田園迷徑路，歸去欲何從。"]'),
('fd116050-1750-4b13-915c-fe37fbe09212','流所贈張錫','章玄同','唐','唐诗','tang','','[]','黃葉因風下，甘從洛浦隈。',24,'全唐诗/poet.tang.5000.json','["黃葉因風下，甘從洛浦隈。", "白雲何所爲，還出帝鄉來。"]'),
('a61f104d-9874-46e5-b674-0262289ea62f','臨高臺','王易從','唐','唐诗','tang','','[]','漢主事[祁]連，良人在高闕。',50,'全唐诗/poet.tang.5000.json','["漢主事[祁]連，良人在高闕。", "空臺寂已暮，愁坐變容髪。", "汎豔春幌風，裴回秋戶月。", "可憐軍書斷，空使流芳歇。"]'),
('9079b311-c980-4a27-9232-317b8ac1804d','初出京邑有懷舊林','盧僎','唐','唐诗','tang','','[]','賦生期獨得，素業守微班。',134,'全唐诗/poet.tang.5000.json','["賦生期獨得，素業守微班。", "外忝文學知，鴻漸鵷鷺間。", "內傾水木趣，築室依近山。", "晨趨天日[晏]，夕臥江海閑。", "松風生坐隅，仙禽舞亭灣。", "曙雲林下客，霽月池上顏。", "雖曰坐郊園，靜默非人寰。", "時步蒼龍闕，寧異白雲關。", "語濟豈時顧，默善忘世攀。", "世網余何觸，天涯謫南蠻。", "回首思洛陽，喟然悲貞艱。"]'),
('be632a1d-3ed9-4a6d-84b8-5f8013d380eb','稍秋曉坐閣遇舟東下揚州既事寄上族父江陽令','盧僎','唐','唐诗','tang','','[]','虎嘯山城晚，猨鳴江樹秋。',288,'全唐诗/poet.tang.5000.json','["虎嘯山城晚，猨鳴江樹秋。", "紅林架落照，青峽送歸流。", "歸流赴淮海，征帆下揚州。", "族父江陽令，盛業繼前修。", "文掩崔亭伯，德齊陳太丘。", "時哉惜未與，千載且爲儔。", "憶昔山陽會，長懷東上游。", "稱觴阮林下，賦雪謝庭幽。", "道濃禮自略，氣舒文轉遒。", "高情薄雲漢，酣態坐芳洲。", "接席復連軫，出入陪華輈。", "獨善與兼濟，語默奉良籌。", "歲月歡無已，風雨暗颼颼。", "掌憲時持節，爲邦邈海頭。", "子人惠雖樹，蒼生望且留。", "微躬趨直道，神甸忝清猷。", "仙臺適西步，蠻徼忽南浮。", "宇內皆安樂，天涯獨遠投。", "忠信徒堅仗，神明豈默詶。", "觀生海漫漫，稽命天悠悠。", "雲昏巴子峽，月遠吳王樓。", "懷昔明不寐，悲令歲屬周。", "喟無排雲翮，暫得抒離憂。", "空灑霑紅淚，萬里逐行舟。"]'),
('434b1042-0a24-444d-9727-35c3143c8420','讓帝挽歌詞二首 一','盧僎','唐','唐诗','tang','','[]','泰伯玄風遠，延州德讓行。',48,'全唐诗/poet.tang.5000.json','["泰伯玄風遠，延州德讓行。", "闔棺追大節，樹羽冊鴻名。", "地戶迎天仗，皇階失帝兄。", "還聞漢明主，遺劒泣東平。"]'),
('66f7f683-f9ff-4a8e-827b-06dd38e6d140','讓帝挽歌詞二首 二','盧僎','唐','唐诗','tang','','[]','朝天馳馬絕，冊帝□宮祖。',48,'全唐诗/poet.tang.5000.json','["朝天馳馬絕，冊帝□宮祖。", "恍惚陵廟新，蕭條池館古。", "萬化一朝空，哀樂此路同。", "西園有明月，修竹韻悲風。"]'),
('194c5bec-15ff-471f-be56-43031e7b0581','十月梅花書贈','盧僎','唐','唐诗','tang','','["\u6292\u60c5", "\u53d9\u4e8b", "\u8bae\u8bba", "\u5199\u666f"]','君不見巴鄉氣候與華別，年年十月梅花發。',195,'全唐诗/poet.tang.5000.json','["君不見巴鄉氣候與華別，年年十月梅花發。", "上苑今應雪作花，寧知此地花爲雪。", "自從遷播落黔巴，三見江上開新花。", "故園風花虛洛汭，窮峽凝雪度歲華。", "花情縱似河陽好，客心倍傷邊候早。", "春候颯驚樓上梅，霜威未落江潭草。", "江水侵天去不還，樓花覆簾空坐攀。", "一向花前看白髮，幾回夢裏憶紅顏。", "紅顏白髮雲泥改，何異桑田移碧海。", "却想華年故國時，唯餘一片空心在。", "空心弔影向誰陳，雲臺仙閣舊遊人。", "儻知巴樹連冬發，應憐南國氣長春。"]'),
('52d5b97f-ac02-4d54-a6fa-8c1816acce1b','歲晚還京臺望城闕成口號先贈交親','盧僎','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6292\u60c5"]','紫陌開行樹，朱城出晚霞。',48,'全唐诗/poet.tang.5000.json','["紫陌開行樹，朱城出晚霞。", "猶憐慣去國，疑是夢還家。", "風弱知催柳，林青覺待花。", "交親望歸騎，幾處擁年華。"]'),
('01dcc878-872c-40de-917f-7ccfcb542411','送蘇八給事出牧徐州用芳韻','盧僎','唐','唐诗','tang','','[]','金鼎屬元方，璅闈連季常。',48,'全唐诗/poet.tang.5000.json','["金鼎屬元方，璅闈連季常。", "畏盈聊出守，分命乃維良。", "曉騎辭朝遠，春帆向楚常。", "賢哉謙自牧，天下詠餘芳。"]'),
('3b4d12bd-9762-4d5e-a1ba-c625cc4099ea','上幸皇太子新院應制','盧僎','唐','唐诗','tang','','[]','佳氣曉蔥蔥，乾行入震宮。',72,'全唐诗/poet.tang.5000.json','["佳氣曉蔥蔥，乾行入震宮。", "前星移北極，少海被南風。", "視膳銅樓下，吹笙玉座中。", "訓深家以正，義舉俗爲公。", "父子成釗合，君臣禹啓同。", "仰天歌聖道，猶愧乏雕蟲。"]'),
('0e54f3d9-f8ba-4ff9-a728-37ffe28d3a23','奉和李令扈從溫泉宮賜遊驪山韋侍郎別業','盧僎','唐','唐诗','tang','','[]','風后軒皇佐，雲峰謝客居。',96,'全唐诗/poet.tang.5000.json','["風后軒皇佐，雲峰謝客居。", "承恩來翠嶺，締賞出丹除。", "飛蓋松谿寂，清笳玉洞虛。", "窺巖詳霧豹，過水略泉魚。", "鄉入無何有，時還上古初。", "伊臯羞過狹，魏丙服麤疎。", "白雪緣情降，青霞落卷舒。", "多慚郎署在，輙繼國風餘。"]'),
('1f345258-084a-43db-99a7-d8dd716b8c7f','季冬送戶部郎中使黔府選補','盧僎','唐','唐诗','tang','','[]','握鏡均荒服，分衡得大同。',72,'全唐诗/poet.tang.5000.json','["握鏡均荒服，分衡得大同。", "徵賢一臺上，補吏五谿中。", "雨露將天澤，文章播國風。", "漢庭睽直諒，楚峽望清通。", "馬逐霜鴻漸，帆沿曉月空。", "還期鳳池拜，照耀列星宮。"]'),
('05c58936-42d2-4418-87b3-0e60e3c0b046','途中口號','盧僎','唐','唐诗','tang','','[]','抱玉三朝楚，懷書十上秦。',24,'全唐诗/poet.tang.5000.json','["抱玉三朝楚，懷書十上秦。", "年年洛陽陌，花鳥弄歸人。"]'),
('4cdad806-1bfb-41de-8adf-a7f5cef159b2','南望樓','盧僎','唐','唐诗','tang','','[]','去國三巴遠，登樓萬里春。',24,'全唐诗/poet.tang.5000.json','["去國三巴遠，登樓萬里春。", "傷心江上客，不是故鄉人。"]'),
('7333ddd5-be42-4c44-a660-130a17737f1d','臨川送別','盧僎','唐','唐诗','tang','','[]','秋郊日半隱，野樹煙初映。',24,'全唐诗/poet.tang.5000.json','["秋郊日半隱，野樹煙初映。", "風水正蕭條，那堪動離詠。"]'),
('9163650d-ca79-45ae-8349-e804904de22c','題殿前桂葉','盧僎','唐','唐诗','tang','','[]','桂樹生南海，芳香隔楚山。',24,'全唐诗/poet.tang.5000.json','["桂樹生南海，芳香隔楚山。", "今朝天上見，疑是月中攀。"]'),
('e104cb68-869c-4afb-8af9-69902118d43e','奉和受圖溫洛應制','牛鳳及','唐','唐诗','tang','','[]','八神扶玉輦，六羽警瑤谿。',60,'全唐诗/poet.tang.5000.json','["八神扶玉輦，六羽警瑤谿。", "戒道伊川北，通津澗水西。", "御圖開洛匱，刻石與天齊。", "瑞日波中上，仙禽霧裏低。", "微臣矯羽翮，抃舞接鸞鷖。"]'),
('9d9bd302-a282-4cad-8692-2340de67b223','雅琴篇','司馬逸客','唐','唐诗','tang','','[]','亭亭嶧陽樹，落落千萬尋。',354,'全唐诗/poet.tang.5000.json','["亭亭嶧陽樹，落落千萬尋。", "獨抱出雲節，孤生不作林。", "影搖綠波水，彩絢丹霞岑。", "直幹思有託，雅志期所任。", "匠者果留盼，雕斵爲雅琴。", "文以楚山玉，錯以昆吾金。", "虬鳳吐奇狀，商徵含清音。", "清音雅調感君子，一撫一弄懷知己。", "不知鍾期百年餘，還憶朝朝幾千里。", "馬卿臺上應蕪沒，阮籍帷前空已矣。", "山情水意君不知，拂匣調弦爲誰理。", "調弦拂匣倍含情，況復空山秋月明。", "隴水悲風已嗚咽，離鵾別鶴更淒清。", "將軍塞外多奇操，中散林間有正聲。", "正聲諧風雅，欲竟此曲誰知者。", "自言幽隱乏先容，不道人物知音寡。", "誰能一奏和天地，誰能再撫歡朝野。", "朝野歡娛樂未央，車馬駢闐盛彩章。", "歲歲汾川事簫鼓，朝朝伊水聽笙簧。", "窈窕樓臺臨上路，妖嬈歌舞出平陽。", "彈弦本自稱仁祖，吹管由來許季長。", "猶憐雅歌淡無味，淥水白雲誰相貴。", "還將逸詞賞幽心，不覺繁聲論遠意。", "傳聞帝樂奏鈞天，儻冀微躬備五弦。"]'),
('7f772e03-beb9-4e4d-b216-e5df1531e5a5','三婦豔','王紹宗','唐','唐诗','tang','','[]','大婦能調瑟，中婦詠新詩。',36,'全唐诗/poet.tang.5000.json','["大婦能調瑟，中婦詠新詩。", "小婦獨無事，花庭曳履綦。", "上客且安坐，春日正遲遲。"]'),
('76089241-9c53-4d9d-9fdb-1bc79448b878','別離怨','鄭遂初','唐','唐诗','tang','','[]','蕩子戍遼東，連年信不通。',48,'全唐诗/poet.tang.5000.json','["蕩子戍遼東，連年信不通。", "塵生錦步障，花送玉屏風。", "只怨紅顏改，寧辭玉簟空。", "繫書春雁足，早晚到雲中。"]'),
('658a96c6-4c44-42ec-85c9-607f1b77cda4','寒食','李崇嗣','唐','唐诗','tang','','["\u5bd2\u98df\u8282", "\u5b64\u72ec"]','普天皆滅焰，匝地盡藏煙。',24,'全唐诗/poet.tang.5000.json','["普天皆滅焰，匝地盡藏煙。", "不知何處火？來就客心然。"]'),
('8badfc5b-9cd3-42c7-a477-debbac0fa971','覽鏡','李崇嗣','唐','唐诗','tang','','[]','歲去紅顏盡，愁來白髮新。',24,'全唐诗/poet.tang.5000.json','["歲去紅顏盡，愁來白髮新。", "今朝開鏡匣，疑是別逢人。"]'),
('83c99263-5213-4d60-95fa-785e517702d6','獨愁','李崇嗣','唐','唐诗','tang','','[]','聞道成都酒，無錢亦可求。',24,'全唐诗/poet.tang.5000.json','["聞道成都酒，無錢亦可求。", "不知將幾斗，銷得此來愁。"]'),
('aa7be51f-e588-45a0-87db-e727a54b9d88','昭君怨三首 一','東方虬','唐','唐诗','tang','','[]','漢道方全盛，朝廷足武臣。',24,'全唐诗/poet.tang.5000.json','["漢道方全盛，朝廷足武臣。", "何須薄命妾，辛苦事和親。"]'),
('28166616-6856-4889-a620-287ad0ea0981','昭君怨三首 二','東方虬','唐','唐诗','tang','','[]','揜淚辭丹鳳，銜悲向白龍。',24,'全唐诗/poet.tang.5000.json','["揜淚辭丹鳳，銜悲向白龍。", "單于浪驚喜，無復舊時容。"]'),
('60ff5387-cca8-4c07-982a-73d9b39bbe55','昭君怨三首 三','東方虬','唐','唐诗','tang','','[]','胡地無花草，春來不似春。',24,'全唐诗/poet.tang.5000.json','["胡地無花草，春來不似春。", "自然衣帶緩，非是爲腰身。"]'),
('f7ec8c5e-78b9-4400-9627-095cf1c47af8','春雪','東方虬','唐','唐诗','tang','','["\u6625\u5929"]','春雪滿空來，觸處似花開。',24,'全唐诗/poet.tang.5000.json','["春雪滿空來，觸處似花開。", "不知園裏樹，若箇是真梅。"]'),
('ab3e9d77-64ad-41b0-866f-3b51e0f9387b','逸人歌贈李山人','張楚金','唐','唐诗','tang','','[]','上有堯兮下有田，眠松陽兮漱潁流。',76,'全唐诗/poet.tang.5000.json','["上有堯兮下有田，眠松陽兮漱潁流。", "其貌古，其心幽，浩歌一曲兮林壑秋。", "道險可驚兮人莫用，樂天知命兮守巖洞。", "時擊磬兮嗟鳴鳳，吾欲知往古之不可追，自悠悠於凡夢。"]'),
('dc166e53-49a5-42cb-b37e-66716bc68b86','謫南海過始興廣勝寺果上人房','房融','唐','唐诗','tang','','[]','零落嗟殘命，蕭條託勝因。',48,'全唐诗/poet.tang.5000.json','["零落嗟殘命，蕭條託勝因。", "方燒三界火，遽洗六情塵。", "隔嶺天花發，凌空月殿新。", "誰令鄉國夢，終此學分身。"]'),
('b716e76f-6401-4990-b62b-637e59c7fb47','詠院中藂竹','呂太一','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u7af9\u5b50", "\u548f\u7269", "\u8d5e\u7f8e"]','擢擢當軒竹，青青重歲寒。',24,'全唐诗/poet.tang.5000.json','["擢擢當軒竹，青青重歲寒。", "心貞徒見賞，籜小未成竿。"]'),
('03bbaefb-d7af-4660-a669-842569a46c2d','和呂御史詠院中藂竹','張紘','唐','唐诗','tang','','[]','聞君庭竹詠，幽意歲寒多。',24,'全唐诗/poet.tang.5000.json','["聞君庭竹詠，幽意歲寒多。", "歎息爲冠小，良工將奈何。"]'),
('921ae33a-5f08-4a8a-bcce-dc4bd7642ae9','閨怨','張紘','唐','唐诗','tang','','[]','去年離別雁初歸，今夜裁縫螢已飛。',32,'全唐诗/poet.tang.5000.json','["去年離別雁初歸，今夜裁縫螢已飛。", "征客近來音信斷，不知何處寄寒衣。"]'),
('235b688d-c7f7-4040-b2a3-91ed11f81bf5','行路難','張紘','唐','唐诗','tang','','[]','君不見溫家玉鏡臺，提攜抱屋九重來。',146,'全唐诗/poet.tang.5000.json','["君不見溫家玉鏡臺，提攜抱屋九重來。", "君不見相如綠綺琴，一撫一拍鳳凰音。", "人生意氣須及早，莫負當年行樂心。", "荆王奏曲楚妃歎，曲盡歡終夜將半。", "朱樓銀閣正平生，碧草青苔坐蕪漫。", "當春對酒不須疑，視日相看能幾時。", "春風吹盡燕初至，此時自爲稱君意。", "秋露萎草鴻始歸，此時衰暮與君違。", "人生翻覆何常定，誰保容顏無是非。"]'),
('c6c6047c-179f-4125-8e64-f0d5beb9da3e','別親朋','鄭蜀賓','唐','唐诗','tang','','[]','畏途方萬里，生涯近百年。',24,'全唐诗/poet.tang.5000.json','["畏途方萬里，生涯近百年。", "不知将白首，何處入黄泉。"]'),
('aef5c658-74d7-447e-b6ee-2035b707df5c','海上作','宋務光','唐','唐诗','tang','','[]','曠哉潮汐池，大矣乾坤力。',192,'全唐诗/poet.tang.5000.json','["曠哉潮汐池，大矣乾坤力。", "浩浩去無際，沄沄深不測。", "崩騰翕衆流，泱漭環中國。", "鱗介錯殊品，氛霞饒詭色。", "天波混莫分，島樹遙難識。", "漢主探靈怪，秦王恣遊陟。", "搜奇大壑東，竦望成山北。", "方術徒相誤，蓬萊安可得。", "吾君略仙道，至化孚淳默。", "驚浪晏窮溟，飛航通絕域。", "馬韓底厥貢，龍伯修其職。", "粵我遘休明，匪躬期正直。", "敢輸鷹隼執，以間豺狼忒。", "海路行已殫，輶軒未皇息。", "勞歌玄月暮，旅睇滄浪極。", "魏闕渺雲端，馳心附歸冀。"]'),
('b35fe792-9512-408f-a45b-3fb4bcd4f89c','回波辭','李景伯','唐','唐诗','tang','','[]','回波爾時酒巵，微臣職在箴規。',28,'全唐诗/poet.tang.5000.json','["回波爾時酒巵，微臣職在箴規。", "侍讌既過三爵，喧譁竊恐非儀。"]'),
('f3fcece0-91c8-4695-8811-df33ba834138','秋晚度廢關','李行言','唐','唐诗','tang','','[]','秦郊平舊險，周德眷遺黎。',72,'全唐诗/poet.tang.5000.json','["秦郊平舊險，周德眷遺黎。", "始聞清夜柝，俄見落封泥。", "物色來無限，津途去不迷。", "空亭誰問馬，閑戍但鳴雞。", "山月寒彌淨，河風曉更淒。", "贈言楊伯起，非復是關西。"]'),
('8802fc47-29ba-4564-a112-a602b5b0ebf0','上元','郭利貞','唐','唐诗','tang','','[]','九陌連燈影，千門度月華。',48,'全唐诗/poet.tang.5000.json','["九陌連燈影，千門度月華。", "傾城出寶騎，匝路轉香車。", "爛熳惟愁曉，周游不問家。", "更逢清管發，處處落梅花。"]'),
('bbe5da24-0d69-450e-bd8a-6ed1210ebc23','贈皇甫侍御赴都八首 一','元希聲','唐','唐诗','tang','','[]','東南之美，生于會稽。',40,'全唐诗/poet.tang.5000.json','["東南之美，生于會稽。", "牛斗之氣，蓄于昆溪。", "有瑤者玉，連城是齊。", "有威者鳳，非梧不棲。"]'),
('56a904d9-d977-44b0-be67-1cce4b11e5bc','贈皇甫侍御赴都八首 二','元希聲','唐','唐诗','tang','','[]','猗嗟衆珍，以況君子。',30,'全唐诗/poet.tang.5000.json','["猗嗟衆珍，以況君子。", "公侯之胄，必復其始。", "利器長材，溫儀峻峙。"]'),
('ec6f0769-4430-4b8f-9e2e-e767753c0163','贈皇甫侍御赴都八首 三','元希聲','唐','唐诗','tang','','[]','道心惟微，厥用允塞。',40,'全唐诗/poet.tang.5000.json','["道心惟微，厥用允塞。", "德輝不泯，而映邦國。", "靜以有神，動而作則。", "九臯千里，其聲不忒。"]'),
('66a25bbb-9840-44c4-b467-9f6fecee4714','贈皇甫侍御赴都八首 四','元希聲','唐','唐诗','tang','','[]','粵在古昔，分官厥初。',40,'全唐诗/poet.tang.5000.json','["粵在古昔，分官厥初。", "刺邪矯枉，非賢勿居。", "稜稜直指，烈烈方書。", "蒼玉鳴珮，繡衣登車。"]'),
('0cec5ccb-da28-4892-9a12-1006e3296439','贈皇甫侍御赴都八首 五','元希聲','唐','唐诗','tang','','[]','綽綽夫君，是膺柱下。',40,'全唐诗/poet.tang.5000.json','["綽綽夫君，是膺柱下。", "準繩有望，名器無假。", "寵蓋伯山，氣雄公雅。", "立朝正色，俟我能者。"]'),
('30769653-572f-4c56-8a3c-b01750734092','贈皇甫侍御赴都八首 六','元希聲','唐','唐诗','tang','','[]','載懷朋情，嘗接閑宴。',40,'全唐诗/poet.tang.5000.json','["載懷朋情，嘗接閑宴。", "好洽昆弟，官聯州縣。", "如彼松竹，春榮冬蒨。", "柯葉藹然，不渝霜霰。"]'),
('ed24afb2-20d1-4065-b30d-adf31e1adacc','贈皇甫侍御赴都八首 七','元希聲','唐','唐诗','tang','','[]','會合非我，關山坐違。',40,'全唐诗/poet.tang.5000.json','["會合非我，關山坐違。", "離鴻曉引，別葉秋飛。", "騑驂徐動，尊餞相依。", "遠情超忽，岐路光輝。"]'),
('a8164f00-219f-4711-be9a-2b2706ca7fc9','贈皇甫侍御赴都八首 八','元希聲','唐','唐诗','tang','','[]','金石其心，芝蘭其室。',40,'全唐诗/poet.tang.5000.json','["金石其心，芝蘭其室。", "言語方間，音徽自溢。", "肅子風威，嚴子霜質。", "贈言歲暮，以保貞吉。"]'),
('8fcae953-211b-470a-968a-4db6e90be6e1','秋庭夜月有懷','李澄之','唐','唐诗','tang','','[]','遊客三江外，單棲百慮違。',48,'全唐诗/poet.tang.5000.json','["遊客三江外，單棲百慮違。", "山川憶處近，形影夢中歸。", "夜月明虛帳，秋風入擣衣。", "從來不慣別，況屬鴈南飛。"]'),
('295d27fa-3837-4853-b70b-2bfc338af73d','明月','李如璧','唐','唐诗','tang','','[]','三五月華流炯光，可憐懷歸郢路長。',170,'全唐诗/poet.tang.5000.json','["三五月華流炯光，可憐懷歸郢路長。", "逾江越漢津無梁，遙遙永夜思茫茫。", "昭君失寵辭上宮，蛾眉嬋娟臥氈穹。", "胡人琵琶彈北風，漢家音信絕南鴻。", "昭君此時怨畫工，可憐明月光[朣]朧。", "節既秋兮天向寒，沅有漪兮湘有瀾。", "沅湘糺合淼漫漫，洛陽才子憶長安。", "可憐明月復團團，逐臣戀主心愈恪。", "棄妻思君情不薄，已悲芳歲徒淪落。", "復恐紅顏坐銷鑠，可憐明月方照灼，向影傾身比葵藿。"]'),
('0cc8df3c-e9b4-4a52-80fe-e1b3014da1d8','嚴陵祠','洪子輿','唐','唐诗','tang','','[]','漢主召子陵，歸宿洛陽殿。',96,'全唐诗/poet.tang.5000.json','["漢主召子陵，歸宿洛陽殿。", "客星今安在，隱迹猶可見。", "水石空潺湲，松篁尚蔥蒨。", "岸深翠陰合，川迴白雲徧。", "幽徑滋蕪沒，荒祠冪霜霰。", "垂釣想遺芳，掇蘋羞野薦。", "高風激終古，語理忘榮賤。", "方騐道可尊，山林情不變。"]'),
('18678980-d18d-4d54-b981-0193b9476cbd','度塗山','寇泚','唐','唐诗','tang','','[]','小年弄文墨，不識戎旅難。',72,'全唐诗/poet.tang.5000.json','["小年弄文墨，不識戎旅難。", "一朝事鞞鼓，策馬度塗山。", "塗山橫地軸，萬里留荒服。", "悠悠征斾遠，騑驂一何速。", "流月揮金戈，驚風折寒木。", "行聞漢飛將，還向臯蘭宿。"]'),
('77065e9d-4ee9-4937-bbad-fe9b901f3c6f','永泰公主挽歌二首 一','吳兢','唐','唐诗','tang','','[]','穠華從婦道，釐降適諸侯。',48,'全唐诗/poet.tang.5000.json','["穠華從婦道，釐降適諸侯。", "河漢天孫合，瀟湘帝子遊。", "關雎方作訓，鳴鳳自相求。", "可歎凌波迹，東川遂不流。"]'),
('1987a544-cf9e-4090-82b1-0fc90d0e791b','永泰公主挽歌二首 二','吳兢','唐','唐诗','tang','','[]','舜華徂北渚，宸思結南陽。',48,'全唐诗/poet.tang.5000.json','["舜華徂北渚，宸思結南陽。", "盩綬哀榮備，游軒寵悼彰。", "三川謀遠日，八水宅連岡。", "無復秦樓上，吹簫下鳳皇。"]'),
('b4bdbf29-64c8-4432-9a3f-d569fb9da794','妾薄命','武平一','唐','唐诗','tang','','[]','有女妖且麗，裴回湘水湄。',144,'全唐诗/poet.tang.5000.json','["有女妖且麗，裴回湘水湄。", "水湄蘭杜芳，採之將寄誰。", "瓠犀發皓齒，雙蛾顰翠眉。", "紅臉如開蓮，素膚若凝脂。", "綽約多逸態，輕盈不自持。", "嘗矜絕代色，復恃傾城姿。", "子夫前入侍，飛燕復當時。", "正悅掌中舞，寧哀團扇詩。", "洛川昔云遇，高唐今尚違。", "幽閤禽雀噪，閑階草露滋。", "流景一何速，年華不可追。", "解佩安所贈，怨咽空自悲。"]'),
('bbfc238a-d827-4f59-894e-cbd28da2fa65','奉和登驪山高頂寓目應制','武平一','唐','唐诗','tang','','[]','鑾輿上碧天，翠帟拖晴煙。',48,'全唐诗/poet.tang.5000.json','["鑾輿上碧天，翠帟拖晴煙。", "絕崿紆仙徑，層巖敞御筵。", "雲披丹鳳闕，日下黑龍川。", "更覩南熏奏，流聲入管弦。"]'),
('58ab4b4a-7267-4525-8e47-15ba3f8aec41','幸梨園觀打毬應制','武平一','唐','唐诗','tang','','[]','令節重遨遊，分鑣應綵毬。',48,'全唐诗/poet.tang.5000.json','["令節重遨遊，分鑣應綵毬。", "驂驔廻上苑，蹀躞繞通溝。", "影就紅塵沒，光隨赭汗流。", "賞闌清景暮，歌舞樂時休。"]'),
('a6d93978-0137-4de2-ba3d-ed5fbbc61917','奉和幸白鹿觀應制','武平一','唐','唐诗','tang','','[]','玉府凌三曜，金壇駐六龍。',48,'全唐诗/poet.tang.5000.json','["玉府凌三曜，金壇駐六龍。", "綵旒懸倒景，羽蓋偃喬松。", "玄圃靈芝秀，華池瑞液濃。", "謬因沾舜渥，長願奉堯封。"]'),
('09588e17-ec73-4899-b0d7-0761871392d1','侍宴安樂公主新宅應制','武平一','唐','唐诗','tang','','["\u9ec4\u5c71"]','紫漢秦樓敞，黃山魯館開。',48,'全唐诗/poet.tang.5000.json','["紫漢秦樓敞，黃山魯館開。", "簪裾分上席，歌舞列平臺。", "馬既如龍至，人疑學鳳來。", "幸茲聯棣萼，何以接鄒枚。"]'),
('dfd5a06e-6d3b-4a84-8eae-34a157dc7db8','送金城公主適西蕃','武平一','唐','唐诗','tang','','[]','廣化三邊靜，通煙四海安。',48,'全唐诗/poet.tang.5000.json','["廣化三邊靜，通煙四海安。", "還將膝下愛，特副域中歡。", "聖念飛玄藻，仙儀下白蘭。", "日斜征蓋沒，歸騎動鳴鸞。"]'),
('9252a97b-dd59-42be-93a8-afc66b7edce1','奉和幸新豐溫泉宮應制','武平一','唐','唐诗','tang','','[]','秦王登碣石，周后襲崑崙。',168,'全唐诗/poet.tang.5000.json','["秦王登碣石，周后襲崑崙。", "何必在遐遠，方稱萬宇尊。", "我皇順時豫，星駕動軒轅。", "雄戟交馳道，清笳度國門。", "回輿長樂觀，校獵上林園。", "行漏移三象，連營總八屯。", "旌搖鸚鵡谷，騎轉鳳皇原。", "絕壁蒼苔古，靈泉碧溜溫。", "參差開水殿，䆗窱敞巖軒。", "豐邑模猶在，驪宮迹尚存。", "煙松銜翠幄，雪徑遶花源。", "侍從推玄草，文章召虎賁。", "深仁浹夷夏，洪造溢乾坤。", "謬忝王枚列，多慙雨露恩。"]'),
('366d110f-3fb7-463c-b21c-860b7b609941','奉和幸韋嗣立山莊侍宴應制','武平一','唐','唐诗','tang','','[]','三光回斗極，萬騎肅鉤陳。',96,'全唐诗/poet.tang.5000.json','["三光回斗極，萬騎肅鉤陳。", "地若遊汾水，畋疑歷渭濱。", "圓塘冰寫鏡，遙樹露成春。", "弦奏魚聽曲，機忘鳥狎人。", "築巖思感夢，磻石想垂綸。", "落景搖紅壁，層陰結翠筠。", "素風紛可尚，玄澤藹無垠。", "薄暮清笳動，天文煥紫宸。"]'),
('10f398e2-d046-469f-af44-51b6c15e569f','興慶池侍宴應制','武平一','唐','唐诗','tang','','[]','鑾輿羽駕直城隈，帳殿旌門此地開。',64,'全唐诗/poet.tang.5000.json','["鑾輿羽駕直城隈，帳殿旌門此地開。", "皎潔靈潭圖日月，參差畫舸結樓臺。", "波搖岸影隨橈轉，風送荷香逐酒來。", "願奉聖情歡不極，長遊雲漢幾昭回。"]'),
('ca642191-74a5-4a73-b1f8-288ea1592018','奉和立春內出綵花樹應制','武平一','唐','唐诗','tang','','[]','鑾輅青旂下帝臺，東郊上苑望春來。',64,'全唐诗/poet.tang.5000.json','["鑾輅青旂下帝臺，東郊上苑望春來。", "黃鶯未解林間囀，紅蘂先從殿裏開。", "畫閣條風初變柳，銀塘曲水半含苔。", "欣逢睿藻光韶律，更促霞觴畏景催。"]'),
('0348db03-dcf5-4e23-ac3c-cbfa186ebae3','奉和正旦賜宰臣栢葉應制','武平一','唐','唐诗','tang','','[]','綠葉迎春綠，寒枝歷歲寒。',24,'全唐诗/poet.tang.5000.json','["綠葉迎春綠，寒枝歷歲寒。", "願持柏葉壽，長奉萬年歡。"]'),
('793b94f3-f7f9-477f-b588-ab464328959c','遊涇川琴溪','武平一','唐','唐诗','tang','','[]','環潭澄曉色，疊嶂照秋影。',24,'全唐诗/poet.tang.5000.json','["環潭澄曉色，疊嶂照秋影。", "幽致欣所逢，紛慮自茲屏。"]'),
('c8fe718c-a86b-43c0-9e05-944b70c54c57','夜宴安樂公主宅','武平一','唐','唐诗','tang','','[]','王孫帝女下仙臺，金牓珠簾入夜開。',32,'全唐诗/poet.tang.5000.json','["王孫帝女下仙臺，金牓珠簾入夜開。", "遽惜瓊筵歡正洽，唯愁銀箭曉相催。"]'),
('d22ae295-a2f3-4641-9508-9cb7dfae6eb4','奉和聖製幸韋嗣立山莊應制','武平一','唐','唐诗','tang','','[]','鳴鑾赫奕下重樓，羽蓋逍遙向一丘。',32,'全唐诗/poet.tang.5000.json','["鳴鑾赫奕下重樓，羽蓋逍遙向一丘。", "漢日唯聞白衣寵，唐年更覩赤松遊。"]'),
('2a1fe757-85b3-41c7-b7cd-6517e66b6e44','餞唐永昌','武平一','唐','唐诗','tang','','[]','聞君墨綬出丹墀，雙舃飛來佇有期。',32,'全唐诗/poet.tang.5000.json','["聞君墨綬出丹墀，雙舃飛來佇有期。", "寄謝銅街攀柳日，無忘粉署握蘭時。"]'),
('0c554a87-f379-4c85-8df2-65a1ae0c04c9','奉和聖製立春日侍宴內殿出剪綵花應制','趙彥昭','唐','唐诗','tang','','[]','剪綵迎初候，攀條故寫真。',48,'全唐诗/poet.tang.5000.json','["剪綵迎初候，攀條故寫真。", "花隨紅意發，葉就綠情新。", "嫩色驚銜燕，輕香誤採人。", "應爲熏風拂，能令芳樹春。"]'),
('b380fb7e-874f-4ef7-a47f-ab28571b7778','奉和人日清暉閣宴羣臣遇雪應制','趙彥昭','唐','唐诗','tang','','[]','出震乘東陸，憑高御北辰。',48,'全唐诗/poet.tang.5000.json','["出震乘東陸，憑高御北辰。", "祥雲應早歲，瑞雪候初旬。", "庭樹千花發，階蓂七葉新。", "幸承今日宴，長奉萬年春。"]'),
('357a9b75-35fa-4e0c-9a10-1d51f84a1e6f','奉和七夕兩儀殿會宴應制','趙彥昭','唐','唐诗','tang','','[]','青女三秋節，黃姑七日期。',48,'全唐诗/poet.tang.5000.json','["青女三秋節，黃姑七日期。", "星橋度玉珮，雲閣掩羅帷。", "河氣通仙掖，天文入睿詞。", "今宵望靈漢，應得見蛾眉。"]'),
('87c44231-ad2f-4024-b056-99e1198bcc46','奉和九日幸臨渭亭登高應制','趙彥昭','唐','唐诗','tang','','["\u5199\u666f", "\u6292\u60c5", "\u767b\u9ad8", "\u91cd\u9633\u8282"]','秋豫凝仙覽，宸遊轉翠華。',48,'全唐诗/poet.tang.5000.json','["秋豫凝仙覽，宸遊轉翠華。", "呼鷹下鳥路，戲馬出龍沙。", "紫菊宜新壽，丹萸辟舊邪。", "須陪長久宴，歲歲奉吹花。"]'),
('9265172e-7267-4e9d-9fa9-f19ba3b5852e','奉和九月九日登慈恩寺浮屠應制','趙彥昭','唐','唐诗','tang','','[]','出豫乘秋節，登高陟梵宮。',48,'全唐诗/poet.tang.5000.json','["出豫乘秋節，登高陟梵宮。", "皇心滿塵界，佛跡現虛空。", "日月宜長壽，人天得大通。", "喜聞題寶偈，受記莫由同。"]'),
('eebc7824-49f4-4fb9-85b0-a0ce8d938a8e','安樂公主移入新宅侍宴應制同用開字','趙彥昭','唐','唐诗','tang','','[]','雲物中京曉，天人外館開。',48,'全唐诗/poet.tang.5000.json','["雲物中京曉，天人外館開。", "飛橋象河漢，懸牓學蓬萊。", "北闕臨仙檻，南山送壽杯。", "一窺輪奐畢，慚恧棟梁材。"]'),
('7bfb9219-ca68-4f1f-81f9-040420daeff7','奉和送金城公主適西蕃應制','趙彥昭','唐','唐诗','tang','','[]','聖后經綸遠，謀臣計畫多。',48,'全唐诗/poet.tang.5000.json','["聖后經綸遠，謀臣計畫多。", "受降追漢策，築館許戎和。", "俗化烏孫壘，春生積石河。", "六龍今出餞，雙鶴願爲歌。"]'),
('c01af4a8-9d4a-4a41-a3d7-275eac4704a5','奉和聖製登驪山高頂寓目應制','趙彥昭','唐','唐诗','tang','','[]','皇情遍九垓，御輦駐昭回。',48,'全唐诗/poet.tang.5000.json','["皇情遍九垓，御輦駐昭回。", "路若隨天轉，人疑近日來。", "河看大禹鑿，山見巨靈開。", "願扈登封駕，常持薦壽杯。"]'),
('d178343f-1985-47e9-b36b-4887a7659429','奉和幸白鹿觀應制','趙彥昭','唐','唐诗','tang','','[]','雲驂驅半景，星蹕坐中天。',48,'全唐诗/poet.tang.5000.json','["雲驂驅半景，星蹕坐中天。", "國誕玄宗聖，家尋碧落仙。", "玉杯鸞薦壽，寶算鶴知年。", "一覩光華旦，欣承道德篇。"]'),
('c6d0c98d-c11f-4124-bcec-00be26f8b5e0','哭僕射鄂公楊再思','趙彥昭','唐','唐诗','tang','','[]','兩揆光天秩，三朝奉帝熙。',48,'全唐诗/poet.tang.5000.json','["兩揆光天秩，三朝奉帝熙。", "何言集大鳥，忽此喪元龜。", "坐歎公槐落，行聞宰樹悲。", "壑舟今已去，寧有濟川期。"]'),
('6f3e2276-e5f0-48e4-946e-c0febd9b9e0c','人日侍讌大明宮應制','趙彥昭','唐','唐诗','tang','','[]','寶契無爲屬聖人，琱輿出幸玩芳辰。',64,'全唐诗/poet.tang.5000.json','["寶契無爲屬聖人，琱輿出幸玩芳辰。", "平樓半入南山霧，飛閤旁臨東墅春。", "夾路穠花千樹發，垂軒弱柳萬條新。", "處處風光今日好，年年願奉屬車塵。"]'),
('cce85c00-604a-4335-b673-e092dd992665','奉和初春幸太平公主南莊應制','趙彥昭','唐','唐诗','tang','','[]','主第巖扃駕鵲橋，天門閶闔降鸞鑣。',64,'全唐诗/poet.tang.5000.json','["主第巖扃駕鵲橋，天門閶闔降鸞鑣。", "歷亂旌旗轉雲樹，參差臺榭入煙霄。", "林間花雜平陽舞，谷裏鶯和弄玉簫。", "已陪沁水追歡日，行奉茅山訪道朝。"]'),
('5146d17b-44c9-4631-9a2b-b93c38b7fd77','奉和幸安樂公主山莊應制','趙彥昭','唐','唐诗','tang','','[]','六龍齊軫御朝曦，雙鷁維舟下綠池。',64,'全唐诗/poet.tang.5000.json','["六龍齊軫御朝曦，雙鷁維舟下綠池。", "飛觀仰看雲外聳，浮橋直見海中移。", "靈泉巧鑿天孫渚，孝筍能抽帝女枝。", "幸願一生同草樹，年年歲歲樂於斯。"]'),
('94955f70-a6be-494e-9950-d29341591fe8','奉和幸大薦福寺','趙彥昭','唐','唐诗','tang','','[]','寶地龍飛後，金身佛現時。',72,'全唐诗/poet.tang.5000.json','["寶地龍飛後，金身佛現時。", "千花開國界，萬善累皇基。", "北闕承行幸，西園屬住持。", "天衣拂舊石，王舍起新祠。", "剎鳳迎琱輦，幡虹駐綵旗。", "同沾小雨潤，竊仰大風詩。"]'),
('c4307bc0-2cc3-4ee8-9b73-6068352937e2','奉和幸長安故城未央宮應制','趙彥昭','唐','唐诗','tang','','[]','夙駕移天蹕，憑軒覽漢都。',72,'全唐诗/poet.tang.5000.json','["夙駕移天蹕，憑軒覽漢都。", "寒煙收紫禁，春色繞黃圖。", "舊史遺陳迹，前王失霸符。", "山河寸土盡，宮觀尺椽無。", "崇高惟在德，壯麗豈爲謨。", "茨室留皇鑒，熏歌盛有虞。"]'),
('4493c79f-42a0-4d5b-828b-e872c9d8928e','奉和幸韋嗣立山莊侍燕應制','趙彥昭','唐','唐诗','tang','','[]','賢族唯題里，儒門但署鄉。',96,'全唐诗/poet.tang.5000.json','["賢族唯題里，儒門但署鄉。", "何如表巖洞，宸翰發輝光。", "地在茲山曲，家臨郃水陽。", "六龍駐旌罕，四牡耀旂常。", "北斗臨台座，東山入廟堂。", "天高羽翼近，主聖股肱良。", "野竹池亭氣，村花澗谷香。", "縱然懷豹隱，空愧躡鵷行。"]'),
('fd70c013-9c45-4ea0-b326-15217c4a82d7','奉和元日賜羣臣栢葉應制','趙彥昭','唐','唐诗','tang','','["\u6625\u8282"]','器乏雕梁器，材非構廈材。',24,'全唐诗/poet.tang.5000.json','["器乏雕梁器，材非構廈材。", "但將千歲葉，常奉萬年杯。"]'),
('6ea04e5b-c451-4f23-9914-a5dd163bc169','苑中人日遇雪應制','趙彥昭','唐','唐诗','tang','','[]','始見青雲干律呂，俄逢瑞雪應陽春。',32,'全唐诗/poet.tang.5000.json','["始見青雲干律呂，俄逢瑞雪應陽春。", "今日迴看上林樹，梅花柳絮一時新。"]'),
('e7ba1af6-b990-4faa-aacd-7bfdce317f98','奉和聖製幸韋嗣立山莊應制','趙彥昭','唐','唐诗','tang','','[]','廊廟心存巖壑中，鑾輿矚在灞城東。',32,'全唐诗/poet.tang.5000.json','["廊廟心存巖壑中，鑾輿矚在灞城東。", "逍遙自在蒙莊子，漢主徒言河上公。"]'),
('e5ab85c8-7f9d-4fd3-87cb-ecf374679ba1','秋朝木芙蓉','趙彥昭','唐','唐诗','tang','','[]','水面芙蓉秋已衰，繁條偏是著花遲。',32,'全唐诗/poet.tang.5000.json','["水面芙蓉秋已衰，繁條偏是著花遲。", "平明露滴垂紅臉，似有朝愁暮落時。"]'),
('d4b40cb2-2a03-47a8-98e8-ce7eec3a275d','侍宴桃花園詠桃花應制','趙彥昭','唐','唐诗','tang','','[]','紅萼競燃春苑曙，粉茸新吐御筵開。',32,'全唐诗/poet.tang.5000.json','["紅萼競燃春苑曙，粉茸新吐御筵開。", "長年願奉西王母，近侍慚無東朔才。"]'),
('c261f594-8ad6-41db-a05b-6065cf277a8b','奉和九日幸臨渭亭登高應制得餘字','蕭至忠','唐','唐诗','tang','','[]','望幸三秋暮，登高九日初。',48,'全唐诗/poet.tang.5000.json','["望幸三秋暮，登高九日初。", "朱旗巡漢苑，翠帟俯秦墟。", "寵極萸房遍，恩深菊酎餘。", "承歡何以荅，萬億奉宸居。"]'),
('08860783-d978-4a97-95d5-68860a19fe7d','奉和九月九日登慈恩寺浮圖應制','蕭至忠','唐','唐诗','tang','','[]','天蹕三乘啓，星輿六轡行。',48,'全唐诗/poet.tang.5000.json','["天蹕三乘啓，星輿六轡行。", "登高凌寶塔，極目徧王城。", "神衞空中遶，仙歌雲外清。", "重陽千萬壽，率舞頌昇平。"]'),
('71c0f59c-3b6b-4083-9250-e0d99ea57f0f','奉和幸安樂公主山莊應制','蕭至忠','唐','唐诗','tang','','[]','西郊窈窕鳳皇臺，北渚平明法駕來。',64,'全唐诗/poet.tang.5000.json','["西郊窈窕鳳皇臺，北渚平明法駕來。", "匝地金聲初度曲，周堂玉溜好傳杯。", "灣路分遊畫舟轉，岸門相向碧亭開。", "微臣此時承宴樂，髣髴疑從星漢迴。"]'),
('ec195244-2805-4a55-acfb-34e3e49660f1','送張亶赴朔方應制','蕭至忠','唐','唐诗','tang','','[]','命將擇耆年，圖功勝必全。',72,'全唐诗/poet.tang.5000.json','["命將擇耆年，圖功勝必全。", "光輝萬乘餞，威武二庭宣。", "中衢橫鼓角，曠野蔽旌旃。", "推食天廚至，投醪御酒傳。", "涼風過鴈苑，殺氣下雞田。", "分閫恩何極，臨岐動睿篇。"]'),
('d9cc0940-aff6-4989-95d4-b7a780b0dc27','陪幸長寧公主林亭','蕭至忠','唐','唐诗','tang','','[]','公主林亭地，清晨降玉輿。',48,'全唐诗/poet.tang.5000.json','["公主林亭地，清晨降玉輿。", "畫橋飛渡水，仙閣逈臨虛。", "新晴看蛺蝶，早夏摘芙蕖。", "文酒娛遊盛，忻叨侍從餘。"]'),
('620e6a73-5aa9-4c8c-8eed-fe95014860cc','陪幸五王宅','蕭至忠','唐','唐诗','tang','','[]','北斗樞機任，西京肺腑親。',72,'全唐诗/poet.tang.5000.json','["北斗樞機任，西京肺腑親。", "疇昔王門下，今茲制幸晨。", "恩來山水被，聖作管弦新。", "遶座薰紅藥，當軒暗綠筠。", "摘荷纔早夏，聽鳥尚餘春。", "行漏金徒曉，風煙是觀津。"]'),
('a138f221-c3fa-4f9c-be94-fb1cdffdf518','三會寺應制','蕭至忠','唐','唐诗','tang','','[]','岧嶤倉史臺，敞朗紺園開。',72,'全唐诗/poet.tang.5000.json','["岧嶤倉史臺，敞朗紺園開。", "戒旦壺人警，翻霜羽騎來。", "下輦登三襲，褰旒望九垓。", "林披館陶牓，水浸昆明灰。", "網戶飛花綴，幡竿度鳥迴。", "豫遊仙唱動，瀟灑初塵埃。"]'),
('11eb12b4-9968-40ff-88c2-884a77f91ece','薦福寺應制','蕭至忠','唐','唐诗','tang','','[]','地靈傳景福，天駕儼鉤陳。',74,'全唐诗/poet.tang.5000.json','["地靈傳景福，天駕儼鉤陳。", "佳哉藩邸舊，赫矣梵宮新。", "香塔魚山下，禪堂鴈水濱。", "珠幡映白日，鏡殿寫青春。", "甚懽延故吏，大覺拯生人。", "幸承歌頌末，長奉屬車[塵]。"]'),
('a39ebbbd-8626-4de4-a582-23146a31e189','陪遊上苑遇雪','蕭至忠','唐','唐诗','tang','','[]','龍驂曉入望春宮，正逢春雪舞春風。',32,'全唐诗/poet.tang.5000.json','["龍驂曉入望春宮，正逢春雪舞春風。", "花光倂在天文上，寒氣行銷御酒中。"]'),
('257a9f3b-dbdd-458c-9cb2-f5e4361a73f0','奉和九日幸臨渭亭登高應制得風字','李迥秀','唐','唐诗','tang','','[]','重九臨商節，登高出漢宮。',48,'全唐诗/poet.tang.5000.json','["重九臨商節，登高出漢宮。", "正逢萸實滿，還對菊花叢。", "霽雲開就日，仙藻麗秋風。", "微臣預在鎬，竊抃遂無窮。"]'),
('76c68224-117d-4b08-8a6a-1f4fe60998e1','奉和九月九日登慈恩寺浮圖應制','李迥秀','唐','唐诗','tang','','[]','沙界人王塔，金繩梵帝遊。',50,'全唐诗/poet.tang.5000.json','["沙界人王塔，金繩梵帝遊。", "言從[祇]樹賞，行翫菊叢秋。", "御酒調甘露，天花拂綵旒。", "堯年將佛日，同此慶時休。"]'),
('1bf34ea6-b786-44e9-975f-8082a33269ee','奉和幸安樂公主山莊應制','李迥秀','唐','唐诗','tang','','[]','詰旦重門聞警蹕，傳言太主奏山林。',64,'全唐诗/poet.tang.5000.json','["詰旦重門聞警蹕，傳言太主奏山林。", "是日迴輿羅萬騎，此時歡喜賜千金。", "鷺羽鳳簫參樂曲，荻園竹徑接帷陰。", "手舞足蹈方無已，萬年千歲奉薰琴。"]'),
('c72f248e-477c-4b3d-ad72-3bdc3a497e59','夜宴安樂公主宅','李迥秀','唐','唐诗','tang','','[]','金牓岧嶤雲裏開，玉簫參差天際迴。',32,'全唐诗/poet.tang.5000.json','["金牓岧嶤雲裏開，玉簫參差天際迴。", "莫驚側弁還歸路，秖爲平陽歌舞催。"]'),
('42c48179-a43b-46eb-85cf-e2f712cc81da','奉和九日幸臨渭亭登高應制得亭字','楊廉','唐','唐诗','tang','','[]','遠目瞰秦坰，重陽坐灞亭。',48,'全唐诗/poet.tang.5000.json','["遠目瞰秦坰，重陽坐灞亭。", "既開黃菊酒，還降紫微星。", "簫鼓諳仙曲，山河入畫屏。", "幸茲陪宴喜，無以效丹青。"]'),
('cdf666d1-3ed9-4732-8d0f-88d4c9752db8','奉和九月九日登慈恩寺浮圖應制','楊廉','唐','唐诗','tang','','[]','萬乘臨真境，重陽眺遠空。',48,'全唐诗/poet.tang.5000.json','["萬乘臨真境，重陽眺遠空。", "慈雲浮鴈塔，定水映龍宮。", "寶鐸含飆響，仙輪帶日紅。", "天文將瑞色，輝煥滿寰中。"]'),
('de75bf9f-8d29-41a6-9a03-ce01876f7971','奉和九日幸臨渭亭登高應制得枝字','韋安石','唐','唐诗','tang','','["\u91cd\u9633", "\u5199\u666f", "\u6292\u60c5", "\u767b\u9ad8", "\u91cd\u9633\u8282"]','重九開秋節，得一動宸儀。',48,'全唐诗/poet.tang.5000.json','["重九開秋節，得一動宸儀。", "金風飄菊蘂，玉露泫萸枝。", "睿覽八紘外，天文七曜披。", "臨深應在即，居高豈忘危。"]'),
('ebf3cd84-4a86-408e-be9b-442cc85352fe','侍宴旋師喜捷應制','韋安石','唐','唐诗','tang','','[]','蜂蟻屯夷落，熊羆逐漢飛。',48,'全唐诗/poet.tang.5000.json','["蜂蟻屯夷落，熊羆逐漢飛。", "忘軀百戰後，屈指一年歸。", "厚眷紓天藻，深慈解御衣。", "興酣歌舞出，朝野歎光輝。"]'),
('99fb5e40-b003-4591-8a47-1e160dfa080e','梁王宅侍宴應制同用風字','韋安石','唐','唐诗','tang','','[]','梁園開勝景，軒駕動宸衷。',48,'全唐诗/poet.tang.5000.json','["梁園開勝景，軒駕動宸衷。", "早荷承湛露，脩竹引薰風。", "九醞傾鍾石，百獸協絲桐。", "小臣陪宴鎬，獻壽奉維嵩。"]'),
('f1e324d9-e77a-485f-b4b6-5ba070d0b75c','奉和九日幸臨渭亭登高應制得明字','竇希玠','唐','唐诗','tang','','[]','鑾輿巡上苑，鳳駕瞰層城。',48,'全唐诗/poet.tang.5000.json','["鑾輿巡上苑，鳳駕瞰層城。", "御座丹烏麗，宸居白鶴驚。", "玉旗縈桂葉，金杯汎菊英。", "九晨陪聖膳，萬歲奉承明。"]'),
('9912716c-15ef-4300-91a5-c82b1e452fbe','奉和九日幸臨渭亭登高應制得臣字','陸景初','唐','唐诗','tang','','[]','九秋光順豫，重節霽良辰。',48,'全唐诗/poet.tang.5000.json','["九秋光順豫，重節霽良辰。", "登高識漢苑，問道侍軒臣。", "菊花浮秬鬯，萸房插縉紳。", "聖化邊陲謐，長洲鴻雁賓。"]'),
('33c54d66-3d90-41a1-b8fb-dd73e1fd8819','奉和九日幸臨渭亭登高應制得日字','鄭南金','唐','唐诗','tang','','[]','重陽玉律應，萬乘金輿出。',48,'全唐诗/poet.tang.5000.json','["重陽玉律應，萬乘金輿出。", "風起韻虞弦，雲開吐堯日。", "菊花浮聖酒，茱香挂衰質。", "欲知恩煦多，順動觀秋實。"]'),
('9cc7048a-1939-4de7-a928-a1e1986ed218','奉和九日幸臨渭亭登高應制得直字','李咸','唐','唐诗','tang','','[]','重陽乘令序，四野開晴色。',48,'全唐诗/poet.tang.5000.json','["重陽乘令序，四野開晴色。", "日月數初幷，乾坤聖登極。", "菊黃迎酒泛，松翠凌霜直。", "遊海難爲深，負山徒倦力。"]'),
('99297825-8deb-454c-90f2-fea3c6f0890c','奉和九日幸臨渭亭登高應制得花字','趙彥伯','唐','唐诗','tang','','[]','九日報仙家，三秋轉歲華。',48,'全唐诗/poet.tang.5000.json','["九日報仙家，三秋轉歲華。", "呼鷹下鳥路，戲馬出龍沙。", "簪挂丹萸蘂，杯浮紫菊花。", "所願同微物，年年共辟邪。"]'),
('ab6b9019-8e9e-4c78-9b41-8870ad5c9d30','從宴桃花園詠桃花應制','趙彥伯','唐','唐诗','tang','','[]','紅萼競燃春苑曙，䒠茸新吐御筵開。',32,'全唐诗/poet.tang.5000.json','["紅萼競燃春苑曙，䒠茸新吐御筵開。", "長年願奉西王讌，近侍慚無東朔才。"]'),
('c6cf7ffe-bf0a-48d5-9e3c-5927cefc4050','苑中遇雪應制','趙彥伯','唐','唐诗','tang','','[]','千鍾聖酒御筵披，六出祥英亂遶枝。',32,'全唐诗/poet.tang.5000.json','["千鍾聖酒御筵披，六出祥英亂遶枝。", "即此神仙對瓊圃，何煩轍跡向瑤池。"]'),
('f25e2481-52d7-4182-af87-4e7b776d33ab','奉和九日幸臨渭亭登高應制得樽字','于經野','唐','唐诗','tang','','[]','御氣三秋節，登高九曲門。',48,'全唐诗/poet.tang.5000.json','["御氣三秋節，登高九曲門。", "桂筵羅玉俎，菊醴溢芳樽。", "遵渚歸鴻度，承雲舞鶴鶱。", "微臣濫陪賞，空荷聖明恩。"]'),
('71821b86-17b6-41fc-a1cd-6c27242b61ee','奉和九日幸臨渭亭登高應制得還字','盧懷慎','唐','唐诗','tang','','[]','時和素秋節，宸豫紫機關。',48,'全唐诗/poet.tang.5000.json','["時和素秋節，宸豫紫機關。", "鶴似聞琴至，人疑宴鎬還。", "曠望臨平野，潺湲俯瞑灣。", "無因酬大德，空此媿崇班。"]'),
('525315c3-238f-40cd-9433-be42332174d3','奉和聖製龍池篇','盧懷慎','唐','唐诗','tang','','[]','代邸東南龍躍泉，清漪碧浪遠浮天。',64,'全唐诗/poet.tang.5000.json','["代邸東南龍躍泉，清漪碧浪遠浮天。", "樓臺影就波中出，日月光疑鏡裏懸。", "雁沼洄流成舜海，龜書薦社應堯年。", "大川既濟慙爲楫，報德空思奉細涓。"]'),
('32bf5259-2813-48cc-b20f-051b1cb271bd','奉和九月九日登慈恩寺浮圖應制','辛替否','唐','唐诗','tang','','[]','洪慈均動植，至德俯深玄。',48,'全唐诗/poet.tang.5000.json','["洪慈均動植，至德俯深玄。", "出豫從初地，登高適梵天。", "白雲飛御藻，慧日暖皇編。", "別有秋原藿，長傾雨露緣。"]'),
('f108d618-8227-4080-aa89-32c2baad96cc','奉和九月九日登慈恩寺浮圖應制','王景','唐','唐诗','tang','','[]','玉輦移中禁，珠梯覽四禪。',48,'全唐诗/poet.tang.5000.json','["玉輦移中禁，珠梯覽四禪。", "重階清漢接，飛竇紫霄懸。", "綴葉披天藻，吹花散御筵。", "無因鑾蹕暇，俱舞鶴林前。"]'),
('3654c63d-a93d-41b3-aa3b-3b1d7387eb97','奉和九月九日登慈恩寺浮圖應制','畢乾泰','唐','唐诗','tang','','[]','鸚林花塔啟，鳳輦順時遊。',48,'全唐诗/poet.tang.5000.json','["鸚林花塔啟，鳳輦順時遊。", "重九昭皇慶，大千揚帝休。", "耆闍妙法闡，王舍睿文流。", "至德覃無極，小臣歌詎酬。"]'),
('24d59c5b-0a80-4032-8cda-5ee93e109edd','奉和九月九日登慈恩寺浮圖應制','麴瞻','唐','唐诗','tang','','[]','扈蹕遊玄地，陪仙瞰紫微。',48,'全唐诗/poet.tang.5000.json','["扈蹕遊玄地，陪仙瞰紫微。", "似邁銖衣刼，將同羽化飛。", "雕戈秋日麗，寶劒曉霜霏。", "獻觴乘菊序，長願奉天暉。"]'),
('d13bfe60-91e1-455f-9f36-68b0612a44aa','奉和九月九日登慈恩寺浮圖應制','樊忱','唐','唐诗','tang','','[]','淨境重陽節，仙遊萬乘來。',48,'全唐诗/poet.tang.5000.json','["淨境重陽節，仙遊萬乘來。", "插萸登鷲嶺，把菊坐蜂臺。", "十地祥雲合，三天瑞景開。", "秋風詞更遠，竊抃樂康哉。"]'),
('3797c008-0fb6-45ae-b786-8ce02b1736d0','奉和九月九日登慈恩寺浮圖應制','孫佺','唐','唐诗','tang','','[]','應節萸房滿，初寒菊圃新。',48,'全唐诗/poet.tang.5000.json','["應節萸房滿，初寒菊圃新。", "龍旗煥辰極，鳳駕儼香闉。", "蓮井偏宜夏，梅梁更若春。", "一忻陪鴈塔，還似得天身。"]'),
('13941e18-7eb0-4cd3-89b8-f3a5d743e21d','奉和九月九日登慈恩寺浮圖應制','李從遠','唐','唐诗','tang','','[]','九月從時豫，三乘爲法開。',48,'全唐诗/poet.tang.5000.json','["九月從時豫，三乘爲法開。", "中霄日天子，半座寶如來。", "摘果珠盤獻，攀萸玉輦迴。", "願將塵露點，遙奉光明臺。"]'),
('6b72c598-a554-48c3-a7cc-f8da784b50ba','奉和九月九日登慈恩寺浮圖應制','周利用','唐','唐诗','tang','','[]','出豫乘金節，飛文煥日宮。',48,'全唐诗/poet.tang.5000.json','["出豫乘金節，飛文煥日宮。", "萸房開聖酒，杏苑被玄功。", "塔向三天迥，禪收八解空。", "叨恩奉蘭藉，終愧洽薰風。"]'),
('f2bd99a1-8616-4140-858a-00dc5578bfa7','奉和九月九日登慈恩寺浮圖應制','張景源','唐','唐诗','tang','','[]','飛塔凌霄起，宸遊一届焉。',48,'全唐诗/poet.tang.5000.json','["飛塔凌霄起，宸遊一届焉。", "金壺新泛菊，寶座即披蓮。", "就日搖香輦，憑雲出梵天。", "祥氛與佳色，相伴雜鑪煙。"]'),
('b210aee2-7a1c-4780-be4f-a96ba8b1bf22','奉和九月九日登慈恩寺浮圖應制','李恆','唐','唐诗','tang','','[]','寶地隣丹掖，香臺瞰碧雲。',48,'全唐诗/poet.tang.5000.json','["寶地隣丹掖，香臺瞰碧雲。", "河山天外出，城闕樹中分。", "睿藻蘭英秀，仙杯菊蘂薰。", "願將今日樂，長奉聖明君。"]'),
('1d5b7326-964e-4402-8d76-241075a9bc6b','奉和九月九日登慈恩寺浮圖應制','張錫','唐','唐诗','tang','','[]','九秋霜景淨，千門曉望通。',48,'全唐诗/poet.tang.5000.json','["九秋霜景淨，千門曉望通。", "仙遊光御路，瑞塔迥凌空。", "菊彩揚堯日，萸香遶舜風。", "天文麗辰象，竊抃仰層穹。"]'),
('d7322f35-3568-45e6-9b17-0db1074ca77a','晦日宴高文學林亭','張錫','唐','唐诗','tang','','[]','雪盡銅駝路，花照石崇家。',48,'全唐诗/poet.tang.5000.json','["雪盡銅駝路，花照石崇家。", "年光開柳色，池影汎雲華。", "賞洽情方遠，春歸景未賒。", "欲知多暇日，尊酒漬澄霞。"]'),
('29243435-70b3-46c9-98f6-abeacdd54eae','奉和九月九日登慈恩寺浮圖應制','解琬','唐','唐诗','tang','','[]','瑞塔臨初地，金輿幸上方。',48,'全唐诗/poet.tang.5000.json','["瑞塔臨初地，金輿幸上方。", "空邊有清淨，覺處無馨香。", "雨霽微塵歛，風秋定水涼。", "茲辰采仙菊，薦壽慶重陽。"]'),
('5647fb48-f78b-415b-932c-3d69550c40cb','晦日宴高氏林亭','解琬','唐','唐诗','tang','','[]','主第簪裾出，王畿春照華。',48,'全唐诗/poet.tang.5000.json','["主第簪裾出，王畿春照華。", "山亭一以眺，城闕帶煙霞。", "橫堤列錦帳，傍浦駐香車。", "歡娛屬晦節，酩酊未還家。"]'),
('deb2bdbe-e1da-4551-a66f-017c7a5be413','侍宴長寧公主東莊應制','鄭愔','唐','唐诗','tang','','[]','公門襲漢環，主第稱秦玉。',48,'全唐诗/poet.tang.5000.json','["公門襲漢環，主第稱秦玉。", "池架祥鱣序，山吹鳴鳳曲。", "拂席蘿薜垂，迴舟芰荷觸。", "平陽妙舞處，日暮清歌續。"]'),
('7d6f3ef1-39a0-4e48-95ea-4d012c92b4fa','采蓮曲','鄭愔','唐','唐诗','tang','','[]','錦䋏沙棠艦，羅帶石榴帬。',48,'全唐诗/poet.tang.5000.json','["錦䋏沙棠艦，羅帶石榴帬。", "綠潭采荷芰，清江日稍曛。", "魚鳥爭唼喋，花葉相芬氳。", "不覺芳洲暮，菱歌處處聞。"]'),
('79031f67-be20-4ef3-b01a-60eb5f5ea925','夜遊曲','鄭愔','唐','唐诗','tang','','[]','漢室歡娛盛，魏國文雅遒。',48,'全唐诗/poet.tang.5000.json','["漢室歡娛盛，魏國文雅遒。", "許史多暮宿，應陳從夜遊。", "西園讌公子，北里召王侯。", "詎似將軍獵，空嗟亭尉留。"]'),
('e1cbd3b8-b932-4503-9398-967fafbc301e','少年行','鄭愔','唐','唐诗','tang','','[]','潁川豪橫客，咸陽輕薄兒。',48,'全唐诗/poet.tang.5000.json','["潁川豪橫客，咸陽輕薄兒。", "田竇方貴幸，趙李新相知。", "軒蓋終朝集，笙竽此夜吹。", "黃金盈篋笥，白日忽西馳。"]'),
('29258541-edd2-4e50-846f-c27aec4b59c9','中宗降誕日長寧公主滿月侍宴應制','鄭愔','唐','唐诗','tang','','[]','春殿猗蘭美，仙階柏樹榮。',48,'全唐诗/poet.tang.5000.json','["春殿猗蘭美，仙階柏樹榮。", "地逢芳節應，時覩聖人生。", "月滿增祥莢，天長發瑞靈。", "南山遙可獻，常願奉皇明。"]'),
('877fdbe6-1d4f-42ef-9106-8237f10420ae','奉和幸上官昭容院獻詩四首 一','鄭愔','唐','唐诗','tang','','[]','地軸樓居遠，天台闕路賒。',48,'全唐诗/poet.tang.5000.json','["地軸樓居遠，天台闕路賒。", "何如遊帝宅，即此對仙家。", "座拂金壺電，池搖玉酒霞。", "無云秦漢隔，別訪武陵花。"]'),
('218bf439-8fbd-4ddb-b578-ecfb526f3c69','奉和幸上官昭容院獻詩四首 二','鄭愔','唐','唐诗','tang','','[]','堯茨姑射近，漢苑建章連。',48,'全唐诗/poet.tang.5000.json','["堯茨姑射近，漢苑建章連。", "十五蓂知月，三千桃紀年。", "鸞歌隨鳳吹，鶴舞向鵾弦。", "更覓瓊妃伴，來過玉女泉。"]'),
('44ec2fc1-0a4d-485e-bb79-eb05c147025a','奉和幸上官昭容院獻詩四首 三','鄭愔','唐','唐诗','tang','','[]','宮掖賢才重，山林高尚難。',48,'全唐诗/poet.tang.5000.json','["宮掖賢才重，山林高尚難。", "不言辭輦地，更有結廬歡。", "池棟清溫燠，巖窗起沍寒。", "幽亭有仙桂，聖主萬年看。"]'),
('d7e343ae-fa2c-4a4a-9b5e-e0e9550331ff','奉和幸上官昭容院獻詩四首 四','鄭愔','唐','唐诗','tang','','[]','槎流天上轉，茅宇禁中開。',48,'全唐诗/poet.tang.5000.json','["槎流天上轉，茅宇禁中開。", "河鵲填橋至，山熊避檻來。", "庭花采菉蓐，巖石步莓苔。", "願奉輿圖泰，長開錦翰裁。"]'),
('33e140e0-3364-4e31-b6fe-fc73eb7aa56b','送金城公主適西蕃應制','鄭愔','唐','唐诗','tang','','["\u9001\u522b", "\u4f24\u6000"]','下嫁戎庭遠，和親漢禮優。',48,'全唐诗/poet.tang.5000.json','["下嫁戎庭遠，和親漢禮優。", "笳聲出虜塞，簫曲背秦樓。", "貴主悲黃鶴，征人怨紫騮。", "皇情眷億兆，割念俯懷柔。"]'),
('083a696c-89c1-484d-9e86-96a93079f9aa','奉和幸望春宮送朔方大總管張仁亶','鄭愔','唐','唐诗','tang','','["\u9001\u522b", "\u4f24\u6000"]','御蹕下都門，軍麾出塞垣。',48,'全唐诗/poet.tang.5000.json','["御蹕下都門，軍麾出塞垣。", "長楊跨武騎，細柳接戎軒。", "睿曲風雲動，邊威鼓吹喧。", "坐帷將閫外，俱是報明恩。"]'),
('d734f531-6626-4892-85b2-b1c9dd67ac85','奉和九月九日登慈恩寺浮圖應制','鄭愔','唐','唐诗','tang','','[]','湧霄開寶塔，倒影駐仙輿。',48,'全唐诗/poet.tang.5000.json','["湧霄開寶塔，倒影駐仙輿。", "鴈子乘堂處，龍王起藏初。", "秋風聖主曲，佳氣史官書。", "願獻重陽壽，承歡萬歲餘。"]'),
('7c9f47d1-81e7-4cf0-bd23-0e8f7e76351f','銅雀妓','鄭愔','唐','唐诗','tang','','[]','日斜漳浦望，風起鄴臺寒。',48,'全唐诗/poet.tang.5000.json','["日斜漳浦望，風起鄴臺寒。", "玉座平生晚，金尊妓吹闌。", "舞餘依帳泣，歌罷向陵看。", "蕭索松風暮，愁煙入井闌。"]'),
('fdda7097-88e0-4e31-8cd1-3a08d472d029','胡笳曲','鄭愔','唐','唐诗','tang','','[]','漢將留邊朔，遙遙歲序深。',48,'全唐诗/poet.tang.5000.json','["漢將留邊朔，遙遙歲序深。", "誰堪牧馬思，正是胡笳吟。", "曲斷關山月，聲悲雨雪陰。", "傳書問蘇武，陵也獨何心。"]'),
('de8e32f9-2b0c-48e2-89a6-7ef1db382ee2','折楊柳','鄭愔','唐','唐诗','tang','','[]','青柳映紅顏，黃雲蔽紫關。',48,'全唐诗/poet.tang.5000.json','["青柳映紅顏，黃雲蔽紫關。", "忽聞邊使出，枝葉爲君攀。", "舞腰愁欲斷，春心望不還。", "風花滾成雪，羅綺亂斑斑。"]'),
('b84e25ca-6a35-40f4-8ddb-65f9a52d332c','秋閨','鄭愔','唐','唐诗','tang','','[]','征客向輪臺，幽閨寂不開。',48,'全唐诗/poet.tang.5000.json','["征客向輪臺，幽閨寂不開。", "音書秋鴈斷，機杼夜蛩催。", "虛幌風吹葉，閑階露濕苔。", "自憐愁思影，常共月裴回。"]'),
('c294f143-f783-4c4c-ba7a-36923e1b3428','人日重宴大明宮恩賜綵縷人勝應制','鄭愔','唐','唐诗','tang','','[]','瓊殿含光映早輪，玉鸞嚴蹕望初晨。',64,'全唐诗/poet.tang.5000.json','["瓊殿含光映早輪，玉鸞嚴蹕望初晨。", "池開凍水仙宮麗，樹發寒花禁苑新。", "佳氣裴回籠細網，殘霙淅瀝染輕塵。", "良時荷澤皆迎勝，窮谷晞陽猶未春。"]'),
('6d003eb8-81c0-44f2-947e-de5b97164299','奉和春日幸望春宮','鄭愔','唐','唐诗','tang','','[]','晨蹕凌高轉翠旌，春樓望遠背朱城。',64,'全唐诗/poet.tang.5000.json','["晨蹕凌高轉翠旌，春樓望遠背朱城。", "忽排花上遊天苑，却坐雲邊看帝京。", "百草香心初罥蝶，千林嫩葉始藏鶯。", "幸同葵藿傾陽早，願比盤根應候榮。"]'),
('3c5b156d-4240-4564-80cf-05df684b1800','奉和幸三會寺應制','鄭愔','唐','唐诗','tang','','[]','鳥籀遺新閣，龍旂訪古臺。',72,'全唐诗/poet.tang.5000.json','["鳥籀遺新閣，龍旂訪古臺。", "造書臣頡往，觀跡帝羲來。", "睿覽山川匝，宸心宇宙該。", "梵音隨駐輦，天步接乘杯。", "舊苑經寒露，殘池問劫灰。", "散花將捧日，俱喜聖慈開。"]'),
('3b940d2c-741a-4c49-b80b-a0d02ca62742','奉和幸大薦福寺','鄭愔','唐','唐诗','tang','','[]','舊邸三乘闢，佳辰萬騎留。',72,'全唐诗/poet.tang.5000.json','["舊邸三乘闢，佳辰萬騎留。", "蘭圖奉葉偈，芝蓋拂花樓。", "國會人王法，宮還天帝遊。", "紫雲成寶界，白水作禪流。", "鴈塔昌基遠，鸚林睿藻抽。", "欣承大風曲，竊預小童謳。"]'),
('38dad855-5955-4d1d-8395-07437cabcaba','同韋舍人早朝','鄭愔','唐','唐诗','tang','','[]','瑞闕龍居峻，宸庭鳳掖深。',72,'全唐诗/poet.tang.5000.json','["瑞闕龍居峻，宸庭鳳掖深。", "才良寄天綍，趨拜侶朝簪。", "飛馬看來影，喧車識駐音。", "重軒輕霧入，洞戶落花侵。", "聞有題新翰，依然想舊林。", "同聲慙卞玉，謬此托韋金。"]'),
('bc6163f1-aca1-413b-b6ec-df3dd84394ab','塞外三首 一','鄭愔','唐','唐诗','tang','','[]','塞外蕭條望，征人此路賒。',72,'全唐诗/poet.tang.5000.json','["塞外蕭條望，征人此路賒。", "邊聲亂朔馬，秋色引胡笳。", "遙嶂侵歸日，長城帶晚霞。", "斷蓬飛古戍，連鴈聚寒沙。", "海暗雲無葉，山春雪作花。", "丈夫期報主，萬里獨辭家。"]'),
('42964d1f-7861-457b-8a4c-ddb01c8e4161','塞外三首 二','鄭愔','唐','唐诗','tang','','[]','荒壘三秋夕，窮郊萬里平。',72,'全唐诗/poet.tang.5000.json','["荒壘三秋夕，窮郊萬里平。", "海陰凝獨樹，日氣下連營。", "戎斾霜旋重，邊裘夜更輕。", "將軍猶轉戰，都尉不成名。", "折柳悲春曲，吹笳斷夜聲。", "明年漢使返，須築受降城。"]'),
('6d4726a5-ff78-4354-986f-a7d08e3541bb','塞外三首 三','鄭愔','唐','唐诗','tang','','[]','陽鳥南飛夜，陰山北地寒。',72,'全唐诗/poet.tang.5000.json','["陽鳥南飛夜，陰山北地寒。", "漢家征戍客，年歲在樓蘭。", "玉塞朔風起，金河秋月團。", "邊聲入鼓吹，霜氣下旌竿。", "海外歸書斷，天涯旅鬢殘。", "子卿猶奉使，常向節旄看。"]'),
('de56b324-ae5c-4da5-a3d0-5a83a12ce7d5','春怨','鄭愔','唐','唐诗','tang','','["\u6625\u5929", "\u95fa\u6028"]','春朝物候妍，愁婦鏡臺前。',60,'全唐诗/poet.tang.5000.json','["春朝物候妍，愁婦鏡臺前。", "風吹數蝶亂，露洗百花鮮。", "試出褰羅幌，還來著錦筵。", "曲中愁夜夜，樓上別年年。", "不及隨蕭史，高飛向紫煙。"]'),
('49414dd2-2059-49c2-9852-771dde011ca2','貶降至汝州廣城驛','鄭愔','唐','唐诗','tang','','[]','近郊憑汝海，遐服指江干。',168,'全唐诗/poet.tang.5000.json','["近郊憑汝海，遐服指江干。", "尚憶趨朝貴，方知失路難。", "曙宮平樂遠，秋澤廣城寒。", "岸葦新花白，山梨晚葉丹。", "鄉關千里暮，歲序四時闌。", "函塞雲間別，旋門霧裏看。", "夙年追騄驥，暮節仰鵷鸞。", "疲駑勞垂耳，騫騰詎矯翰。", "將調梅鉉實，不正李園冠。", "荆玉終無玷，隨珠忽已彈。", "曉裝違鞏洛，夕夢在長安。", "北上頻傷阮，西征未學潘。", "傾車無共轍，同派有殊瀾。", "去去懷知己，何由報一餐。"]'),
('01c3c86a-f92b-4ec3-93e5-5251f52137c3','哭郎著作','鄭愔','唐','唐诗','tang','','[]','詩禮康成學，文章賈誼才。',72,'全唐诗/poet.tang.5000.json','["詩禮康成學，文章賈誼才。", "巳年人得夢，庚日鳥爲災。", "書草藏天閣，琴聲入夜臺。", "荒階羅駁蘚，虛座網浮埃。", "白馬賓徒散，青烏隴隧開。", "空憐門下客，懷舊幾遲迴。"]'),
('3a499396-f057-4ee3-bb52-07f1677178f1','詠黃鶯兒','鄭愔','唐','唐诗','tang','','[]','欲囀聲猶澀，將飛羽未調。',24,'全唐诗/poet.tang.5000.json','["欲囀聲猶澀，將飛羽未調。", "高風不借便，何處得遷喬。"]'),
('d819f0af-85d9-4951-8514-69b9fb3c4d66','百舌','鄭愔','唐','唐诗','tang','','[]','百舌鳴高樹，弄音無常則。',24,'全唐诗/poet.tang.5000.json','["百舌鳴高樹，弄音無常則。", "借問聲何煩，末俗不尚默。"]'),
('9474b09d-81ac-4734-82e5-2a5afcb30152','奉和聖製送張說上集賢學士賜宴','源乾曜','唐','唐诗','tang','','[]','盛業光書府，徵人盡國英。',72,'全唐诗/poet.tang.5000.json','["盛業光書府，徵人盡國英。", "絲綸賢得相，羣俊學爲名。", "寵命垂天錫，崇恩發睿情。", "熏風清禁籞，文殿述皇明。", "日霽庭陰出，池曛水氣生。", "歡娛此無限，詩酒自相迎。"]'),
('30873668-ceda-45c4-b3cd-7a48303bea39','奉和御製乾曜與張說宋璟同日上官命宴都堂賜詩','源乾曜','唐','唐诗','tang','','[]','睿作超千古，湛恩育萬人。',96,'全唐诗/poet.tang.5000.json','["睿作超千古，湛恩育萬人。", "遞遷俱荷澤，同拜忽爲鄰。", "道合徽音暢，芳辰景命新。", "鼓鐘崇享禮，鵷鷺集朝倫。", "竊位思官謗，凋容謝木春。", "慙多無以敘，拙備實難陳。", "進綬懷三少，承光盡百身。", "自當歸第日，何幸列宮臣。"]'),
('f2e49f26-7311-4e3e-8dbc-6dacb8baf4cb','奉和聖製送張尚書巡邊','源乾曜','唐','唐诗','tang','','[]','匈奴邇河朔，漢地須戎旅。',120,'全唐诗/poet.tang.5000.json','["匈奴邇河朔，漢地須戎旅。", "天子擇英才，朝端出監撫。", "流星下閶闔，寶鉞專公輔。", "禮物生光輝，宸章備恩詡。", "有征視矛戟，制勝唯樽俎。", "彼美何壯哉，桓桓擅斯舉。", "聲華振臺閣，功德標文武。", "奉國知命輕，忘家以身許。", "安人在勤恤，保大殫襟俯。", "此外無異言，同情報明主。"]'),
('2caf55bd-0b7a-475d-bfb6-d415d09bf010','禪社首樂章','源乾曜','唐','唐诗','tang','','[]','靈具醉，杳熙熙。',32,'全唐诗/poet.tang.5000.json','["靈具醉，杳熙熙。", "靈將往，眇禗禗。", "願明德，吐正詞。", "爛遺光，流禎祺。"]'),
('8448c1b4-de72-4f28-8380-5f7ec03343aa','奉和聖製送張說赴集賢院學士賜宴賦得虛字','徐堅','唐','唐诗','tang','','[]','崇文德化洽，新殿集賢初。',72,'全唐诗/poet.tang.5000.json','["崇文德化洽，新殿集賢初。", "庸菲參高選，首濫承明廬。", "殊私光輔弼，榮送列簪裾。", "座引中廚饌，杯錫上尊餘。", "翠葉濃丹苑，晴空卷碧虛。", "忝同文史地，願草登封書。"]'),
('b1e5c890-7ac5-4d56-a827-7a0f53a8423c','奉和聖製送張說巡邊','徐堅','唐','唐诗','tang','','[]','至德撫遐荒，神兵赴朔方。',120,'全唐诗/poet.tang.5000.json','["至德撫遐荒，神兵赴朔方。", "帝思元帥重，爰擇股肱良。", "累相承安世，深籌協子房。", "寄崇專斧鉞，禮備設壇場。", "鼙鼓喧雷電，戈劒凜風霜。", "四騑將戒道，十乘啓先行。", "聖錫加恆數，天文耀寵光。", "出郊開帳飲，寅餞盛離章。", "雨濯梅林潤，風清麥野涼。", "燕山應勒頌，麟閣佇名揚。"]'),
('8bba12cb-1ae4-41a5-9703-c386c8886cee','奉和送金城公主適西蕃應制','徐堅','唐','唐诗','tang','','[]','星漢下天孫，車服降殊蕃。',48,'全唐诗/poet.tang.5000.json','["星漢下天孫，車服降殊蕃。", "匣中詞易切，馬上曲虛繁。", "關塞移朱帳，風塵暗錦軒。", "簫聲去日遠，萬里望河源。"]'),
('cb7d5cc0-b4b6-49fa-95d0-a9d67836aa5b','餞許州宋司馬赴任','徐堅','唐','唐诗','tang','','[]','舊許星車轉，神京祖帳開。',48,'全唐诗/poet.tang.5000.json','["舊許星車轉，神京祖帳開。", "斷煙傷別望，零雨送離杯。", "辭燕依空遶，賓鴻入聽哀。", "分襟與秋氣，日夕共悲哉。"]'),
('5a9c7cf3-39a4-48f7-8636-27915ed0004e','餞唐永昌','徐堅','唐','唐诗','tang','','[]','郎官出宰赴伊瀍，征傳駸駸灞水前。',32,'全唐诗/poet.tang.5000.json','["郎官出宰赴伊瀍，征傳駸駸灞水前。", "此時悵望新豐道，握手相看共黯然。"]'),
('7d8e345e-97e3-452c-8771-b5409d20dbae','送考功武員外學士使嵩山置舍利塔歌','徐堅','唐','唐诗','tang','','[]','伊川別騎，灞岸分筵。',66,'全唐诗/poet.tang.5000.json','["伊川別騎，灞岸分筵。", "對三春之花月，覽千里之風煙。", "望青山兮分地，見白雲兮在天。", "寄愁心於樽酒，愴離緒於清弦。", "共握手而相顧，各銜悽而黯然。"]'),
('605462fe-3bcc-4503-a9ef-22ae16636dd2','櫂歌行','徐堅','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','櫂女飾銀鉤，新妝下翠樓。',108,'全唐诗/poet.tang.5000.json','["櫂女飾銀鉤，新妝下翠樓。", "霜絲青桂檝，蘭栧紫霞舟。", "水落金陵曙，風起洞庭秋。", "扣舷過曲浦，飛帆越回流。", "影入桃花浪，香飄杜若洲。", "洲長殊未返，蕭散雲霞晚。", "日下大江平，煙生歸岸遠。", "岸遠聞潮波，爭途遊戲多。", "因聲趙津女，來聽採菱歌。"]'),
('55d63d1d-9f85-40fc-9933-42120e54757d','送武進鄭明府','徐堅','唐','唐诗','tang','','[]','絃歌試宰日，城闕賞心違。',48,'全唐诗/poet.tang.5000.json','["絃歌試宰日，城闕賞心違。", "北謝蒼龍去，南隨黃鵠飛。", "夏雲海中出，吳山江上微。", "甿謠豈云遠，從此慶緇衣。"]'),
('da39b136-8fb0-493e-a1a5-4223bca03afc','儀坤廟樂章','徐堅','唐','唐诗','tang','','[]','於穆清廟，肅雍嚴祀。',20,'全唐诗/poet.tang.5000.json','["於穆清廟，肅雍嚴祀。", "合福受釐，介以繁祉。"]'),
('d2ee20f6-53b2-4743-836e-518ab9abe749','祭汾陰樂章','源光裕','唐','唐诗','tang','','[]','方丘既膳，嘉饗載謐。',40,'全唐诗/poet.tang.5000.json','["方丘既膳，嘉饗載謐。", "齋敬畢誠，陶匏貴質。", "秀畢豐薦，芳俎盈實。", "永永福流，其升如日。"]'),
('96575e78-6563-4419-8738-89a08b43f83f','奉和聖製送張說上集賢學士賜宴','李元紘','唐','唐诗','tang','','[]','碩儒延鳳沼，金馬被鴻私。',72,'全唐诗/poet.tang.5000.json','["碩儒延鳳沼，金馬被鴻私。", "饌玉趨丹禁，牋花降紫墀。", "銜恩傾旨酒，鼓舞詠康時。", "暫覯羣書緝，逾昭盛業丕。", "接筵欣有命，搦管媿無詞。", "自驚一何幸，太陽還及葵。"]'),
('10c1ed8b-a04a-4842-991e-2cf9b13209be','綠墀怨','李元紘','唐','唐诗','tang','','[]','征馬噪金珂，嫖姚向北河。',48,'全唐诗/poet.tang.5000.json','["征馬噪金珂，嫖姚向北河。", "綠苔行跡少，紅粉淚痕多。", "寶屋粘花絮，銀箏覆網羅。", "別君如昨日，青海雁頻過。"]'),
('124122ce-045f-48ca-808e-3dc8775246a8','相思怨','李元紘','唐','唐诗','tang','','[]','望月思氛氳，朱衾嬾更熏。',48,'全唐诗/poet.tang.5000.json','["望月思氛氳，朱衾嬾更熏。", "春生翡翠帳，花點石榴裠。", "燕語時驚妾，鶯啼轉憶君。", "交河一萬里，仍隔數重雲。"]'),
('92f7144c-b226-40e5-a28b-ae7789ab8c0c','奉和聖製送張說上集賢學士賜宴','裴漼','唐','唐诗','tang','','[]','問道圖書盛，尊儒禮教興。',72,'全唐诗/poet.tang.5000.json','["問道圖書盛，尊儒禮教興。", "石渠因學廣，金殿爲賢昇。", "日月恩光照，風雲寵命膺。", "謀謨言可範，舟檝事斯憑。", "宴喜明時洽，光輝湛露凝。", "大哉堯作主，天下頌歌稱。"]'),
('8999600e-5b3f-44a0-9c15-a8b309a2f3c0','奉和御製旋師喜捷','裴漼','唐','唐诗','tang','','[]','殊類驕無長，王師示有征。',48,'全唐诗/poet.tang.5000.json','["殊類驕無長，王師示有征。", "中軍纔受律，妖寇已亡精。", "斬虜還遮塞，綏降更築城。", "從來攻必克，天策振奇兵。"]'),
('4391aa73-8756-404c-937f-e99263585e26','奉和御製平胡','裴漼','唐','唐诗','tang','','[]','玄漠聖恩通，由來書軌同。',96,'全唐诗/poet.tang.5000.json','["玄漠聖恩通，由來書軌同。", "忽聞窺月滿，相聚寇雲中。", "廟略占黃氣，神兵出絳宮。", "將軍行逐虜，使者亦和戎。", "一舉轒輼滅，再麾沙漠空。", "直將威禁暴，非用武爲雄。", "飲至明軍禮，醻勳錫武功。", "干戈還載戢，文德在唐風。"]'),
('ee5bd665-80a6-43ef-b098-dc72dd829139','奉和聖製龍池篇','裴漼','唐','唐诗','tang','','[]','乾坤啓聖吐龍泉，泉水年年勝一年。',64,'全唐诗/poet.tang.5000.json','["乾坤啓聖吐龍泉，泉水年年勝一年。", "始看魚躍方成海，即覩飛龍利在天。", "洲渚遙將銀漢接，樓臺直與紫微連。", "休氣榮光恆不散，懸知此地是神仙。"]'),
('4595908c-a166-442c-ac0a-afee0f0defdd','奉和聖製送張說上集賢學士賜宴','劉昇','唐','唐诗','tang','','[]','圖書應明主，策府宴嘉賓。',72,'全唐诗/poet.tang.5000.json','["圖書應明主，策府宴嘉賓。", "台曜臨東壁，乾光自北辰。", "網羅窮象繫，述作究天人。", "聖酒千鍾洽，仙廚百味陳。", "成山徒可仰，涉海詎知津。", "幸逢文教盛，還覩頌聲新。"]'),
('0d53059c-8668-4c0d-a0cb-5bcbe08248de','奉和聖製送張說上集賢學士賜宴','蕭嵩','唐','唐诗','tang','','[]','帝曰簡才能，旌賢在股肱。',72,'全唐诗/poet.tang.5000.json','["帝曰簡才能，旌賢在股肱。", "文章體一變，禮樂道逾弘。", "芸閣英華入，賓門鵷鷺登。", "恩筵過所望，聖澤實超恆。", "夏葉開紅藥，餘花發紫藤。", "微臣亦何幸，叨此預文朋。"]'),
('7a48b1b7-3c37-4c8a-9a7e-faa8df549996','奉和御製左丞相說右丞相璟太子少傅乾曜同日上官命宴都堂賜詩','蕭嵩','唐','唐诗','tang','','[]','審官思共理，多士屬惟唐。',96,'全唐诗/poet.tang.5000.json','["審官思共理，多士屬惟唐。", "歷選台庭舊，來熙帝業昌。", "入朝師百辟，論道協三光。", "垂拱咨元老，親賢輔少陽。", "登庸崇禮送，寵德耀宸章。", "御酒飛觴洽，仙闈雅樂張。", "荷恩思有報，陳力媿無良。", "願罄公忠節，同心奉我皇。"]'),
('f5071e7f-1a10-4fba-9b62-3279fecfdcd1','奉和聖製送張說上集賢學士賜宴','韋抗','唐','唐诗','tang','','[]','廣庭臨璧沼，多士侍金閨。',72,'全唐诗/poet.tang.5000.json','["廣庭臨璧沼，多士侍金閨。", "英宰文儒叶，明君日月齊。", "集賢光首拜，改殿發新題。", "早夏初移律，餘花尚拂溪。", "壺觴接雲上，經術引關西。", "聖德鴻名遠，將陪玉檢泥。"]'),
('6c5b6a30-130d-4f9a-9e85-c3e5bc9522be','奉和聖製送張說上集賢學士賜宴','李暠','唐','唐诗','tang','','[]','偃武堯風接，崇文漢道恢。',72,'全唐诗/poet.tang.5000.json','["偃武堯風接，崇文漢道恢。", "集賢更內殿，清選自中台。", "佐命留侯業，詞華博物才。", "天廚千品降，御酒百壺催。", "鵷鷺方成列，神仙喜暫陪。", "復欣同拜首，叨此頌良哉。"]'),
('3b115a49-2dcc-445a-96c2-4e9129d8a72f','奉和聖製送張說上集賢學士賜宴','韋述','唐','唐诗','tang','','[]','修文中禁啓，改字令名加。',72,'全唐诗/poet.tang.5000.json','["修文中禁啓，改字令名加。", "台座徵人傑，書坊應國華。", "賦詩開廣宴，賜酒酌流霞。", "雲散明金闕，池開照玉沙。", "掖垣留宿鳥，溫樹落餘花。", "謬此天光及，銜恩醉日斜。"]'),
('13cbd4e0-e3f8-41a9-bf75-39f175bf6c34','晚渡伊水','韋述','唐','唐诗','tang','','[]','悠悠涉伊水，伊水清見石。',120,'全唐诗/poet.tang.5000.json','["悠悠涉伊水，伊水清見石。", "是時春向深，兩岸草如積。", "迢遰望洲嶼，逶迤亙津陌。", "新樹落疎紅，遙原上深碧。", "回瞻洛陽苑，遽有長山隔。", "煙霧猶辨家，風塵已爲客。", "登陟多異趣，往來見行役。", "雲起早已昏，鳥飛日將夕。", "光陰逝不借，超然慕疇昔。", "遠游亦何爲？歸來存竹帛。"]'),
('4b88ea4a-692e-4d91-9bc3-c6e89d65d6ca','春日山莊','韋述','唐','唐诗','tang','','[]','初歲開韶月，田家喜載陽。',48,'全唐诗/poet.tang.5000.json','["初歲開韶月，田家喜載陽。", "晚晴搖水態，遲景蕩山光。", "浦淨漁舟遠，花飛樵路香。", "自然成野趣，都使俗情忘。"]'),
('90f239b1-7810-42cb-a91a-6aff697f6696','廣陵送別宋員外佐越鄭舍人還京','韋述','唐','唐诗','tang','','[]','朱紱臨秦望，皇華赴洛橋。',48,'全唐诗/poet.tang.5000.json','["朱紱臨秦望，皇華赴洛橋。", "文章南渡越，書奏北歸朝。", "樹入江雲盡，城銜海月遙。", "秋風將客思，川上晚蕭蕭。"]'),
('e62bcd28-f094-44e7-89a6-3ada42c24b9e','奉和聖製送張說上集賢學士賜宴','陸堅','唐','唐诗','tang','','[]','聖主崇文教，層霄降德音。',72,'全唐诗/poet.tang.5000.json','["聖主崇文教，層霄降德音。", "尊賢澤既厚，式宴寵逾深。", "復有夔龍相，良哉簡帝心。", "得人惟邁昔，多士諒推今。", "書殿榮光滿，儒門喜氣臨。", "顧惟誠濫吹，徒此接衣簪。"]'),
('f9e4128d-2ed0-4356-917c-ca2e67d4a0bb','句 千秋節應制','陸堅','唐','唐诗','tang','','[]','風移覃土宇，雲上浹羣臣。',12,'全唐诗/poet.tang.5000.json','["風移覃土宇，雲上浹羣臣。"]'),
('337e560d-f0eb-489f-8b80-4ecca434391a','奉和聖製送張說上集賢學士賜宴','程行諶','唐','唐诗','tang','','[]','聖主崇文化，鏘鏘得盛才。',72,'全唐诗/poet.tang.5000.json','["聖主崇文化，鏘鏘得盛才。", "相因歸夢立，殿以集賢開。", "象繫微言闡，詩書至道該。", "堯尊承帝澤，禹膳自天來。", "禮洽歡逾長，風恬暑更迴。", "國朝將舜頌，同是一康哉。"]'),
('6e9a6235-fc3f-40c9-b123-6d9e5f7560d8','奉和聖製送張說上集賢學士賜宴','褚秀','唐','唐诗','tang','','[]','講習延東觀，趨陪盛北宮。',72,'全唐诗/poet.tang.5000.json','["講習延東觀，趨陪盛北宮。", "惟師恢帝則，敷教叶天工。", "宣室恩嘗異，金華禮更崇。", "洞門清永日，華綬接微風。", "萐降堯廚翠，榴開舜酒紅。", "文思光萬宇，高議待升中。"]'),
('06fa004f-d3f2-49ec-9721-24c48152cc37','奉和御製左丞相說右丞相璟太子少傅乾曜同日上官命都堂賜詩','裴光庭','唐','唐诗','tang','','[]','樂賢聞往誥，褒德偶茲辰。',98,'全唐诗/poet.tang.5000.json','["樂賢聞往誥，褒德偶茲辰。", "端揆升元老，師謀擇累仁。", "紫庭崇讓畢，粉署禮容陳。", "既荷恩榮舊，俱承寵命新。", "天文懸瑞色，聖酒汎華茵。", "雜遝喧簫鼓，歡娛洽搢紳。", "掖垣招近侍，虛薄[廁]清塵。", "共保堅貞節，常期雨露均。"]'),
('82368b5a-e0a0-4758-96d3-09bc84096ca9','奉和聖製左丞相說右丞相璟太子少傅乾曜同日上官命宴都堂賜詩','宇文融','唐','唐诗','tang','','[]','申甫生周日，宣慈舉舜年。',96,'全唐诗/poet.tang.5000.json','["申甫生周日，宣慈舉舜年。", "何如偶昌運，比德邁前賢。", "寵獲元良密，榮瞻端揆遷。", "職優三事老，位在百僚先。", "北極迴宸渥，南宮飾御筵。", "飛文瑤札降，賜酒玉杯傳。", "謬列台衡重，俱承雨露偏。", "誓將同竭力，相與效塵涓。"]'),
('6ce86466-e25b-435e-b4f0-af476ada09cb','奉和聖製同二相已下羣官樂游園宴','崔沔','唐','唐诗','tang','','[]','五日酺纔畢，千年樂未央。',72,'全唐诗/poet.tang.5000.json','["五日酺纔畢，千年樂未央。", "復承天所賜，終宴國之陽。", "地勝春逾好，恩深樂更張。", "落花飛廣座，垂柳拂行觴。", "庶尹陪三史，諸侯具萬方。", "酒酣同抃躍，歌舞詠時康。"]'),
('73fcfbdf-bb02-4490-a7bf-5ed9819a3ac2','奉和聖製同二相已下羣臣樂游園宴','崔尚','唐','唐诗','tang','','[]','春日照長安，皇恩寵庶官。',72,'全唐诗/poet.tang.5000.json','["春日照長安，皇恩寵庶官。", "合錢承罷宴，賜帛復追歡。", "供帳憑高列，城池入迥寬。", "花催相國醉，鳥和樂人彈。", "北闕雲中見，南山樹杪看。", "樂游宜締賞，舞詠惜將闌。"]'),
('4d5936ea-0964-4f20-9aeb-b629964cd727','奉和聖製同二相以下羣官樂游園宴','胡皓','唐','唐诗','tang','','[]','五酺終宴集，三錫又歡娛。',72,'全唐诗/poet.tang.5000.json','["五酺終宴集，三錫又歡娛。", "仙阜崇高異，神州眺覽殊。", "南山臨皓雪，北闕對明珠。", "廣座鵷鴻滿，昌庭駟馬趨。", "綺羅含草樹，絲竹吐郊衢。", "銜杯不能罷，歌舞樂唐虞。"]'),
('eb0f5fb9-dd8e-45a6-99f1-725eeccee708','奉和聖製送張尚書巡邊','胡皓','唐','唐诗','tang','','[]','燕公爲漢將，武德奉文思。',120,'全唐诗/poet.tang.5000.json','["燕公爲漢將，武德奉文思。", "利用經戎莽，英圖叶聖詒。", "塞沙制長策，窮石卷搖旗。", "萬里要相賀，三邊又在茲。", "稜威方逐逐，談笑坐怡怡。", "寵餞紛郊道，充廚竭御司。", "嘗醪企行邁，聽樂罷漣洏。", "衮旒垂翰墨，纓蕤迭賦詩。", "金山無積阻，玉樹有華滋。", "請迨炎風暮，歸旌候此時。"]'),
('0603e48a-3ed6-465a-ab42-6a89e8d198dd','和宋之問寒食題臨江驛','胡皓','唐','唐诗','tang','','["\u5bd2\u98df\u8282", "\u611f\u4f24"]','聞道山陰會，仍爲火忌辰。',48,'全唐诗/poet.tang.5000.json','["聞道山陰會，仍爲火忌辰。", "途中甘棄日，江上苦傷春。", "流水飜催淚，寒灰更伴人。", "丹心終不改，白髮爲誰新。"]'),
('75d52b0f-5f08-493c-ad13-74e8ca3a2a95','出峽','胡皓','唐','唐诗','tang','','[]','巴東三峽盡，曠望九江開。',48,'全唐诗/poet.tang.5000.json','["巴東三峽盡，曠望九江開。", "楚塞雲中出，荆門水上來。", "魚龍潛嘯雨，鳧雁動成雷。", "南國秋風晚，客思幾悠哉。"]'),
('6f6f6922-932e-45ff-a88b-48f40d12fa5b','同蔡孚起居詠鸚鵡','胡皓','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','鸚鵡殊姿致，鸞皇得比肩。',48,'全唐诗/poet.tang.5000.json','["鸚鵡殊姿致，鸞皇得比肩。", "常尋金殿裏，每話玉階前。", "賈誼才方達，揚雄老未遷。", "能言既有地，何惜爲聞天。"]'),
('a9fabab9-0c8d-42d4-bed2-1cb0ffd1305c','大漠行','胡皓','唐','唐诗','tang','','[]','單于犯薊堧，虜騎略蕭邊。',288,'全唐诗/poet.tang.5000.json','["單于犯薊堧，虜騎略蕭邊。", "南山木葉飛下地，北海蓬根亂上天。", "科斗連營太原道，魚麗合陣武威川。", "三軍遙倚伏，萬里相馳逐。", "旌斾悠悠靜潮源，鼙鼓喧喧動盧谷。", "窮徼出幽陵，吁嗟倦寢興。", "馬蹄凍溜石，胡毳煖生冰。", "雲沙泱漭天光閉，河塞陰沈海色凝。", "崆峒北國誰能託，蕭索邊心常不樂。", "近見行人畏白龍，遙聞公主愁黃鶴。", "陽春半，岐路間，瑤臺苑，玉門關。", "百花芳樹紅將歇，二月蘭臯綠未還。", "陣雲不散魚龍水，雨雪猶飛鴻鵠山。", "山嶂緜連那可極，路遠辛勤夢顏色。", "北堂萱草不寄來，東園桃李長相憶。", "漢將紛紜攻戰盈，胡寇蕭條幽朔清。", "韓昌拜節偏知送，鄭吉驅旌坐見迎。", "火絕煙沈左西極，谷靜山空右北平。", "但得將軍能百勝，不須天子築長城。"]'),
('850a485d-6f69-44ea-96bf-a507f8aa1fbb','朝退','李適之','唐','唐诗','tang','','[]','朱門長不閉，親友恣相過。',24,'全唐诗/poet.tang.5000.json','["朱門長不閉，親友恣相過。", "年今將半百，不樂復如何。"]'),
('3cc2e99a-ef51-4c6c-a86c-beb89f8c9b81','罷相作','李適之','唐','唐诗','tang','','[]','避賢初罷相，樂聖且銜杯。',24,'全唐诗/poet.tang.5000.json','["避賢初罷相，樂聖且銜杯。", "爲問門前客，今朝幾箇來。"]'),
('14631ff0-8fb9-4d70-b3d7-ca2d31eaecba','題漢州西湖','房琯','唐','唐诗','tang','','["\u897f\u6e56"]','高流纏峻隅，城下緬丘墟。',120,'全唐诗/poet.tang.5000.json','["高流纏峻隅，城下緬丘墟。", "決渠信浩蕩，潭島成江湖。", "結宇依迴渚，水中信可居。", "三伏氣不蒸，四達暑自徂。", "同人千里駕，鄰國五馬車。", "月出共登舟，風生隨所如。", "舉麾指極浦，欲極更盤紆。", "繚繞各殊致，夜盡情有餘。", "遭亂意不開，即理還暫祛。", "安得長晤語，使我憂更除。"]'),
('126eccee-4aa4-47d4-b207-0d3c36a7ec51','詠方圓動靜','李泌','唐','唐诗','tang','','[]','方如行義，圓如用智。',20,'全唐诗/poet.tang.5000.json','["方如行義，圓如用智。", "動如逞才，靜如遂意。"]'),
('a85c8e21-b706-4511-aaa4-39447568a11b','長歌行','李泌','唐','唐诗','tang','','[]','天覆吾，地載吾，天地生吾有意無。',80,'全唐诗/poet.tang.5000.json','["天覆吾，地載吾，天地生吾有意無。", "不然絕粒昇天衢，不然鳴珂遊帝都。", "焉能不貴復不去，空作昂藏一丈夫。", "一丈夫兮一丈夫，千生氣志是良圖。", "請君看取百年事，業就扁舟泛五湖。"]'),
('5b7402d5-8836-4962-9e46-ce0d04fa3c53','奉和聖製中和節曲江宴百僚','李泌','唐','唐诗','tang','','[]','風俗時有變，中和節惟新。',60,'全唐诗/poet.tang.5000.json','["風俗時有變，中和節惟新。", "軒車雙闕下，宴會曲江濱。", "金石何鏗鏘，簪纓亦紛綸。", "皇恩降自天，品物感知春。", "慈恩匝寰瀛，歌詠同君臣。"]'),
('9ee1065e-adba-4eda-bec9-2b69c95bab2c','奉和聖製重陽賜會聊示所懷','李泌','唐','唐诗','tang','','["\u6292\u6000", "\u91cd\u9633\u8282"]','大唐造昌運，品物荷時成。',60,'全唐诗/poet.tang.5000.json','["大唐造昌運，品物荷時成。", "乘秋逢令節，錫宴歡羣情。", "俯臨秦山川，高會漢公卿。", "未追赤松子，且泛黃菊英。", "賡歌聖人作，海內同休明。"]'),
('733cf267-5516-4f52-8110-518c913fe478','句','李泌','唐','唐诗','tang','','[]','青青東門柳，歲晏復憔悴。',40,'全唐诗/poet.tang.5000.json','["青青東門柳，歲晏復憔悴。", "良弓摧折久，誰識是龍韜。", "旋沫翻成碧玉池，添酥散出琉璃眼。"]'),
('79a24c06-2170-401e-ab36-9e7760b2b2a5','享太廟樂章 廣運舞','郭子儀','唐','唐诗','tang','','[]','於赫皇祖，昭明有融。',40,'全唐诗/poet.tang.5000.json','["於赫皇祖，昭明有融。", "惟文之德，惟武之功。", "河海靜謐，車書混同。", "虔恭孝饗，穆穆玄風。"]'),
('8d22864e-294b-442e-a53d-b381cfc59f81','享太廟樂章 保大舞','郭子儀','唐','唐诗','tang','','[]','於穆文考，聖神昭彰。',40,'全唐诗/poet.tang.5000.json','["於穆文考，聖神昭彰。", "簫勺羣慝，含光遠方。", "萬物茂遂，九夷賓王。", "愔愔雲韶，德音不忘。"]'),
('a73c2e95-76f7-41c9-ae8f-6853bf0bf1a2','百子池','張諤','唐','唐诗','tang','','[]','舊聞百子漢家池，漢家淥水今逶迤。',32,'全唐诗/poet.tang.5000.json','["舊聞百子漢家池，漢家淥水今逶迤。", "宮女厭鏡笑窺池，身前影後不相見。"]'),
('72d603a6-a1b8-4629-9d88-7fe380b38b3d','東封山下宴羣臣','張諤','唐','唐诗','tang','','[]','萬里扈封巒，羣公遇此歡。',48,'全唐诗/poet.tang.5000.json','["萬里扈封巒，羣公遇此歡。", "幔城連夜靜，霜仗滿空寒。", "輦路宵煙合，旌門曉月殘。", "明朝陪聖主，山下禮圓壇。"]'),
('760c54f2-b48b-4e5f-8a4b-771629364989','三日岐王宅','張諤','唐','唐诗','tang','','[]','玉女貴妃生，嫛婗始發聲。',48,'全唐诗/poet.tang.5000.json','["玉女貴妃生，嫛婗始發聲。", "金盆浴未了，綳子繡初成。", "翡翠雕芳縟，真珠帖小纓。", "何時學健步？鬬取落花輕。"]'),
('c97842eb-4af6-42a8-b1a1-5539bde31aa5','滿月','張諤','唐','唐诗','tang','','[]','社金流茂祉，庭玉表奇才。',48,'全唐诗/poet.tang.5000.json','["社金流茂祉，庭玉表奇才。", "竹似因談植，蘭疑入夢栽。", "烏將八子去，鳳逐九雛來。", "今夜明珠色，當隨滿月開。"]'),
('eda88b0f-c62a-45ef-84f5-f60e86a5bc28','岐王山亭','張諤','唐','唐诗','tang','','[]','王家傍綠池，春色正相宜。',48,'全唐诗/poet.tang.5000.json','["王家傍綠池，春色正相宜。", "豈有樓臺好，兼看草樹奇。", "石榴天上葉，椰子日南枝。", "出入千門裏，年年樂未移。"]'),
('738332fd-e464-47c5-854a-3c8907c0420e','岐王席上詠美人','張諤','唐','唐诗','tang','','[]','半額畫雙蛾，盈盈燭下歌。',48,'全唐诗/poet.tang.5000.json','["半額畫雙蛾，盈盈燭下歌。", "玉杯寒意少，金屋夜情多。", "香豔王分帖，裙嬌敕賜羅。", "平陽莫相妬，喚出不如他。"]'),
('f49af9d0-bd59-4ea7-b187-d2e680706d33','還京','張諤','唐','唐诗','tang','','[]','朱紱臨秦望，皇華赴洛橋。',48,'全唐诗/poet.tang.5000.json','["朱紱臨秦望，皇華赴洛橋。", "文章南渡越，書奏北歸朝。", "樹入江雲盡，城銜海月遙。", "秋風將客思，川上晚蕭蕭。"]'),
('b9b88e5e-5909-4b37-9c3d-8a5c3641f396','贈吏部孫員外濟','張諤','唐','唐诗','tang','','[]','天子愛賢才，星郎入拜來。',48,'全唐诗/poet.tang.5000.json','["天子愛賢才，星郎入拜來。", "明光朝半下，建禮直初迴。", "名帶含香發，文隨綺幕開。", "披雲自有鏡，從此照仙臺。"]'),
('d9eeda00-1160-4028-a848-1a0b83017c80','送李著作倅杭州','張諤','唐','唐诗','tang','','[]','輟史空三署，題輿佐一方。',48,'全唐诗/poet.tang.5000.json','["輟史空三署，題輿佐一方。", "祖筵開霽景，征陌直朝光。", "水陸風煙隔，秦吳道路長。", "佇聞敷善政，邦國詠惟康。"]'),
('394fd898-f9e3-4e52-be36-ce140b3f5992','九日','張諤','唐','唐诗','tang','','[]','秋來林下不知春，一種佳遊事也均。',64,'全唐诗/poet.tang.5000.json','["秋來林下不知春，一種佳遊事也均。", "絳葉從朝飛著夜，黃花開日未成旬。", "將曛陌樹頻驚鳥，半醉歸途數問人。", "城遠登高倂九日，茱萸凡作幾年新。"]'),
('c869f274-e9ed-452a-b3b6-fa246a95be0d','延平門高齋亭子應岐王教','張諤','唐','唐诗','tang','','[]','花源藥嶼鳳城西，翠幕紗窗鶯亂啼。',64,'全唐诗/poet.tang.5000.json','["花源藥嶼鳳城西，翠幕紗窗鶯亂啼。", "昨夜蒲萄初上架，今朝楊柳半垂堤。", "片片仙雲來渡水，雙雙燕子共銜泥。", "請語東風催後騎，倂將歌舞向前谿。"]'),
('98f11149-ee2c-4a9f-b909-cdadce36d2fa','九日宴','張諤','唐','唐诗','tang','','[]','秋葉風吹黃颯颯，晴雲日照白鱗鱗。',32,'全唐诗/poet.tang.5000.json','["秋葉風吹黃颯颯，晴雲日照白鱗鱗。", "歸來得問茱萸女，今日登高醉幾人。"]'),
('1d108c7f-8c11-48b0-98d0-315baf79b9e6','從軍','劉庭琦','唐','唐诗','tang','','["\u6cf0\u5c71"]','朔風吹寒塞，胡沙千萬里。',48,'全唐诗/poet.tang.5000.json','["朔風吹寒塞，胡沙千萬里。", "陣雲出岱山，孤月生海水。", "決勝方求敵，銜恩本輕死。", "蕭蕭牧馬鳴，中夜拔劒起。"]'),
('6f234307-50b8-4f01-8dfe-fba9acd9cc7a','奉和聖製瑞雪篇','劉庭琦','唐','唐诗','tang','','[]','紫宸飛雪曉裴回，層閣重門雪照開。',176,'全唐诗/poet.tang.5000.json','["紫宸飛雪曉裴回，層閣重門雪照開。", "九衢皛耀浮埃盡，千品差池贄帛來。", "何處田中非種玉，誰家院裏不生梅？", "埋雲翳景無窮已，因風落地吹還起。", "先過翡翠寶房中，轉入鴛鴦金殿裏。", "美人含笑出聯翩，豔逸相輕鬬容止。", "羅衣點著渾是花，玉手摶來半成水。", "奕奕紛紛何所如，頓憶楊園二月初。", "羞同班女高秋扇，欲照明王乙夜書。", "姑射山中符聖壽，芙蓉闕下降神車。", "願隨睿澤流無限，長報豐年貴有餘。"]'),
('476908f1-15ce-4d83-a8b8-178a866d9f39','詠木槿樹題武進文明府廳','劉庭琦','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','物情良可見，人事不勝悲。',24,'全唐诗/poet.tang.5000.json','["物情良可見，人事不勝悲。", "莫恃朝榮好，君看暮落時。"]'),
('409480c8-adcb-41b6-bd7b-33693b76b64a','銅雀臺','劉庭琦','唐','唐诗','tang','','[]','銅臺宮觀委灰塵，魏主園林漳水濱。',32,'全唐诗/poet.tang.5000.json','["銅臺宮觀委灰塵，魏主園林漳水濱。", "即今西望猶堪思，況復當時歌舞人。"]'),
('097b2ef7-d98e-4ece-afdf-d271139ec20e','失白鷹','鄭繇','唐','唐诗','tang','','[]','白錦文章亂，丹霄羽翮齊。',36,'全唐诗/poet.tang.5000.json','["白錦文章亂，丹霄羽翮齊。", "雲中呼暫下，雪裏放還迷。", "梁苑驚池鶩，陳倉拂野雞。"]'),
('0486e63b-397b-448f-ad85-88e59a524ced','經慈澗題','鄭繇','唐','唐诗','tang','','[]','岸與恩同廣，波將慈共深。',24,'全唐诗/poet.tang.5000.json','["岸與恩同廣，波將慈共深。", "涓涓勞日夜，長似下流心。"]'),
('39a1c0f9-bf83-443e-b84e-62c7e7fd6fa2','奉和御製平胡','韓休','唐','唐诗','tang','','[]','南牧正紛紛，長河起塞氛。',96,'全唐诗/poet.tang.5000.json','["南牧正紛紛，長河起塞氛。", "玉符徵選士，金鉞拜將軍。", "疊鼓搖邊吹，連旌暗朔雲。", "祅星乘夜落，害氣入朝分。", "始見幽烽警，俄看烈火焚。", "功成奏凱樂，戰罷策歸勳。", "盛德陳清廟，神謨屬大君。", "叨榮逢偃羽，率舞詠時文。"]'),
('f4c506d3-0f24-44ae-96a8-65e68849a0be','奉和聖製送張說巡邊','韓休','唐','唐诗','tang','','[]','一德光台象，三軍掌夏卿。',120,'全唐诗/poet.tang.5000.json','["一德光台象，三軍掌夏卿。", "來威申廟略，出總叶師貞。", "受鉞辭金殿，憑軒去鼎城。", "曙光搖組甲，疎吹繞雲旌。", "左律方先凱，中鼙即訓兵。", "定功彰武事，陳頌紀天聲。", "祖宴初留賞，宸章更寵行。", "車徒零雨送，林野夕陰生。", "路極河流遠，川長朔氣平。", "南轅遲返斾，歸奏謁承明。"]'),
('335c8817-702f-479e-ac93-3e5a24681f49','祭汾陰樂章','韓休','唐','唐诗','tang','','[]','於穆濬哲，維清緝熙。',40,'全唐诗/poet.tang.5000.json','["於穆濬哲，維清緝熙。", "肅事昭配，永言孝思。", "滌濯靜嘉，馨香在茲。", "神之聽之，用受福釐。"]'),
('feb96a9b-0a04-4a7f-9944-a3f641aaf9f0','徵君宅','許景先','唐','唐诗','tang','','[]','徵君昔嘉遯，抗跡遺俗塵。',168,'全唐诗/poet.tang.5000.json','["徵君昔嘉遯，抗跡遺俗塵。", "了心悟有物，乘化遊無垠。", "道喪歷千載，復存潁陽真。", "上虞佳山水，晚歲耽隱淪。", "內史既解綬，支公亦相親。", "儒道匪遠理，意勝聊自欣。", "洄沿南谿夕，流浪東山春。", "石壁踐丹景，金潭冒綠蘋。", "探鍊備海嶠，賞心寓情人。", "奈何靈仙骨，鍬翮瑤池津。", "寥寥虛白宇，夙剏招提因。", "家風緬多尚，玄德謝無鄰。", "謬陪金門彥，矯跡侍紫宸。", "皇恩竟已矣，遺烈庶不泯。"]'),
('fdef87c4-ea2c-4314-a05c-c2a3a2020d5b','折柳篇','許景先','唐','唐诗','tang','','[]','春色東來度渭橋，青門垂柳百千條。',144,'全唐诗/poet.tang.5000.json','["春色東來度渭橋，青門垂柳百千條。", "長楊西連建章路，漢家林苑紛無數。", "縈花始遍合歡枝，遊絲半罥相思樹。", "春樓初日照南隅，柔條垂綠掃金鋪。", "寶釵新梳倭墮髻，錦帶交垂連理襦。", "自憐柳塞淹戎幕，銀燭長啼愁夢著。", "芳樹朝催玉管新，春風夜染羅衣薄。", "城頭楊柳已如絲，今年花落去年時。", "折芳遠寄相思曲，爲惜容華難再持。"]'),
('05f82d30-58ac-461b-bc36-ec76ce48811d','奉和御製春臺望','許景先','唐','唐诗','tang','','[]','睿德在青陽，高居視中縣。',204,'全唐诗/poet.tang.5000.json','["睿德在青陽，高居視中縣。", "秦城連鳳闕，漢寢疏龍殿。", "文物照光輝，郊畿鬱葱蒨。", "千門望成錦，八水明如練。", "複道曉光披，宸遊出禁移。", "瑞氣朝浮五雲閣，祥光夜吐萬年枝。", "蘭葉負龜初薦祉，桐花集鳳更來儀。", "秦漢生人凋力役，阿房甘泉構雲碧。", "汾祠雍畤望通天，玉堂宣室坐長年。", "鼓鐘西接咸陽觀，苑囿南通鄠杜田。", "明主卑宮誡前失，輔德欽賢政惟一。", "昆蟲不夭在春蒐，稼穡常艱重農術。", "邦家已荷聖謨新，猶聞儉陋惜中人。", "豫奉北辰齊七政，長歌東武抃千春。"]'),
('cee76afb-0fad-4e36-b901-da622b03df46','陽春怨','許景先','唐','唐诗','tang','','[]','紅樹曉鶯蹄，春風暖翠閨。',48,'全唐诗/poet.tang.5000.json','["紅樹曉鶯蹄，春風暖翠閨。", "雕籠熏繡被，珠履踏金堤。", "芍藥花初吐，菖蒲葉正齊。", "藁砧當此日，行役向遼西。"]'),
('c23c5496-030a-4a54-8d35-948712d74756','奉和聖製送張尚書巡邊','許景先','唐','唐诗','tang','','[]','文武承邦式，風雲感國禎。',120,'全唐诗/poet.tang.5000.json','["文武承邦式，風雲感國禎。", "王師親賦政，廟略久論兵。", "漢主知三傑，周官統六卿。", "四方分閫受，千里坐謀成。", "介胄辭前殿，壺觴宿左營。", "賞延頒賜重，宸贈出車榮。", "龍武三軍氣，魚鈴五校名。", "郊雲駐旌羽，邊吹引金鉦。", "訓旅方稱德，安人更克貞。", "佇看銘石罷，同聽凱歌聲。"]'),
('a13f9919-7528-4a5d-8347-c7a862412b89','詠史','王丘','唐','唐诗','tang','','[]','高潔非養正，盛名亦險艱。',96,'全唐诗/poet.tang.5000.json','["高潔非養正，盛名亦險艱。", "偉哉謝安石，攜妓入東山。", "雲巖響金奏，空水灧朱顏。", "蘭露滋香澤，松風鳴珮環。", "歌聲入空盡，舞影到池閑。", "杳眇同天上，繁華非代間。", "卷舒混名跡，縱誕無憂患。", "何必蘇門子，冥然閉清關。"]'),
('3218fe9c-8dc4-460d-9bba-89b3c6a107b7','奉和聖製荅張說扈從南出鼠雀谷之作','王丘','唐','唐诗','tang','','[]','襟帶三秦接，旂常萬乘過。',72,'全唐诗/poet.tang.5000.json','["襟帶三秦接，旂常萬乘過。", "陽原淑氣早，陰谷沍寒多。", "花縟前茅仗，霜嚴後殿戈。", "代雲開晉嶺，江雁入汾河。", "北土分堯俗，南風動舜歌。", "一聞天樂唱，恭逐萬人和。"]'),
('06dc81a5-672a-45e7-a824-bbbcfdfacfd2','奉和聖製送張尚書巡邊','王丘','唐','唐诗','tang','','[]','德業蘊時宗，幽符夢象通。',108,'全唐诗/poet.tang.5000.json','["德業蘊時宗，幽符夢象通。", "台司計祈父，師律總元戎。", "出入敷能政，謀猷體至公。", "贈行光睿什，宴別感宸衷。", "文炳高天曜，恩垂湛露融。", "建牙之塞表，鳴鼓接雲中。", "策密鬼神祕，威成劍騎雄。", "朔門正炎月，兵氣已秋風。", "肅殺從此始，方知胡運窮。"]'),
('86096050-5a25-46a4-8412-ce6fdde8995f','過賈六','蘇晉','唐','唐诗','tang','','[]','主人病且閑，客來情彌適。',48,'全唐诗/poet.tang.5000.json','["主人病且閑，客來情彌適。", "一酌復一笑，不知日將夕。", "昨來屬歡游，於今盡成昔。", "努力持所趣，空名定何益。"]'),
('000ede98-9759-43b7-adb0-4471d95e6bac','奉和聖製送張說巡邊','蘇晉','唐','唐诗','tang','','[]','方漢比周年，興王合在宣。',120,'全唐诗/poet.tang.5000.json','["方漢比周年，興王合在宣。", "亟聞降虜拜，復覩出師篇。", "祈父萬邦式，英猷三略傳。", "算車申夏政，茇舍啓戎田。", "嚴問盟胡苑，軍容濟洛川。", "皇情悵關斾，詔餞列郊筵。", "路接禁園草，池分御井蓮。", "離聲軫去角，居念斷歸蟬。", "三捷豈云爾，七擒良信然。", "具僚誠寄望，奏凱秋風前。"]'),
('97839a51-808c-4d21-a951-c8eb863457d4','奉和聖製送張說巡邊','崔禹錫','唐','唐诗','tang','','[]','供帳何煌煌，公其撫朔方。',120,'全唐诗/poet.tang.5000.json','["供帳何煌煌，公其撫朔方。", "羣僚咸餞酌，明主降離章。", "關塞重門下，郊岐禁苑傍。", "練兵宜雨洗，臥鼓候風涼。", "炎景寧云憚，神謀肅所將。", "旌搖天月迥，騎入塞雲長。", "赫赫皇威振，油油聖澤滂。", "非惟按車甲，兼以正封疆。", "叱詫陰山道，澄清翰海陽。", "虜垣行決勝，台座佇爲光。"]'),
('aa5e6f28-7fd0-41cb-8eb1-5b07a33c2556','恩敕尚書省僚宴昆明池應制','張嘉貞','唐','唐诗','tang','','[]','靈沼初開漢，神池舊浴堯。',72,'全唐诗/poet.tang.5000.json','["靈沼初開漢，神池舊浴堯。", "昔人徒習武，明代此聞韶。", "地脈山川勝，天恩雨露饒。", "時光牽利舸，春淑覆柔條。", "芳醞酲千日，華牋落九霄。", "幸承歡賚重，不覺醉歸遙。"]'),
('485cc25b-4678-498b-b388-08d60e9c535b','奉和早登太行山中言志應制','張嘉貞','唐','唐诗','tang','','[]','明發扈山巔，飛龍高在天。',96,'全唐诗/poet.tang.5000.json','["明發扈山巔，飛龍高在天。", "山南平對鞏，山北遠通燕。", "瞻彼岡巒峻，憑茲士馬妍。", "九圻行若砥，萬谷輾如川。", "羅網開三面，閭閻問百年。", "澤將春雪比，文共曉星連。", "徯后逢今聖，登台謝曩賢。", "唯餘事君節，不讓古人先。"]'),
('8cc7ee29-39ed-4e57-bd60-d4910a93be0e','奉和聖製送張說巡邊','張嘉貞','唐','唐诗','tang','','[]','天錫我宗盟，元戎付夏卿。',120,'全唐诗/poet.tang.5000.json','["天錫我宗盟，元戎付夏卿。", "多才兼將相，必勇獨橫行。", "經緯稱人傑，文章作代英。", "山川看是陣，草木想爲兵。", "不待河冰合，猶防塞月明。", "有謀當繫醜，無戰且綏氓。", "閫外傳三略，雲中冀一平。", "感恩同義激，悵別屢魂驚。", "直視前旌掣，遙聞後騎鳴。", "還期方定日，復此出郊迎。"]'),
('5505a7aa-ed04-4a77-840b-c8966d315802','句','張嘉貞','唐','唐诗','tang','','[]','河魚未上凍，江蟄已聞雷。',12,'全唐诗/poet.tang.5000.json','["河魚未上凍，江蟄已聞雷。"]'),
('502f3a7b-a236-49e1-adab-ecb2994c9772','奉和聖製送張說巡邊','盧從愿','唐','唐诗','tang','','[]','上將發文昌，中軍靜朔方。',120,'全唐诗/poet.tang.5000.json','["上將發文昌，中軍靜朔方。", "占星引旌節，擇日拜壇場。", "禮樂臨軒送，威聲出塞揚。", "安邊俟帷幄，制勝在巖廊。", "作鼓將軍氣，投醪壯士觴。", "戒途遵六月，離贈動三光。", "槐路清梅暑，蘅臯起麥涼。", "時文仰雄伯，耀武震遐荒。", "衽席知無戰，兵戈示不忘。", "佇聞歌杕杜，凱入繫名王。"]'),
('f7022466-a984-4926-a64b-be9acb8d8b16','祭汾陰樂章','盧從愿','唐','唐诗','tang','','[]','坤元載物，陽樂發生。',40,'全唐诗/poet.tang.5000.json','["坤元載物，陽樂發生。", "播植資始，品彙咸亨。", "列俎棊布，方壇砥平。", "神歆禋祀，后德惟明。"]'),
('d7e52b7f-b4c8-4c4d-abf9-4ce444fe421d','長門怨','袁暉','唐','唐诗','tang','','[]','早知君愛歇，本自無縈妒。',48,'全唐诗/poet.tang.5000.json','["早知君愛歇，本自無縈妒。", "誰使恩情深，今來反相誤。", "愁眠羅帳曉，泣坐金閨暮。", "獨有夢中魂，猶言意如故。"]'),
('af25d93d-733d-42f0-894b-9b917792da5d','銅雀妓','袁暉','唐','唐诗','tang','','[]','君愛本相饒，從來似舞腰。',48,'全唐诗/poet.tang.5000.json','["君愛本相饒，從來似舞腰。", "那堪攀玉座，腸斷望陵朝。", "怨著情無主，哀凝曲不調。", "況臨松日暮，悲吹坐蕭蕭。"]'),
('bea50743-fb46-4fc0-94c0-0e8fc05f5294','正月閨情','袁暉','唐','唐诗','tang','','[]','正月金閨裏，微風繡戶間。',48,'全唐诗/poet.tang.5000.json','["正月金閨裏，微風繡戶間。", "曉魂憐別夢，春思逼啼顏。", "遶砌梅堪折，當軒樹未攀。", "歲華庭北上，何日度陽關。"]'),
('4649aec3-077d-499c-bdcf-19ffeb68887d','二月閨情','袁暉','唐','唐诗','tang','','[]','二月韶光好，春風香氣多。',48,'全唐诗/poet.tang.5000.json','["二月韶光好，春風香氣多。", "園中花巧笑，林裏鳥能歌。", "有恨離琴瑟，無情著綺羅。", "更聽春燕語，妾亦不如他。"]'),
('79cc2e51-0605-4acd-bcbd-989f29961253','三月閨情','袁暉','唐','唐诗','tang','','[]','三月春將盡，空房妾獨居。',48,'全唐诗/poet.tang.5000.json','["三月春將盡，空房妾獨居。", "蛾眉愁自結，鬢髪沒情梳。", "□□□□□，□□□□□。", "□□□□□，□□□□□。"]'),
('9f08eb28-640f-4fd7-87f3-bfa5d6c426b3','七月閨情','袁暉','唐','唐诗','tang','','[]','七月坐涼宵，金波滿麗譙。',48,'全唐诗/poet.tang.5000.json','["七月坐涼宵，金波滿麗譙。", "容華芳意改，枕席怨情饒。", "錦字沾愁淚，羅裙緩細腰。", "不如銀漢女，歲歲鵲成橋。"]'),
('29b67fd8-ac8b-4e91-909e-b92ef44c66d1','奉和聖製荅張說扈從南出雀鼠谷之作','袁暉','唐','唐诗','tang','','[]','魏國山河險，周王警蹕迴。',72,'全唐诗/poet.tang.5000.json','["魏國山河險，周王警蹕迴。", "九旗雲際出，萬騎谷中來。", "石路行將盡，煙郊望忽開。", "賞矜垂柳報，春畏落花催。", "興逸橫汾什，恩褒作頌才。", "小臣瞻日月，延首詠康哉。"]'),
('6100a4a9-5b27-4888-a917-ae59cb31c027','奉和聖製送張尚書巡邊','袁暉','唐','唐诗','tang','','[]','出師宣九命，分閫用三台。',120,'全唐诗/poet.tang.5000.json','["出師宣九命，分閫用三台。", "始應幕中畫，言從天上來。", "丹青不獨任，韜略遂雙該。", "坐見威稜洽，彌彰事業恢。", "旌旗曉雲送，鞞鼓朔風催。", "虜氣消殘月，邊聲韻落梅。", "羽書雄北地，龍漠寢南垓。", "寵戰黃金盡，輸誠白日迴。", "離章宸翰發，祖讌國門開。", "欲識恩華盛，平生文武材。"]'),
('c08da636-312a-412a-a664-5f36076e2030','奉和聖製荅張說扈從南出雀鼠谷','王光庭','唐','唐诗','tang','','[]','省俗恩將遍，巡方路稍迴。',72,'全唐诗/poet.tang.5000.json','["省俗恩將遍，巡方路稍迴。", "寒隨汾谷盡，春逐晉郊來。", "雲騎傳行漏，煙旄引從臺。", "惠風初應律，和氣正調梅。", "雅頌通宸詠，天文接曙台。", "灞陵桃李色，應待日華開。"]'),
('e1b1a72d-b466-4bf3-bb80-8f3c6de9cc49','奉和聖製送張說巡邊','王光庭','唐','唐诗','tang','','[]','賢相德符充，朝推文武雄。',120,'全唐诗/poet.tang.5000.json','["賢相德符充，朝推文武雄。", "海波先若鏡，關草豫從風。", "鉞助將軍勇，威成天子功。", "瓊章九霄發，錫宴五衢通。", "玉輾龍盤帶，金裝鳳勒驄。", "虎貔紛儗儗，河洛振熊熊。", "戈劍千霜白，旌旗萬火紅。", "示刑夷夏變，流惠鬼方同。", "寇息軍容偃，塵銷朔野空。", "用師敷禮樂，非是爲獯戎。"]'),
('868fbddc-f0b1-4cd9-b915-017aab829bd6','奉和聖製送張說巡邊','徐知仁','唐','唐诗','tang','','[]','聖德膺三統，皇恩被八埏。',120,'全唐诗/poet.tang.5000.json','["聖德膺三統，皇恩被八埏。", "大明均照物，小醜未寧邊。", "國相台衡重，元戎廟略宣。", "紫泥方受命，黃石乃推賢。", "問辠陰山下，安人屬國前。", "度關行照月，乘障坐消煙。", "北闕紆宸藻，南橋列祖筵。", "耀威當夏日，殺氣指秋天。", "鞞鼓黿鼉振，旌旗鳥獸懸。", "由來詞翰手，今見勒燕然。"]'),
('5bb20764-fe77-441e-babf-dfd3e73503a4','奉和勅賜公主鏡','席豫','唐','唐诗','tang','','[]','令節頒龍鏡，仙輝下鳳臺。',48,'全唐诗/poet.tang.5000.json','["令節頒龍鏡，仙輝下鳳臺。", "含靈萬象入，寫照百花開。", "色與皇明散，光隨聖澤來。", "妍媸冰鑑裏，從此愧非才。"]'),
('b09794a8-da3c-473b-939c-a9c8687def73','江行紀事二首 一','席豫','唐','唐诗','tang','','[]','飄颻任舟楫，迴合傍江津。',48,'全唐诗/poet.tang.5000.json','["飄颻任舟楫，迴合傍江津。", "後浦情猶在，前山賞更新。", "樹深煙冪冪，灘淺石磷磷。", "川路南行遠，淹留惜此辰。"]'),
('152f099c-7665-4218-a5d4-cadd9a51a327','江行紀事二首 二','席豫','唐','唐诗','tang','','[]','江汛春風勢，山樓曙月輝。',48,'全唐诗/poet.tang.5000.json','["江汛春風勢，山樓曙月輝。", "猿攀紫巖飲，鳥拂清潭飛。", "古樹崩沙岸，新苔覆石磯。", "津途賞無限，征客蹔忘歸。"]'),
('5ded4090-008e-41f9-9279-ad581a1da886','奉和聖製答張說南出雀鼠谷','席豫','唐','唐诗','tang','','[]','鳴鑾初幸代，旋蓋欲橫汾。',72,'全唐诗/poet.tang.5000.json','["鳴鑾初幸代，旋蓋欲橫汾。", "山盡千旗出，郊平五校分。", "前林已暄景，後壑尚寒氛。", "風送簫韶曲，花鋪黼黻文。", "鹽梅推上宰，禮樂統中軍。", "獻賦紆天札，飄颻飛白雲。"]'),
('ae1df7b5-c6fa-4a73-9179-28eb08e87c7e','奉和聖製送張說巡邊','席豫','唐','唐诗','tang','','[]','聖主重兵權，分符屬大賢。',120,'全唐诗/poet.tang.5000.json','["聖主重兵權，分符屬大賢。", "中軍仍執政，丞相復巡邊。", "翕習戎裝動，張皇廟略宣。", "朝榮承睿札，野餞轉行旃。", "亭障東緣海，沙場北際天。", "春冬見巖雪，朝夕候烽煙。", "已勒封山記，猶聞遣戍篇。", "五營將月合，八陣與雲連。", "經略圖方遠，懷柔道更全。", "歸來畫麟閣，藹藹武功傳。"]'),
('ab10b8da-25cd-4c86-bc72-39ea5106adaf','祭汾陰樂章','韓思復','唐','唐诗','tang','','[]','大樂和暢，殷薦明神。',40,'全唐诗/poet.tang.5000.json','["大樂和暢，殷薦明神。", "一降通感，八變必臻。", "有求斯應，無德不親。", "降靈醉止，休徵萬人。"]'),
('7fe5d450-c2c0-4e86-b05c-22ff6fa7b92e','祭汾陰樂章','劉晃','唐','唐诗','tang','','[]','大君出震，有事郊禋。',40,'全唐诗/poet.tang.5000.json','["大君出震，有事郊禋。", "齋戒既肅，馨香畢陳。", "樂和禮備，候暖風春。", "恭惟降福，實賴明神。"]'),
('e3a1df4d-dd21-4e1a-967e-17d85ef7aa17','唐禪社首樂章 順和','賀知章','唐','唐诗','tang','','["\u6292\u60c5", "\u53d9\u4e8b", "\u5199\u666f"]','至哉含柔德，萬物資以生。',48,'全唐诗/poet.tang.5000.json','["至哉含柔德，萬物資以生。", "常順稱厚載，流謙通變盈。", "聖心事能察，增廣陳厥誠。", "黃祇僾如在，泰折俟咸亨。"]'),
('6f0ac62c-0b54-4b6d-a9f8-ce5534d52264','太和','賀知章','唐','唐诗','tang','','[]','肅我成命，於昭黃衹。',40,'全唐诗/poet.tang.5000.json','["肅我成命，於昭黃衹。", "裘冕而祀，陟降在斯。", "五音克備，八變聿施。", "緝熙肆靖，厥心匪離。"]'),
('8b3e7335-b163-4dae-b4cb-bd3d9ab6c7c7','太和 肅和','賀知章','唐','唐诗','tang','','[]','黃祇是祗，我其夙夜。',40,'全唐诗/poet.tang.5000.json','["黃祇是祗，我其夙夜。", "夤畏誠絜，匪遑寧舍。", "禮以琮玉，薦厥茅藉。", "念茲降康，胡寧克暇。"]'),
('97fa6464-7f5f-4ffc-ab32-0d72e4171029','太和 雍和','賀知章','唐','唐诗','tang','','[]','夙夜宥密，不敢寧宴。',40,'全唐诗/poet.tang.5000.json','["夙夜宥密，不敢寧宴。", "五齊既陳，八音在縣。", "粢盛以絜，房俎斯薦。", "惟德惟馨，尚茲克徧。"]'),
('cc92ee7f-f8d6-47bb-9efe-f2402a4aa123','太和 壽和','賀知章','唐','唐诗','tang','','[]','惟以明發，有懷載殷。',40,'全唐诗/poet.tang.5000.json','["惟以明發，有懷載殷。", "樂盈而反，禮順其禋。", "立清以獻，薦欲是親。", "於穆不已，裒對斯臻。"]'),
('9413d4ed-a104-4098-95bd-ca20ce911d85','太和 福和','賀知章','唐','唐诗','tang','','["\u6cf0\u5c71"]','穆穆天子，告成岱宗。',40,'全唐诗/poet.tang.5000.json','["穆穆天子，告成岱宗。", "大裘如濡，執珽有顒。", "樂以平志，禮以和容。", "上帝臨我，云胡肅邕。"]'),
('eda5a0a2-a343-4b90-82cb-fbc5425e622c','太和 太和','賀知章','唐','唐诗','tang','','[]','昭昭有唐，天俾萬國。',40,'全唐诗/poet.tang.5000.json','["昭昭有唐，天俾萬國。", "列祖應命，四宗順則。", "申錫無疆，宗我同德。", "曾孫繼緒，享神配極。"]'),
('8d177157-4a06-44d4-9a20-6c30f98e89c1','太和 晚發','賀知章','唐','唐诗','tang','','[]','江臯聞曙鐘，輕栧理還舼。',48,'全唐诗/poet.tang.5000.json','["江臯聞曙鐘，輕栧理還舼。", "海潮夜約約，川露晨溶溶。", "始見沙上鳥，猶埋雲外峰。", "故鄉杳無際，明發懷朋從。"]'),
('36cd0a6f-d2b1-4ee0-b9cb-d04f080b1441','奉和御製春臺望','賀知章','唐','唐诗','tang','','[]','青陽布王道，玄覽陶真性。',204,'全唐诗/poet.tang.5000.json','["青陽布王道，玄覽陶真性。", "欣若天下春，高逾域中聖。", "神臯類觀賞，帝里如懸鏡。", "繚繞八川浮，岧嶢雙闕映。", "曉色徧昭陽，晴雲卷建章。", "華滋的皪丹青樹，顥氣氤氳金玉堂。", "尚有靈蛇下鄜畤，還徵瑞寶入陳倉。", "自昔秦奢漢窮武，後庭萬餘宮百數。", "旗回五丈殿千門，連綿南隥出西垣。", "廣畫螓蛾誇窈窕，羅生玳瑁象崑崙。", "廼睠天晴興隱恤，古來土木良非一。", "荆臨章觀趙叢臺，何如堯階將禹室。", "層欄䆗窱下龍輿，清管逶迤半綺疏。", "一聽南風引鸞舞，長謠北極仰鶉居。"]'),
('05c8a0ab-59be-412f-9ed4-d2bd5915de73','望人家桃李花','賀知章','唐','唐诗','tang','','[]','山源夜雨度仙家，朝發東園桃李花。',160,'全唐诗/poet.tang.5000.json','["山源夜雨度仙家，朝發東園桃李花。", "桃花紅兮李花白，照灼城隅復南陌。", "南陌青樓十二重，春風桃李爲誰容。", "棄置千金輕不顧，踟躕五馬謝相逢。", "徒言南國容華晚，遂歎西家飄落遠。", "的皪長奉明光殿，氛氳半入披香苑。", "苑中珍木元自奇，黃金作葉白銀枝。", "千年萬歲不凋落，還將桃李更相宜。", "桃李從來露井傍，成蹊結影矜豔陽。", "莫道春花不可樹，會持仙實薦君王。"]'),
('1e7232a3-99e2-4b6d-89e8-73c221072a79','送人之軍','賀知章','唐','唐诗','tang','','[]','常經絕脉塞，復見斷腸流。',48,'全唐诗/poet.tang.5000.json','["常經絕脉塞，復見斷腸流。", "送子成今別，令人起昔愁。", "隴雲晴半雨，邊草夏先秋。", "萬里長城寄，無貽漢國憂。"]'),
('b7801dee-a508-4774-8d0e-51e3e5469fc8','奉和聖製送張說上集賢學士賜宴賦得謨字','賀知章','唐','唐诗','tang','','[]','西學垂玄覽，東堂發聖謨。',72,'全唐诗/poet.tang.5000.json','["西學垂玄覽，東堂發聖謨。", "天光燭武殿，時宰集鴻都。", "枯朽霑皇澤，翾飛舞帝梧。", "跡同遊汗漫，榮是出泥塗。", "三歎承湯鼎，千歡接舜壺。", "微軀不可荅，空欲詠依蒲。"]'),
('cfc44e7f-df97-4b76-b5f3-8bf9bd6fc657','奉和聖製送張說巡邊','賀知章','唐','唐诗','tang','','[]','荒憬盡懷忠，梯航已自通。',120,'全唐诗/poet.tang.5000.json','["荒憬盡懷忠，梯航已自通。", "九攻雖不戰，五月尚持戎。", "遣戍徵周牒，恢邊重漢功。", "選車命元宰，授律取文雄。", "胄出天弧上，謀成帝幄中。", "詔旂分夏物，專土錫唐弓。", "帳宿伊川右，鉦傳晉苑東。", "饔人藉蕡實，樂正理絲桐。", "岐陌涵餘雨，離川照晚虹。", "恭聞詠方叔，千載舞皇風。"]'),
('e7185b87-f7c2-483a-8d88-dec61a065199','題袁氏別業','賀知章','唐','唐诗','tang','','[]','主人不相識，偶坐爲林泉。',24,'全唐诗/poet.tang.5000.json','["主人不相識，偶坐爲林泉。", "莫謾愁沽酒，囊中自有錢。"]'),
('bf4ce5bb-7a29-4b33-b8c6-55a020394ab8','詠柳','賀知章','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u548f\u7269", "\u5199\u98ce", "\u67f3\u6811", "\u690d\u7269"]','碧玉妝成一樹高，萬條垂下綠絲縧。',32,'全唐诗/poet.tang.5000.json','["碧玉妝成一樹高，萬條垂下綠絲縧。", "不知細葉誰裁出，二月春風似剪刀。"]'),
('eea19f7a-04c7-417d-bec7-9a93dd55e845','采蓮曲','賀知章','唐','唐诗','tang','','[]','稽山罷霧鬱嵯峨，鏡水無風也自波。',32,'全唐诗/poet.tang.5000.json','["稽山罷霧鬱嵯峨，鏡水無風也自波。", "莫言春度芳菲盡，別有中流采芰荷。"]'),
('599b8a93-47ab-4426-94c0-ca16eea0ca37','回鄉偶書二首 一','賀知章','唐','唐诗','tang','','[]','少小離家老大回，鄉音難改鬢毛衰。',32,'全唐诗/poet.tang.5000.json','["少小離家老大回，鄉音難改鬢毛衰。", "兒童相見不相識，笑問客從何處來。"]'),
('3cee858c-b57c-4262-94fd-6737dd8e9996','回鄉偶書二首 二','賀知章','唐','唐诗','tang','','[]','離別家鄉歲月多，近來人事半銷磨。',32,'全唐诗/poet.tang.5000.json','["離別家鄉歲月多，近來人事半銷磨。", "唯有門前鏡湖水，春風不改舊時波。"]'),
('0b7ac645-06f5-47f1-a8d7-1107dc7ce594','答朝士','賀知章','唐','唐诗','tang','','[]','鈒鏤銀盤盛蛤蜊，鏡湖蓴菜亂如絲。',32,'全唐诗/poet.tang.5000.json','["鈒鏤銀盤盛蛤蜊，鏡湖蓴菜亂如絲。", "鄉曲近來隹此味，遮渠不道是吳兒。"]'),
('828a80d9-71f3-48a0-995b-0fa749c6bcb5','句','賀知章','唐','唐诗','tang','','[]','落花真好些，一醉一回顛。',12,'全唐诗/poet.tang.5000.json','["落花真好些，一醉一回顛。"]'),
('cf510a24-e1e4-49c3-b828-9be2ce8931c9','敬酬張九齡當塗界留贈之作','裴耀卿','唐','唐诗','tang','','[]','茂先寔王佐，仲舉信時英。',108,'全唐诗/poet.tang.5000.json','["茂先寔王佐，仲舉信時英。", "氣覩衝天發，人將下榻迎。", "珪符肅有命，江國遠徂征。", "九派期方越，千鈞或所輕。", "高帆出風迥，孤嶼入雲平。", "遄邁嗟于役，離憂空自情。", "餙簪陪早歲，接壤廁專城。", "曠別心彌軫，宏規義轉傾。", "徒然恨飢渴，況乃諷瑤瓊。"]'),
('e1d8badb-0d37-4681-937e-c76190fbecbb','酬張九齡使風見示','裴耀卿','唐','唐诗','tang','','[]','茲地五湖隣，艱哉萬里人。',48,'全唐诗/poet.tang.5000.json','["茲地五湖隣，艱哉萬里人。", "驚飆翻是託，危浪亦相因。", "宣室才華子，金閨諷議臣。", "承明有三人，去去速歸輪。"]'),
('f05aac0b-94cd-4b6a-ae77-bc159c653125','贈張丞相','宋鼎','唐','唐诗','tang','','[]','漢上登飛幰，荆南歷舊居。',72,'全唐诗/poet.tang.5000.json','["漢上登飛幰，荆南歷舊居。", "已嘗臨砌橘，更覩躍池魚。", "盛德繼微渺，深衷能卷舒。", "義申蓬閣際，情切廟堂初。", "郡挹文章美，人懷燮理餘。", "皇恩儻照亮，豈厭承明廬。"]'),
('cbbe3dfd-98f0-403f-b4b4-1fd4b5d5f951','酬故人還山','宋鼎','唐','唐诗','tang','','[]','舉櫂乘春水，歸山撫歲華。',72,'全唐诗/poet.tang.5000.json','["舉櫂乘春水，歸山撫歲華。", "碧潭宵見月，紅樹晚開花。", "肅穆輕風度，依微隱徑斜。", "危亭暗松石，幽澗落雲霞。", "思鳥吟高樹，游魚戲淺沙。", "安知餘興盡，相望紫煙賒。"]'),
('668736cb-2e47-45b1-b6d9-e943c41e1f7f','和張荆州九齡晨出郡舍林下','崔頌','唐','唐诗','tang','','[]','優閑表政清，林薄賞秋成。',48,'全唐诗/poet.tang.5000.json','["優閑表政清，林薄賞秋成。", "江上懸曉月，往來虧復盈。", "天雲抗真意，郡閣晦高名。", "坐嘯應無欲，寧辜濟物情。"]'),
('1f5beb19-67e2-4773-b8f8-5effef828301','奉酬張洪州九齡江上見贈','孫翃','唐','唐诗','tang','','[]','受命讞封疆，逢君牧豫章。',48,'全唐诗/poet.tang.5000.json','["受命讞封疆，逢君牧豫章。", "於焉審虞芮，復爾共舟航。", "悵別秋陰盡，懷歸客思長。", "江臯枉離贈，持此慰他鄉。"]'),
('12f78bb0-5e00-475f-82d8-06be38002050','古意贈孫翃','徐仁友','唐','唐诗','tang','','[]','南望緱氏嶺，山居共澗陰。',48,'全唐诗/poet.tang.5000.json','["南望緱氏嶺，山居共澗陰。", "東西十數里，緬邈方寸心。", "雲日落廣廈，鶯花對孤琴。", "琴中多苦調，悽切誰復尋。"]'),
('a96b44c1-6739-43b1-972b-23ffe9cb582d','奉和姚令公駕幸溫湯喜雪應制','蘇綰','唐','唐诗','tang','','[]','漢主新豐邑，周王尚父師。',48,'全唐诗/poet.tang.5000.json','["漢主新豐邑，周王尚父師。", "雲符沛童唱，雪應海神期。", "林變驚春早，山明訝夕遲。", "況逢溫液霈，恩重御裘詩。"]'),
('76b2b7f8-8748-4cdb-99db-2385a0e93721','詠月','康庭芝','唐','唐诗','tang','','[]','天使下西樓，光含萬里秋。',48,'全唐诗/poet.tang.5000.json','["天使下西樓，光含萬里秋。", "臺前疑挂鏡，簾外似懸鉤。", "張尹將眉學，班姬取扇儔。", "佳期應借問，爲報在刀頭。"]'),
('ee0836be-5444-4e92-bdcd-012b9e633cea','山行見孤松成詠','張宣明','唐','唐诗','tang','','[]','孤松鬱山椒，肅爽凌清霄。',60,'全唐诗/poet.tang.5000.json','["孤松鬱山椒，肅爽凌清霄。", "既挺千丈幹，亦生百尺條。", "青青恆一色，落落非一朝。", "大廈今已構，惜哉無人招。", "寒霜十二月，枝葉獨不凋。"]'),
('caf76db9-d31b-429e-b8f4-4364e68e8014','使至三姓咽麵','張宣明','唐','唐诗','tang','','[]','昔聞班家子，筆硯忽然投。',84,'全唐诗/poet.tang.5000.json','["昔聞班家子，筆硯忽然投。", "一朝撫長劒，萬里入荒陬。", "豈不服艱險，只思清國讐。", "山川去何歲，霜露幾逢秋。", "玉塞已遐廓，鐵關方阻修。", "東都日窅窅，西海此悠悠。", "卒使功名建，長封萬里侯。"]'),
('69cbee7e-a72f-40d5-b1d8-45c6a2de2b87','新都南亭別郭大元振','盧崇道','唐','唐诗','tang','','[]','竹徑女蘿蹊，蓮洲文石隄。',72,'全唐诗/poet.tang.5000.json','["竹徑女蘿蹊，蓮洲文石隄。", "靜深人俗斷，尋翫往還迷。", "碧潭秀初月，素林驚夕棲。", "褰幌納鳥侶，罷琴聽猨啼。", "佳辰改宿昔，勝寄在暌攜。", "長懷賞心愛，如玉復如珪。"]'),
('64e5a06a-f81d-49c7-9a5d-b6c4fdbbcd91','登翅頭山題儼公石壁','包融','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','晨登翅頭山，山曛黃霧起。',120,'全唐诗/poet.tang.5000.json','["晨登翅頭山，山曛黃霧起。", "却瞻迷向背，直下失城市。", "暾日銜東郊，朝光生邑里。", "掃除諸煙氛，照出衆樓雉。", "青爲洞庭山，白是太湖水。", "蒼茫遠郊樹，倏忽不相似。", "萬象以區別，森然共盈几。", "坐令開心胸，漸覺落塵滓。", "北巖千餘仞，結廬誰家子。", "願陪中峯遊，朝暮白雲裏。"]'),
('fb1e768a-e763-4ebc-99bb-55846f117ad3','阮公嘯臺','包融','唐','唐诗','tang','','[]','荒臺森荆杞，蒙籠無上路。',72,'全唐诗/poet.tang.5000.json','["荒臺森荆杞，蒙籠無上路。", "傳是古人跡，阮公長嘯處。", "至今清風來，時時動林樹。", "逝者共已遠，升攀想遺趣。", "靜然荒榛門，久之若有悟。", "靈光未歇滅，千載知仰慕。"]'),
('47e1bba9-990a-4008-a8b1-aa2bcd8a2778','酬忠公林亭','包融','唐','唐诗','tang','','[]','江外有真隱，寂居歲已侵。',120,'全唐诗/poet.tang.5000.json','["江外有真隱，寂居歲已侵。", "結廬近西術，種樹久成陰。", "人迹乍及戶，車聲遙隔林。", "自言解塵事，咫尺能輜塵。", "爲道豈廬霍，會靜由吾心。", "方秋院木落，仰望日蕭森。", "持我興來趣，采菊行相尋。", "塵念到門盡，遠情對君深。", "一談入理窟，再索破幽襟。", "安得山中信，致書移尚禽。"]'),
('eef64c3d-cdab-48ca-a00f-41052c7c3ce2','送國子張主簿','包融','唐','唐诗','tang','','[]','湖岸纜初解，鶯啼別離處。',48,'全唐诗/poet.tang.5000.json','["湖岸纜初解，鶯啼別離處。", "遙見舟中人，時時一迴顧。", "坐悲芳歲晚，花落青軒樹。", "春夢隨我心，悠揚逐君去。"]'),
('e7e28bc0-5783-4899-af12-9baceec134f8','和陳校書省中翫雪','包融','唐','唐诗','tang','','[]','芸閣朝來雪，飄颻正滿空。',48,'全唐诗/poet.tang.5000.json','["芸閣朝來雪，飄颻正滿空。", "褰開明月下，校理落花中。", "色向懷鉛白，光因翰簡融。", "能令草玄者，迴思入流風。"]'),
('bc5fff54-81e0-4a6a-8611-db52356cb40b','和崔會稽詠王兵曹廳前湧泉勢城中字','包融','唐','唐诗','tang','','[]','茂德來徵應，流泉入詠歌。',48,'全唐诗/poet.tang.5000.json','["茂德來徵應，流泉入詠歌。", "含靈符上善，作字表中和。", "有草恆垂露，無風欲偃波。", "爲看人共水，清白定誰多。"]'),
('0eb73c7c-ae62-4e2e-9050-c1b67cd5bcd2','賦得岸花臨水發','包融','唐','唐诗','tang','','[]','笑笑傍溪花，叢叢逐岸斜。',48,'全唐诗/poet.tang.5000.json','["笑笑傍溪花，叢叢逐岸斜。", "朝開川上日，夜發浦中霞。", "照灼如臨鏡，䒠茸勝浣紗。", "春來武陵道，幾樹落仙家。"]'),
('a01291fb-dbf6-478b-a177-2e8bbb9c5584','武陵桃源送人','包融','唐','唐诗','tang','','["\u9001\u522b"]','武陵川徑入幽遐，中有雞犬秦人家。',32,'全唐诗/poet.tang.5000.json','["武陵川徑入幽遐，中有雞犬秦人家。", "先時見者爲誰耶，源水今流桃復花。"]'),
('9c17ce38-a6c8-4d25-8d82-f762b7c6b59d','和薦福寺英公新搆禪堂','丁仙芝','唐','唐诗','tang','','["\u5e90\u5c71"]','上人久棄世，中道自忘筌。',96,'全唐诗/poet.tang.5000.json','["上人久棄世，中道自忘筌。", "寂照出羣有，了心清衆緣。", "所以於此地，築館開青蓮。", "果藥羅砌下，煙虹垂戶前。", "咒中灑甘露，指處流香泉。", "禪遠目無事，體清宵不眠。", "枳聞廬山法，松入漢陽禪。", "一枕西山外，虛舟常浩然。"]'),
('d596b388-593f-43f7-aa91-e09e6fd59413','贈朱中書','丁仙芝','唐','唐诗','tang','','[]','十年種田濱五湖，十年遭澇盡爲蕪。',112,'全唐诗/poet.tang.5000.json','["十年種田濱五湖，十年遭澇盡爲蕪。", "頻年井稅常不足，今年緡錢誰爲輸。", "東鄰轉穀五之利，西鄰販繒日已貴。", "而我守道不遷業，誰能肯敢效此事。", "紫微侍郎白虎殿，出入通籍迴天眷。", "晨趨綵筆柏梁篇，晝出雕盤大官膳。", "會應憐爾居素約，可即長年守貧賤。"]'),
('cfb0ae5e-0ca1-48af-ac89-4ada2cc1f1f3','戲贈姚侍御','丁仙芝','唐','唐诗','tang','','[]','繁霜曉幕鳴柏烏，待子獸炭然金爐。',56,'全唐诗/poet.tang.5000.json','["繁霜曉幕鳴柏烏，待子獸炭然金爐。", "重門啟鎖紫髯胡，新披驄馬隴西駒。", "頭戴獬豸急晨趨，明光殿前見天子，今日應彈佞倖夫。"]'),
('f6b5b537-3c6d-4c76-bb3d-c1f765308578','餘杭醉歌贈吳山人','丁仙芝','唐','唐诗','tang','','[]','曉幕紅襟燕，春城白項烏。',88,'全唐诗/poet.tang.5000.json','["曉幕紅襟燕，春城白項烏。", "只來梁上語，不向府中趨。", "城頭坎坎鼓聲曙，滿庭新種櫻桃樹。", "桃花昨夜撩亂開，當軒發色映樓臺。", "十千兌得餘杭酒，二月春城長命杯。", "酒後留君待明月，還將明月送君回。"]'),
('4145adde-b933-4175-8a83-b567f42e55cd','京中守歲','丁仙芝','唐','唐诗','tang','','[]','守歲多然燭，通宵莫掩扉。',48,'全唐诗/poet.tang.5000.json','["守歲多然燭，通宵莫掩扉。", "客愁當暗滿，春色向明歸。", "玉斗巡初匝，銀河落漸微。", "開正獻歲酒，千里間庭闈。"]'),
('e5b38f6a-08a9-4942-ae35-5dd9f94304bf','渡揚子江','丁仙芝','唐','唐诗','tang','','[]','桂檝中流望，空波兩畔明。',48,'全唐诗/poet.tang.5000.json','["桂檝中流望，空波兩畔明。", "林開揚子驛，山出潤州城。", "海盡邊陰靜，江寒朔吹生。", "更聞風葉下，淅瀝度秋聲。"]'),
('1ab5083b-3274-40a4-8c4c-1c5815f99470','長寧公主舊山池','丁仙芝','唐','唐诗','tang','','[]','平陽舊池館，寂寞使人愁。',48,'全唐诗/poet.tang.5000.json','["平陽舊池館，寂寞使人愁。", "座卷流黃簟，簾垂白玉鉤。", "庭閑花自落，門閉水空流。", "追想吹簫處，應隨仙鶴遊。"]'),
('f5ee9ca8-b098-4217-9b6b-6d39355e2aba','剡谿館聞笛','丁仙芝','唐','唐诗','tang','','[]','夜久聞羗笛，寥寥虛客堂。',48,'全唐诗/poet.tang.5000.json','["夜久聞羗笛，寥寥虛客堂。", "山空響不散，谿靜曲宜長。", "草木生邊氣，城池泛夕涼。", "虛然異風出，髣髴宿平陽。"]'),
('a04e286d-365c-465f-be1e-6bd6497c38f9','越裳貢白雉','丁仙芝','唐','唐诗','tang','','[]','聖哲承休運，伊夔列上台。',72,'全唐诗/poet.tang.5000.json','["聖哲承休運，伊夔列上台。", "覃恩丹徼遠，入貢素翬來。", "北闕欣初見，南枝顧未迴。", "歛容殘雪淨，矯翼片雲開。", "馴擾將無懼，翻飛幸不猜。", "甘從上林裏，飲啄自徘徊。"]'),
('177a290b-ab04-46ac-a70e-6e8c3e1563d9','江南曲五首 一','丁仙芝','唐','唐诗','tang','','[]','長干斜路北，近浦是兒家。',24,'全唐诗/poet.tang.5000.json','["長干斜路北，近浦是兒家。", "有意來相訪，明朝出浣紗。"]'),
('749747c0-70c3-4cdf-b69f-c04b0f9a3c1a','江南曲五首 二','丁仙芝','唐','唐诗','tang','','[]','發向橫塘口，船開值急流。',24,'全唐诗/poet.tang.5000.json','["發向橫塘口，船開值急流。", "知郎舊時意，且請攏船頭。"]'),
('7af78fae-7826-4eeb-af76-0c6a4a3e9b8f','江南曲五首 三','丁仙芝','唐','唐诗','tang','','[]','昨暝逗南陵，風聲波浪阻。',24,'全唐诗/poet.tang.5000.json','["昨暝逗南陵，風聲波浪阻。", "入浦不逢人，歸家誰信汝。"]'),
('0db62e12-9ab8-44ca-beee-630539346037','江南曲五首 四','丁仙芝','唐','唐诗','tang','','[]','未曉已成妝，乘潮去茫茫。',24,'全唐诗/poet.tang.5000.json','["未曉已成妝，乘潮去茫茫。", "因從京口渡，使報邵陵王。"]'),
('6a3f1a5a-ec6d-4d68-bc7c-1076f0e0b6c2','江南曲五首 五','丁仙芝','唐','唐诗','tang','','[]','始下芙蓉樓，言發瑯琊岸。',24,'全唐诗/poet.tang.5000.json','["始下芙蓉樓，言發瑯琊岸。", "急爲打船開，惡許傍人見。"]'),
('00c502e9-0d35-412a-87cd-9569751b56c6','句','丁仙芝','唐','唐诗','tang','','[]','窮花常閉戶，秋城聞搗衣。',24,'全唐诗/poet.tang.5000.json','["窮花常閉戶，秋城聞搗衣。", "樹迴早秋色，川長遲落暉。"]'),
('07e89d25-01be-46f0-a638-cd4456fc6276','石橋琪樹','蔡隱丘','唐','唐诗','tang','','[]','山上天將近，人間路漸遙。',24,'全唐诗/poet.tang.5000.json','["山上天將近，人間路漸遙。", "誰當雲裏見，知欲渡仙橋。"]'),
('cd7d8cf4-1601-4c21-9058-b47c99900863','句','蔡隱丘','唐','唐诗','tang','','[]','整巾千嶂聳，曳履百泉鳴。',12,'全唐诗/poet.tang.5000.json','["整巾千嶂聳，曳履百泉鳴。"]'),
('8ec575c9-fa85-4e55-81ae-b0fd03de06aa','奉和扈從溫泉宮承恩賜浴','蔡希周','唐','唐诗','tang','','[]','天行雲從指驪宮，浴日餘波錫詔同。',64,'全唐诗/poet.tang.5000.json','["天行雲從指驪宮，浴日餘波錫詔同。", "綵殿氤氳擁香溜，紗窗宛轉閉和風。", "來將蘭氣衝皇澤，去引星文捧碧空。", "自憐遇坎便能止，願托仙槎路未通。"]'),
('ba63b5b7-5201-41f8-9d57-e2258a8d3d01','同家兄題渭南王公別業','蔡希寂','唐','唐诗','tang','','[]','好閑知在家，退跡何必深。',120,'全唐诗/poet.tang.5000.json','["好閑知在家，退跡何必深。", "不出人境外，蕭條江海心。", "軒車自來往，空名對清陰。", "川涘將釣玉，鄉亭期散金。", "素暉射流瀨，翠色緜森林。", "曾爲詩書癖，寧惟耕稼任。", "吾兄許微尚，枉道來相尋。", "朝慶老萊服，夕閑安道琴。", "文章遙頌美，寤寐增所欽。", "既鬱蒼生望，明時豈陸沈。"]'),
('a8192f25-446d-4ab4-801f-6a095dd511b9','登福先寺上方然公禪室','蔡希寂','唐','唐诗','tang','','[]','名都標佛剎，梵構臨河干。',108,'全唐诗/poet.tang.5000.json','["名都標佛剎，梵構臨河干。", "舉目上方峻，森森青翠攢。", "步登諸劫盡，忽造浮雲端。", "當暑敞扃闥，却嫌絺綌寒。", "禪房最高頂，靜者殊閑安。", "疎雨向空城，數峯簾外盤。", "午鐘振衣坐，招我同一餐。", "真味雜飴露，衆香唯茝蘭。", "晚來恣偃俛，茶果仍留歡。"]'),
('14f9b10b-83ed-407d-b6ab-90784434eda9','陝中作','蔡希寂','唐','唐诗','tang','','[]','西別秦關近，東行陝服長。',48,'全唐诗/poet.tang.5000.json','["西別秦關近，東行陝服長。", "川原餘讓畔，歌吹憶遺棠。", "河水流城下，山雲起路傍。", "更憐棲泊處，池館繞林篁。"]'),
('5a866c5e-cec4-4ae5-ba65-010f97788cde','洛陽客舍逢祖詠留宴','蔡希寂','唐','唐诗','tang','','[]','緜緜鐘漏洛陽城，客舍貧居絕送迎。',32,'全唐诗/poet.tang.5000.json','["緜緜鐘漏洛陽城，客舍貧居絕送迎。", "逢君貰酒因成醉，醉後焉知世上情。"]'),
('210e4b4a-f6b8-4761-8dba-9e3ff50293d8','贈張敬微','蔡希寂','唐','唐诗','tang','','[]','大河東北望桃林，雜樹冥冥結翠陰。',32,'全唐诗/poet.tang.5000.json','["大河東北望桃林，雜樹冥冥結翠陰。", "不知君作神仙尉，特訝行來雲霧深。"]'),
('08b9dea0-7e08-4ae3-a558-5db3ebaa8d9f','江風行','張潮','唐','唐诗','tang','','[]','壻貧如珠玉，壻富如埃塵。',144,'全唐诗/poet.tang.5000.json','["壻貧如珠玉，壻富如埃塵。", "貧時不忘舊，富日多寵新。", "妾本富家女，與君爲偶匹。", "惠好一何深，中門不曾出。", "妾有繡衣裳，葳蕤金縷光。", "念君貧且賤，易此從遠方。", "遠方三千里，思君心未已。", "日暮情更來，空望去時水。", "孟夏麥始秀，江上多南風。", "商賈歸欲盡，君今尚巴東。", "巴東有巫山，窈窕神女顏。", "常恐遊此方，果然不知還。"]'),
('5fe8fb13-d2f7-4f59-9cc0-d4b52d2c6b8b','襄陽行','張潮','唐','唐诗','tang','','[]','玉盤轉明珠，君心無定準。',166,'全唐诗/poet.tang.5000.json','["玉盤轉明珠，君心無定準。", "昨見襄陽客，剩說襄陽好無盡。", "襄漢水，峴山垂，漢水東流風北吹。", "只言一世長嬌寵，那悟今朝見別離。", "君渡清羗渚，知人獨不語。", "妾見鳥棲林，憶君相思深。", "莫作雲間鴻，離聲顧儔侶。", "尚如匣中劒，分形會同處。", "是君婦，識君情，怨君恨君爲此行。", "下牀一宿不可保，況乃萬里襄陽城。", "襄陽傳近大堤北，君到襄陽莫回惑。", "大堤諸女兒，憐錢不憐德。"]'),
('127c8d97-6aa4-4bfe-bbb8-b73e6c984cee','采蓮詞','張潮','唐','唐诗','tang','','[]','朝出沙頭日正紅，晚來雲起半江中。',32,'全唐诗/poet.tang.5000.json','["朝出沙頭日正紅，晚來雲起半江中。", "賴逢鄰女曾相識，並著蓮舟不畏風。"]'),
('501fed64-f4bf-40aa-8e79-b15610ecaa0a','江南行','張潮','唐','唐诗','tang','','[]','茨菰葉爛別西灣，蓮子花開猶未還。',32,'全唐诗/poet.tang.5000.json','["茨菰葉爛別西灣，蓮子花開猶未還。", "妾夢不離江水上，人傳郎在鳳凰山。"]'),
('1fefba2a-49be-45fc-9575-166b0567930e','長干行','張潮','唐','唐诗','tang','','[]','憶昔深閨裏，煙塵不曾識。',170,'全唐诗/poet.tang.5000.json','["憶昔深閨裏，煙塵不曾識。", "嫁與長干人，沙頭候風色。", "五月南風興，思君下巴陵。", "八月西風起，想君發[揚]子。", "去來悲如何，見少離別多。", "湘潭幾日到，妾夢越風波。", "昨夜狂風度，吹折江頭樹。", "淼淼暗無邊，行人在何處。", "北客真三公，朱衣滿江中。", "薄暮來投宿，數朝不肯東。", "好乘浮雲驄，佳期蘭渚東。", "鴛鴦綠浦上，翡翠錦屏中。", "自憐十五餘，顏色桃花紅。", "那作商人婦，愁水復愁風。"]'),
('bf892243-b038-4aca-a78d-30114fcb1125','句','張潮','唐','唐诗','tang','','[]','寒林苞晚橘，風絮露垂楊。',12,'全唐诗/poet.tang.5000.json','["寒林苞晚橘，風絮露垂楊。"]'),
('92f9905a-855c-40c1-ac2a-854b61b1566d','遊棲霞寺','張翬','唐','唐诗','tang','','[]','躋險入幽林，翠微含竹殿。',48,'全唐诗/poet.tang.5000.json','["躋險入幽林，翠微含竹殿。", "泉聲無休歇，山色時隱見。", "潮來雜風雨，梅落成霜霰。", "一從方外遊，頓覺塵心變。"]'),
('9a7136ae-e46a-48fe-818a-3ccd4538fa2e','絕句','張翬','唐','唐诗','tang','','[]','茫茫煙上水，日暮陰雲飛。',24,'全唐诗/poet.tang.5000.json','["茫茫煙上水，日暮陰雲飛。", "孤坐正愁緒，湖南誰擣衣。"]'),
('9eed79f1-49ed-4848-8df8-7f77613f00b4','潘司馬別業','周瑀','唐','唐诗','tang','','[]','門對青山近，汀牽綠草長。',48,'全唐诗/poet.tang.5000.json','["門對青山近，汀牽綠草長。", "寒深包晚橘，風緊落垂楊。", "湖畔聞漁唱，天邊數鴈行。", "蕭然有高士，清思滿書堂。"]'),
('4880b25c-7b97-489c-adc7-68049ef84083','送潘三入京','周瑀','唐','唐诗','tang','','[]','故人嗟此別，相送出煙坰。',48,'全唐诗/poet.tang.5000.json','["故人嗟此別，相送出煙坰。", "柳色分官路，荷香入水亭。", "離歌未盡曲，酌酒共忘形。", "把手河橋上，孤山日暮青。"]'),
('86c29e00-f2a1-4f6c-a94e-b0e34c2cff6f','臨川山行','周瑀','唐','唐诗','tang','','[]','朝見青山雪，暮見青山雲。',24,'全唐诗/poet.tang.5000.json','["朝見青山雪，暮見青山雲。", "雲山無斷絕，秋思日紛紛。"]'),
('74b8473f-9ca2-436f-a3d7-cd0e4acfa909','清谿館作','談戭','唐','唐诗','tang','','[]','指途清谿裏，左右唯深林。',48,'全唐诗/poet.tang.5000.json','["指途清谿裏，左右唯深林。", "雲蔽望鄉處，雨愁爲客心。", "遇人多物役，聽鳥時幽音。", "何必滄浪水，庶茲浣塵襟。"]'),
('785e8cf2-185e-4843-b539-7bae8c4e64b8','句','談戭','唐','唐诗','tang','','[]','清清江潭樹，日夕增所思。',12,'全唐诗/poet.tang.5000.json','["清清江潭樹，日夕增所思。"]'),
('f67279c0-fbec-4a62-a5be-16f1c58eb60f','塞上','殷遙','唐','唐诗','tang','','[]','萬里隤城在，三邊虜氣衰。',48,'全唐诗/poet.tang.5000.json','["萬里隤城在，三邊虜氣衰。", "沙填孤嶂角，燒斷故關碑。", "馬色經寒慘，鵰聲帶晚悲。", "將軍正閑暇，留客換歌辭。"]'),
('88a6a7aa-6a5b-4ce9-9b51-9187cf3a5a76','送友人下第歸省','殷遙','唐','唐诗','tang','','[]','君此卜行日，高堂應夢歸。',48,'全唐诗/poet.tang.5000.json','["君此卜行日，高堂應夢歸。", "莫將和氏淚，滴著老萊衣。", "嶽雨連河細，田禽出麥飛。", "到家調膳後，吟好送斜暉。"]'),
('29601924-1af4-441b-9a95-9d59e3ea20f7','送杜士瞻楚州覲省','殷遙','唐','唐诗','tang','','[]','風流與才思，俱似晉時人。',48,'全唐诗/poet.tang.5000.json','["風流與才思，俱似晉時人。", "淮月歸心促，江花入興新。", "雲深蒼海暮，柳暗白門春。", "共道官猶小，憐君孝養親。"]'),
('6565de4f-4eb4-4645-9ec4-e49462bbcbb7','友人山亭','殷遙','唐','唐诗','tang','','[]','故人雖薄宦，往往涉清溪。',48,'全唐诗/poet.tang.5000.json','["故人雖薄宦，往往涉清溪。", "鑿牖對山月，褰裳拂澗霓。", "遊魚逆水上，宿鳥向風棲。", "一見桃花發，能令秦漢迷。"]'),
('57cc79ae-2171-4b30-8834-1ca6e7fdb865','春晚山行','殷遙','唐','唐诗','tang','','[]','寂歷青山晚，山行趣不稀。',48,'全唐诗/poet.tang.5000.json','["寂歷青山晚，山行趣不稀。", "野花成子落，江燕引雛飛。", "暗草薰苔徑，晴楊掃石磯。", "俗人猶語此，余亦轉忘歸。"]'),
('ceac2818-1ba1-44a5-aafd-22c93a3309b4','寄張徵古','沈如筠','唐','唐诗','tang','','[]','寂歷遠山意，微冥半空碧。',48,'全唐诗/poet.tang.5000.json','["寂歷遠山意，微冥半空碧。", "綠蘿無冬春，彩雲竟朝夕。", "張子海內奇，久爲巖中客。", "聖君當夢想，安得老松石。"]'),
('3f26ce3f-5ee1-4ee8-86ff-5518745202b7','閨怨二首 一','沈如筠','唐','唐诗','tang','','["\u601d\u5ff5", "\u95fa\u6028", "\u5987\u5973"]','鴈盡書難寄，愁多夢不成。',24,'全唐诗/poet.tang.5000.json','["鴈盡書難寄，愁多夢不成。", "願隨孤月影，流照伏波營。"]'),
('eaa74fb2-a2e1-460e-86a0-e00d5b78066b','閨怨二首 二','沈如筠','唐','唐诗','tang','','[]','隴底嗟長別，流襟一動君。',24,'全唐诗/poet.tang.5000.json','["隴底嗟長別，流襟一動君。", "何言幽咽所，更作死生分。"]'),
('1d3e6ed1-b1fe-4cca-ad4e-7e4b7ad61d9c','寄天台司馬道士','沈如筠','唐','唐诗','tang','','[]','河洲花豔爚，庭樹光彩蒨。',24,'全唐诗/poet.tang.5000.json','["河洲花豔爚，庭樹光彩蒨。", "白雲天台山，可思不可見。"]'),
('f52b1bcf-63cb-47a5-915e-ce13083964e2','句','沈如筠','唐','唐诗','tang','','[]','思酸寒鴈斷，淅瀝秋樹空。',24,'全唐诗/poet.tang.5000.json','["思酸寒鴈斷，淅瀝秋樹空。", "漁陽燕舊都，美女花不如。"]'),
('6fc9de56-4aca-4cbb-8abe-4cfcdb96d3a6','詠黃鶯','孫處玄','唐','唐诗','tang','','[]','欲囀聲猶澀，將飛羽未調。',24,'全唐诗/poet.tang.5000.json','["欲囀聲猶澀，將飛羽未調。", "高風不借便，何處得遷喬。"]'),
('197bdcd7-6fc5-4644-a965-96cafe102d90','失題','孫處玄','唐','唐诗','tang','','[]','漢家輕壯士，無狀殺彭王。',24,'全唐诗/poet.tang.5000.json','["漢家輕壯士，無狀殺彭王。", "一遇風塵起，令誰守四方。"]'),
('ca20df22-e548-4a99-9f4c-1f78d0c301f5','句','孫處玄','唐','唐诗','tang','','[]','殘花與露落，墮葉隨風翻。',24,'全唐诗/poet.tang.5000.json','["殘花與露落，墮葉隨風翻。", "日側南澗幽，風凝北林暮。"]'),
('3c4b7c86-882b-4525-a284-f3b3812546d4','折楊柳','徐延壽','唐','唐诗','tang','','[]','大道連國門，東西種楊柳。',96,'全唐诗/poet.tang.5000.json','["大道連國門，東西種楊柳。", "葳蕤君不見，嫋娜垂來久。", "緣枝棲暝禽，雄去雌獨吟。", "餘花怨春盡，微月起秋陰。", "坐望窗中蝶，起攀枝上葉。", "好風吹長條，婀娜何如妾。", "妾見柳園新，高樓四五春。", "莫吹胡塞曲，愁殺隴頭人。"]'),
('57f3cd85-28f7-47ba-accb-b9d2b7d10f1d','南州行','徐延壽','唐','唐诗','tang','','[]','搖艇至南國，國門連大江。',72,'全唐诗/poet.tang.5000.json','["搖艇至南國，國門連大江。", "中洲西邊岸，數步一垂楊。", "金釧越溪女，羅衣胡粉香。", "織縑春卷幔，采蕨暝提筐。", "弄瑟嬌垂幌，迎人笑下堂。", "河頭浣衣處，無數紫鴛鴦。"]'),
('8d7bd64d-8899-4188-80fe-58b3a0063af2','人日剪綵','徐延壽','唐','唐诗','tang','','[]','閨婦持刀坐，自憐裁剪新。',48,'全唐诗/poet.tang.5000.json','["閨婦持刀坐，自憐裁剪新。", "葉催情綴色，花寄手成春。", "帖燕留妝戶，黏雞待餉人。", "擎來問夫壻，何處不如真。"]'),
('05548d45-5c9e-475e-bd89-e10dbf89a995','南中感懷','樊晃','唐','唐诗','tang','','[]','南路磋跎客未回，常嗟物候暗相催。',32,'全唐诗/poet.tang.5000.json','["南路磋跎客未回，常嗟物候暗相催。", "四時不變江頭草，十月先開嶺上梅。"]'),
('8928ce05-1d1d-4a58-a334-f4f8b624e6b8','句','樊晃','唐','唐诗','tang','','[]','巧裁蟬鬢畏風吹，盡作蛾眉恐人妒。',16,'全唐诗/poet.tang.5000.json','["巧裁蟬鬢畏風吹，盡作蛾眉恐人妒。"]'),
('3e4c5e1e-96f2-4339-9789-4e45f6f170ba','和戶部楊員外伯成寓直','李憕','唐','唐诗','tang','','[]','落日彌綸地，公才畫省郎。',48,'全唐诗/poet.tang.5000.json','["落日彌綸地，公才畫省郎。", "詞驚起草筆，坐引護衣香。", "雙闕天河近，千門夕漏長。", "遙知臺上宿，不獨有文強。"]'),
('d10809a9-e7c1-4d27-8759-b4b32fe17fd4','同望幸新亭賜錢公宴','李憕','唐','唐诗','tang','','[]','感夢通玄化，覃恩降紫宸。',48,'全唐诗/poet.tang.5000.json','["感夢通玄化，覃恩降紫宸。", "賜錢開漢府，分帛醉堯人。", "地隔朝宗慶，亭臨卜洛新。", "行看廣雲雨，二月次東巡。"]'),
('d7074ac6-6297-4761-ba43-5b3e76de300c','奉和聖製從蓬萊向興慶閣道中留春雨中春望之作應制','李憕','唐','唐诗','tang','','[]','別館春還淑氣催，三宮路轉鳳皇臺。',64,'全唐诗/poet.tang.5000.json','["別館春還淑氣催，三宮路轉鳳皇臺。", "雲飛北闕輕陰散，雨歇南山積翠來。", "御柳遙隨天仗發，林花不待曉風開。", "已知聖澤深無限，更喜年芳入睿才。"]'),
('4a58b5cf-8779-4148-b8eb-e5dd3cad0594','銅雀妓','李邕','唐','唐诗','tang','','[]','西陵望何及，弦管徒在茲。',96,'全唐诗/poet.tang.5000.json','["西陵望何及，弦管徒在茲。", "誰言死者樂，但令生者悲。", "丈夫有餘志，兒女焉足私。", "擾擾多俗情，投迹互相師。", "直節豈感激，荒淫乃淒其。", "潁水有許由，西山有伯夷。", "頌聲何寥寥，唯聞銅雀詩。", "君舉良未易，永爲後代嗤。"]'),
('902a9ae8-7f5f-4a23-9204-52aa739e7c12','詠雲','李邕','唐','唐诗','tang','','[]','綵雲驚歲晚，繚繞孤山頭。',48,'全唐诗/poet.tang.5000.json','["綵雲驚歲晚，繚繞孤山頭。", "散作五般色，凝爲一段愁。", "影雖沈澗底，形在天際遊。", "風動必飛去，不應長此留。"]'),
('d213db65-8a6b-4c37-a5e5-798519744192','登歷下古城員外孫新亭','李邕','唐','唐诗','tang','','[]','吾宗固神秀，體物寫謀長。',72,'全唐诗/poet.tang.5000.json','["吾宗固神秀，體物寫謀長。", "形制開古跡，曾冰延樂方。", "太山雄地理，巨壑眇雲莊。", "高興汨煩促，永懷清典常。", "含弘知四大，出入見三光。", "負郭喜秔稻，安時歌吉祥。"]'),
('fe2277d7-42fb-4069-b4d2-c69887a0b629','奉和初春幸太平公主南莊應制','李邕','唐','唐诗','tang','','[]','傳聞銀漢支機石，復見金輿出紫微。',64,'全唐诗/poet.tang.5000.json','["傳聞銀漢支機石，復見金輿出紫微。", "織女橋邊烏鵲起，仙人樓上鳳皇飛。", "流風入座飄歌扇，瀑水侵階濺舞衣。", "今日還同犯牛斗，乘槎共逐海潮歸。"]'),
('e4c75dc6-6c7d-4141-a878-7d8786d4bebb','奉使登終南山','王灣','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','常愛南山遊，因而盡原隰。',204,'全唐诗/poet.tang.5000.json','["常愛南山遊，因而盡原隰。", "數朝至林嶺，百仞登嵬岌。", "石壯馬徑窮，苔色步緣入。", "物奇春狀改，氣遠天香集。", "虛洞策杖鳴，低雲拂衣濕。", "倚巖見廬舍，入戶欣拜揖。", "問性矜勤勞，示心教澄習。", "玉英時共飯，芝草爲余拾。", "境絕人不行，潭深鳥空立。", "一乘從此授，九轉兼是給。", "辭處若輕飛，憩來唯吐吸。", "閑襟超已勝，迴路倏而及。", "煙色松上深，水流山下急。", "漸平逢車騎，向晚睨城邑。", "峯在野趣繁，塵飄宦情澁。", "辛苦久爲吏，勞生何妄執。", "日暮懷此山，悠然賦斯什。"]'),
('f25a9d9e-3d21-4565-af59-e4e97bd1eed1','晚夏馬嵬卿叔池亭即事寄京都一二知己','王灣','唐','唐诗','tang','','[]','忝職畿甸淹，濫陪時俊後。',132,'全唐诗/poet.tang.5000.json','["忝職畿甸淹，濫陪時俊後。", "才輕策疲劣，勢薄常驅走。", "牽役勞風塵，秉心在巖藪。", "宗賢開別業，形勝代希偶。", "竹繞清渭濱，泉流白渠口。", "逡巡期賞會，揮忽變星斗。", "逮此乘務閑，因而訪幽叟。", "入來殊景物，行復洗紛垢。", "林靜秋色多，潭深月光厚。", "盛香蓮近拆，新味瓜初剖。", "滯拙懷隱淪，書之寄良友。"]'),
('076db65b-9bc5-42e9-b146-28e50e39fc50','麗正殿賜宴同勒天前煙年四韻應制','王灣','唐','唐诗','tang','','[]','金殿忝陪賢，瓊羞忽降天。',48,'全唐诗/poet.tang.5000.json','["金殿忝陪賢，瓊羞忽降天。", "鼎羅仙掖裏，觴拜瑣闈前。", "院逼青霄路，廚和紫禁煙。", "酒酣空忭舞，何以荅昌年。"]'),
('31df5224-a5fc-449d-ad93-17de30f6e9cc','奉和賀監林月清酌','王灣','唐','唐诗','tang','','[]','華月當秋滿，朝英假興同。',48,'全唐诗/poet.tang.5000.json','["華月當秋滿，朝英假興同。", "淨林新霽入，規院小涼通。", "碎影行筵裏，搖花落酒中。", "清宵凝爽意，倂此助文雄。"]'),
('5bb5c590-5de8-4bfb-aee6-30bc4bcdf99a','次北固山下','王灣','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5185)", "\u5730\u70b9", "\u4e94\u8a00\u5f8b\u8bd7", "\u521d\u4e2d\u53e4\u8bd7", "\u54f2\u7406"]','客路青山外，行舟綠水前。',48,'全唐诗/poet.tang.5000.json','["客路青山外，行舟綠水前。", "潮平兩岸闊，風正一帆懸。", "海日生殘夜，江春入舊年。", "鄉書何處達，歸雁洛陽邊。"]'),
('ea4b6d44-baf2-4afc-9554-c48284940ccc','觀搊箏','王灣','唐','唐诗','tang','','[]','虛室有秦箏，箏新月復清。',48,'全唐诗/poet.tang.5000.json','["虛室有秦箏，箏新月復清。", "弦多弄委曲，柱促語分明。", "曉怨凝繁手，春嬌入曼聲。", "近來唯此樂，傳得美人情。"]'),
('2db81524-6e32-4f96-b553-86b51abc429a','晚春詣蘇州敬贈武員外','王灣','唐','唐诗','tang','','[]','蘇臺憶季常，飛櫂歷江鄉。',180,'全唐诗/poet.tang.5000.json','["蘇臺憶季常，飛櫂歷江鄉。", "持此功曹掾，初離華省郎。", "貴門生禮樂，明代秉文章。", "嘉郡位先進，鴻儒名重揚。", "爰從姻婭貶，豈失忠信防。", "萬里行驥足，十年暌鳳翔。", "迴遷翊元聖，入拜佇惟良。", "別業對南浦，羣書滿北堂。", "意深投轄盛，才重接筵光。", "陋學叨鉛簡，弱齡許翰場。", "神馳勞舊國，顏展別殊方。", "際曉雜氛散，殘春衆物芳。", "煙和疎樹滿，雨續小谿長。", "旅拙感成慰，通賢顧不忘。", "從來琴曲罷，開匣爲君張。"]'),
('ebfa17b6-afc5-4123-81cd-62f7f9625597','秋夜寓直即事懷贈蕭令公裴侍郎兼通簡南省諸友人','王灣','唐','唐诗','tang','','[]','聖主萬年興，賢臣數載升。',288,'全唐诗/poet.tang.5000.json','["聖主萬年興，賢臣數載升。", "古靈傳嶽秀，宏量稟川澄。", "畿甸舉長策，風霜秉直繩。", "出車遙俗震，登閣滿朝稱。", "賦簡流亡輯，農安政理憑。", "還家新長幼，巡壠舊溝塍。", "忠梗大勛立，寰瀛墮業懲。", "焚香兼御史，懸鏡委中丞。", "旟隼當朝立，臺驄發郡乘。", "司徒漢家重，國典潁川徵。", "雲路俄平入，台階忽上凌。", "秉鈞調造化，宣綍慰黎烝。", "金省方秋作，瑤軒直夜凭。", "中書贈陳準，右相簡王陵。", "三傑賢更穆，百僚歡且兢。", "搖懷及賓友，計曲辨淄澠。", "閶闔暝陰散，鉤陳爽氣凝。", "月深宮樹轉，河近禁樓冰。", "卑吏夙驅策，微涓效斗升。", "望麾宵繼火，書板曙懷蒸。", "彼此雖流盼，規模轉服膺。", "惠將霄漢隔，勞或歲時矜。", "位重恩寧濫，才輕懾不勝。", "林巒甘獨往，疵賤苦相仍。"]'),
('e88124ec-8947-407d-a166-3888dc12d228','哭補闕亡友綦毋學士','王灣','唐','唐诗','tang','','["\u6cf0\u5c71"]','明代資多士，儒林得異才。',216,'全唐诗/poet.tang.5000.json','["明代資多士，儒林得異才。", "書從金殿出，人向玉墀來。", "詞學張平子，風儀褚彥回。", "崇儀希上德，近侍接元台。", "曩契心期早，今遊宴賞陪。", "屢遷君擢桂，分尉我從梅。", "忽遇乘軺客，云傾構廈材。", "泣爲洹水化，歎作泰山頹。", "冀善初將慰，尋言半始猜。", "位聯情易感，交密痛難裁。", "遠日寒旌暗，長風古挽哀。", "寰中無舊業，行處有新苔。", "反哭魂猶寄，終喪子尚孩。", "葬田門吏給，墳木路人栽。", "遽洩悲成往，俄傳寵令迴。", "玄經貽石室，朱紱耀泉臺。", "地古春長閉，天明夜不開。", "登山一臨哭，揮淚滿蒿萊。"]'),
('d2900cc3-a8f3-4d4b-82b9-e9f22d17c8ab','閏月七日織女','王灣','唐','唐诗','tang','','[]','耿耿曙河微，神仙此夜稀。',24,'全唐诗/poet.tang.5000.json','["耿耿曙河微，神仙此夜稀。", "今年七月閏，應得兩回歸。"]'),
('6d77d022-7335-45c9-aa82-0e1725555536','句','王灣','唐','唐诗','tang','','[]','月華照杵空隨妾，風響傳砧不到君。',16,'全唐诗/poet.tang.5000.json','["月華照杵空隨妾，風響傳砧不到君。"]'),
('7c339c18-2e14-4988-ba44-43ea5456e44d','應詔賦得除夜','史青','唐','唐诗','tang','','["\u6625\u8282"]','今歲今宵盡，明年明日催。',48,'全唐诗/poet.tang.5000.json','["今歲今宵盡，明年明日催。", "寒隨一夜去，春逐五更來。", "氣色空中改，容顏暗裏回。", "風光人不覺，已著後園梅。"]'),
('aa433fe7-1543-4bfd-9898-bde02b490e2f','汴堤柳','王泠然','唐','唐诗','tang','','[]','隋家天子憶揚州，厭坐深宮傍海游。',160,'全唐诗/poet.tang.5000.json','["隋家天子憶揚州，厭坐深宮傍海游。", "穿地鑿山開御路，鳴笳疊鼓泛清流。", "流從鞏北分河口，直到淮南種官柳。", "功成力盡人旋亡，代謝年移樹空有。", "當時綵女侍君王，繡帳旌門對柳行。", "青葉交垂連幔色，白花飛度染衣香。", "今日摧殘何用道，數里曾無一枝好。", "驛騎征帆損更多，山精野魅藏應老。", "涼風八月露爲霜，日夜孤舟入帝鄉。", "河畔時時聞木落，客中無不淚沾裳。"]'),
('55b45ff4-173f-42d3-82bb-7f9404191f94','夜光篇','王泠然','唐','唐诗','tang','','[]','遊人夜到汝陽間，夜色冥濛不解顏。',188,'全唐诗/poet.tang.5000.json','["遊人夜到汝陽間，夜色冥濛不解顏。", "誰家暗起寒山燒，因此明中得見山。", "山頭山下須臾滿，歷險緣深無暫斷。", "焦聲散著羣樹鳴，炎氣傍林一川暖。", "是時西北多海風，吹上連天光更雄。", "濁煙熏月黑，高豔爇雲紅。", "初謂煉丹仙竈裏，還疑鑄劒神谿中。", "劃爲飛電來照物，乍作流星併上空。", "西山無草光已滅，東頂熒熒猶未絕。", "沸湯空谷數道水，融蓋陰崖幾年雪。", "兩京貧病若爲居，四壁皆成鑿照餘。", "未得貴游同秉燭，唯將半影借披書。"]'),
('03e63bb4-cad0-4027-b341-bb449e5f0f00','古木臥平沙','王泠然','唐','唐诗','tang','','[]','古木臥平沙，摧殘歲月賒。',48,'全唐诗/poet.tang.5000.json','["古木臥平沙，摧殘歲月賒。", "有根橫水石，無葉拂煙霞。", "春至苔爲葉，冬來雪作花。", "不逢星漢使，誰辨是靈槎。"]'),
('8e072273-a90f-49d2-bd63-6da85977707b','淮南寄舍弟','王泠然','唐','唐诗','tang','','[]','昔予從不調，經歲旅淮源。',72,'全唐诗/poet.tang.5000.json','["昔予從不調，經歲旅淮源。", "念爾長相失，何時返故園。", "寄書迷處所，分袂隔涼溫。", "遠道俱爲客，他鄉共在原。", "歸情春伴雁，愁泣夜隨猨。", "愧見高堂上，朝朝獨倚門。"]'),
('642529dd-2808-475b-9ca4-ad6985008f89','句','王泠然','唐','唐诗','tang','','[]','林狖欺童子，山精試老僧。',40,'全唐诗/poet.tang.5000.json','["林狖欺童子，山精試老僧。", "陳兵劒閣山將動，飲馬珠江水不流。", "官微思倚玉，文淺怯投珠。"]'),
('aeec458f-b3b7-4d10-9f85-62dcc40c3a9c','春江花月夜二首 一','張子容','唐','唐诗','tang','','[]','林花發岸口，氣色動江新。',36,'全唐诗/poet.tang.5000.json','["林花發岸口，氣色動江新。", "此夜江中月，流光花上春。", "分明石潭裏，宜照浣紗人。"]'),
('b99dc5a8-4003-4bb0-9a4d-b088be0d8cb1','春江花月夜二首 二','張子容','唐','唐诗','tang','','[]','交甫憐瑤珮，仙妃難重期。',36,'全唐诗/poet.tang.5000.json','["交甫憐瑤珮，仙妃難重期。", "沈沈綠江晚，惆悵碧雲姿。", "初逢花上月，言是弄珠時。"]'),
('ffd4483e-e27d-4f9e-a371-4a62234c1000','雲陽驛陪崔使君邵道士夜宴','張子容','唐','唐诗','tang','','[]','一尉東南遠，誰知此夜歡。',48,'全唐诗/poet.tang.5000.json','["一尉東南遠，誰知此夜歡。", "諸侯傾皁蓋，仙客整黃冠。", "染翰燈花滿，飛觴雲氣寒。", "欣承國士遇，更借美人看。"]'),
('9e85481e-fbae-467c-bb19-e7ea6e7846e2','除夜樂城逢孟浩然','張子容','唐','唐诗','tang','','[]','遠客襄陽郡，來過海岸家。',48,'全唐诗/poet.tang.5000.json','["遠客襄陽郡，來過海岸家。", "樽開柏葉酒，燈發九枝花。", "妙曲逢盧女，高才得孟嘉。", "東山行樂意，非是競繁華。"]'),
('3383d17e-05be-4ab5-8c75-5d42cb91b236','送蘇倩遊天台','張子容','唐','唐诗','tang','','[]','靈異尋滄海，笙歌訪翠微。',48,'全唐诗/poet.tang.5000.json','["靈異尋滄海，笙歌訪翠微。", "江鷗迎共狎，雲鶴待將飛。", "琪樹嘗仙果，瓊樓試羽衣。", "遙知神女問，獨怪阮郎歸。"]'),
('e2ed4537-3fcb-40ef-8c0f-29c1c46366b3','泛永嘉江日暮迴舟','張子容','唐','唐诗','tang','','[]','無雲天欲暮，輕鷁大江清。',48,'全唐诗/poet.tang.5000.json','["無雲天欲暮，輕鷁大江清。", "歸路煙中遠，迴舟月上行。", "傍潭窺竹暗，出嶼見沙明。", "更值微風起，乘流絲管聲。"]'),
('8626a651-e63a-4a8f-a6b5-62529aab56fc','永嘉即事寄贛縣袁少府瓘','張子容','唐','唐诗','tang','','[]','山繞樓臺出，谿通里閈斜。',48,'全唐诗/poet.tang.5000.json','["山繞樓臺出，谿通里閈斜。", "曾爲謝客郡，多有逐臣家。", "海氣朝成雨，江天晚作霞。", "題書報賈誼，此濕似長沙。"]');
